INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c11232fe-8527-5bf5-8601-c62f1903b5f9', 'd1d29e49-bbb1-5aa2-9ad8-822a170ffd11', 'Comment se forme le passé composé ?', '[{"id":"a","text":"Avec l''auxiliaire être ou avoir au présent + le participe passé"},{"id":"b","text":"Avec l''auxiliaire être ou avoir au futur + le participe passé"},{"id":"c","text":"Avec le radical du verbe + la terminaison -ais"},{"id":"d","text":"Avec l''auxiliaire aller au présent + l''infinitif"}]'::jsonb, 'a', 'Le passé composé est un temps composé : l''auxiliaire être ou avoir se conjugue au présent, suivi du participe passé (j''ai fini, elle est partie).', 1)
