INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e2825cfb-c7f6-5565-9b60-5c7ba5da65ce', 'd1d29e49-bbb1-5aa2-9ad8-822a170ffd11', 'Complète au présent : « Les élèves ___ (réfléchir) avant de répondre. »', '[{"id":"a","text":"réfléchent"},{"id":"b","text":"réfléchit"},{"id":"c","text":"réfléchissent"},{"id":"d","text":"réfléchisent"}]'::jsonb, 'c', 'Réfléchir est un verbe du 2e groupe : au pluriel, il prend l''élément -iss- → les élèves réfléchissent. « réfléchent » oublie le -iss-, et « réfléchit » est le singulier.', 2)
