INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('388cc6fb-7cb1-5940-bf74-dcd2f72a5dd5', 'd1d29e49-bbb1-5aa2-9ad8-822a170ffd11', 'Quelle est la valeur du présent dans « L''eau bout à cent degrés. » ?', '[{"id":"a","text":"Le présent de narration"},{"id":"b","text":"Une action future"},{"id":"c","text":"Une action en train de se réaliser"},{"id":"d","text":"Une vérité générale"}]'::jsonb, 'd', 'Ce fait est toujours vrai, à n''importe quel moment : c''est la valeur de vérité générale du présent.', 3)
