INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cfce562e-2e79-5c50-a916-ec6c3c212da8', 'd1d29e49-bbb1-5aa2-9ad8-822a170ffd11', 'Complète au passé composé : « Nour et Sirine ___ (rentrer) tard de Bizerte. »', '[{"id":"a","text":"sont rentré"},{"id":"b","text":"sont rentrées"},{"id":"c","text":"ont rentré"},{"id":"d","text":"sont rentrés"}]'::jsonb, 'b', 'Rentrer se conjugue avec être : le participe s''accorde avec le sujet. Nour et Sirine sont deux filles → féminin pluriel → sont rentrées.', 4)
