INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f3ad1779-ca7e-5f84-a156-0cb8c0c754ca', 'd1d29e49-bbb1-5aa2-9ad8-822a170ffd11', 'Complète au passé composé : « Les garçons ___ (manger) une glace à La Marsa. »', '[{"id":"a","text":"sont mangés"},{"id":"b","text":"ont mangés"},{"id":"c","text":"ont mangée"},{"id":"d","text":"ont mangé"}]'::jsonb, 'd', 'Manger se conjugue avec avoir. Avec avoir, le participe ne s''accorde pas avec le sujet, et le COD « une glace » est placé après le verbe → aucun accord → ont mangé.', 5)
