INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6ae880f8-720e-5955-93c5-4765e3e4f6df', '8aa6fb83-e03c-5b3c-b3d1-f921dfc554b2', '« Hier soir, la lampe s''éteint soudain et toute la maison plonge dans le noir. » Quelle est la valeur des verbes au présent ?', '[{"id":"a","text":"Une vérité générale"},{"id":"b","text":"Le présent de narration"},{"id":"c","text":"Une habitude"},{"id":"d","text":"Le futur proche"}]'::jsonb, 'b', 'La scène s''est passée hier soir, mais elle est racontée au présent pour la rendre plus vivante : c''est le présent de narration. Le mot « hier » prouve que l''action est passée.', 3)
