INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2e907a49-0360-5ce0-9f2e-f5fe694b613a', 'f3479832-10ac-5968-9243-03299b241ce4', '« Je finis mes devoirs, tu ranges ta chambre, il choisi un livre et nous partons. » Quel verbe est mal orthographié ?', '[{"id":"a","text":"« finis »"},{"id":"b","text":"« ranges »"},{"id":"c","text":"« choisi »"},{"id":"d","text":"« partons »"}]'::jsonb, 'c', 'Chasse à l''erreur : « il choisi » est faux. Choisir est du 2e groupe et prend -it à la 3e personne → il choisit. Les trois autres verbes sont correctement conjugués.', 1)
