INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('abb9e2f2-171a-5551-9e3c-592241927903', 'f3479832-10ac-5968-9243-03299b241ce4', 'Dans quelle phrase l''auxiliaire est-il mal choisi ?', '[{"id":"a","text":"« Ils ont resté à la maison. »"},{"id":"b","text":"« Elle est tombée dans l''escalier. »"},{"id":"c","text":"« Nous avons mangé des dattes. »"},{"id":"d","text":"« Tu es arrivé le premier. »"}]'::jsonb, 'a', 'Rester se conjugue avec être, pas avec avoir : il faut « ils sont restés ». Les phrases b (tomber → être), c (manger → avoir) et d (arriver → être) sont correctes.', 2)
