INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c1b51f3c-2765-5e19-85cf-e89fbef9da6e', 'f3479832-10ac-5968-9243-03299b241ce4', 'Quelle phrase contient une FAUTE d''accord du participe passé ?', '[{"id":"a","text":"« Les fleurs que Nour a cueillies sentent bon. »"},{"id":"b","text":"« Nour a cueilli des fleurs. »"},{"id":"c","text":"« Les fleurs que Nour a cueilli sentent bon. »"},{"id":"d","text":"« Nour les a cueillies ce matin. »"}]'::jsonb, 'c', 'Dans c, le COD « que » (= les fleurs, féminin pluriel) est placé avant le verbe : le participe doit s''accorder → « cueillies ». Les phrases a et d accordent correctement (COD avant), et b n''accorde pas car le COD est après.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('07b9be09-02b7-5de0-b9d2-4f41a2a1ab6c', 'f3479832-10ac-5968-9243-03299b241ce4', 'Transforme au passé composé ET à la forme négative : « Selim se réveille tôt. »', '[{"id":"a","text":"« Selim n''est pas se réveillé tôt. »"},{"id":"b","text":"« Selim ne s''est pas réveillé tôt. »"},{"id":"c","text":"« Selim ne c''est pas réveillé tôt. »"},{"id":"d","text":"« Selim ne s''est pas réveiller tôt. »"}]'::jsonb, 'b', 'Trois étapes : verbe pronominal → auxiliaire être (« s''est ») ; accord avec le sujet masculin singulier → « réveillé » ; négation « ne… pas » autour de l''auxiliaire → Selim ne s''est pas réveillé tôt. « c''est » et l''infinitif « réveiller » sont des pièges.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ea20e41f-70b5-5e46-a67a-21348156a8e8', 'f3479832-10ac-5968-9243-03299b241ce4', '« Chaque été, nous ___ à Djerba ; l''an dernier, nous y ___ un mois. » Quelle suite de temps convient (retourner / rester) ?', '[{"id":"a","text":"« retournons » (présent) et « sommes restés » (passé composé)"},{"id":"b","text":"« sommes retournés » et « restons »"},{"id":"c","text":"« retournons » et « avons resté »"},{"id":"d","text":"« retournions » et « sommes restés »"}]'::jsonb, 'a', '« Chaque été » marque une habitude → présent (retournons). « L''an dernier » marque un fait précis et achevé → passé composé ; rester se conjugue avec être → sommes restés. « avons resté » se trompe d''auxiliaire.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

