INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('962dcca6-fe41-5154-b52f-521d9fd3cc53', 'eb5b7991-08d9-597f-99c6-ffd1bd22a57e', 'Complète au passé composé : « Sirine ___ (rester) à la maison tout le week-end. »', '[{"id":"a","text":"est restée"},{"id":"b","text":"a resté"},{"id":"c","text":"est resté"},{"id":"d","text":"a restée"}]'::jsonb, 'a', 'Rester se conjugue avec être : accord avec le sujet. Sirine est une fille → féminin singulier → est restée. « a resté » se trompe d''auxiliaire.', 2)
