INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7db998e9-98e9-5f3e-bfa6-5e3986a18c63', 'eb5b7991-08d9-597f-99c6-ffd1bd22a57e', '« Qui sème le vent récolte la tempête. » Quelle est la valeur du présent dans ce proverbe ?', '[{"id":"a","text":"Une action en cours"},{"id":"b","text":"Une vérité générale"},{"id":"c","text":"Le présent de narration"},{"id":"d","text":"Le futur proche"}]'::jsonb, 'b', 'Un proverbe énonce une idée toujours valable : c''est la valeur de vérité générale du présent.', 3)
