INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('69752abe-33c4-53af-bb43-6d49fa34b32c', 'eb5b7991-08d9-597f-99c6-ffd1bd22a57e', 'Complète : « Les touristes ont ___ (visiter) la médina de Sousse. »', '[{"id":"a","text":"visité"},{"id":"b","text":"visitée"},{"id":"c","text":"visités"},{"id":"d","text":"visiter"}]'::jsonb, 'a', 'Auxiliaire avoir : le COD « la médina » est placé APRÈS le verbe → aucun accord → visité. Attention à ne pas accorder avec le sujet « les touristes » (l''accord avec le sujet ne vaut que pour l''auxiliaire être).', 5)
