INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b2ab8c54-c210-59be-b1de-0c4ff5390591', 'e5fe67da-12ed-516f-9a4d-33bf400ed4c2', '« La Terre tourne autour du Soleil depuis des milliards d''années. » Quelle valeur a le présent « tourne » ?', '[{"id":"a","text":"Une vérité générale"},{"id":"b","text":"Une action passée"},{"id":"c","text":"Une habitude passagère"},{"id":"d","text":"Le présent de narration"}]'::jsonb, 'a', 'C''est un fait scientifique toujours vrai : le présent y exprime une vérité générale, même avec le complément « depuis des milliards d''années ».', 1)
