INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a44b2c9c-2623-5a1b-9b0e-83bd6f84e646', 'e5fe67da-12ed-516f-9a4d-33bf400ed4c2', '« Ines a acheté des roses. » En remplaçant « des roses » par un pronom, quelle phrase est correcte ?', '[{"id":"a","text":"« Ines les a acheté. »"},{"id":"b","text":"« Ines l''a acheté. »"},{"id":"c","text":"« Ines les a achetées. »"},{"id":"d","text":"« Ines les a achetés. »"}]'::jsonb, 'c', 'Le pronom « les » remplace « des roses » (féminin pluriel) et se place AVANT le verbe → le participe s''accorde → les a achetées. Une fois le COD placé avant, l''accord devient obligatoire.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
