  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('99064e08-af2a-5b74-b88d-904ddf6bb8bf', 'e5fe67da-12ed-516f-9a4d-33bf400ed4c2', 'Complète : « Rania ___ (descendre) les valises au rez-de-chaussée. »', '[{"id":"a","text":"est descendue"},{"id":"b","text":"a descendu"},{"id":"c","text":"est descendu"},{"id":"d","text":"a descendues"}]'::jsonb, 'b', 'Piège d''élite : ici « descendre » a un COD (« les valises ») → il se conjugue avec avoir, pas avec être → a descendu. Le COD étant placé après le verbe, il n''y a pas d''accord. (Sans complément, on dirait : Rania est descendue.)', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f2ab7937-c384-5901-b505-dc09acf9c784', 'e5fe67da-12ed-516f-9a4d-33bf400ed4c2', '« La nuit tombe sur Kairouan. Un marchand ferme sa boutique, un chat traverse la ruelle. » Dans ce récit situé dans le passé mais raconté au présent, comment nomme-t-on cet emploi ?', '[{"id":"a","text":"Le présent de vérité générale"},{"id":"b","text":"Le présent d''habitude"},{"id":"c","text":"Le présent de narration"},{"id":"d","text":"Le futur proche"}]'::jsonb, 'c', 'Les événements d''un récit sont racontés au présent pour les rendre plus vivants sous les yeux du lecteur : c''est le présent de narration (ou présent historique).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d9471067-bb02-5e2b-8ff3-213d0e08cae8', 'e5fe67da-12ed-516f-9a4d-33bf400ed4c2', 'Complète : « Les touristes que nous ___ (accompagner) ___ (repartir) enchantés. »', '[{"id":"a","text":"avons accompagné / ont reparti"},{"id":"b","text":"avons accompagnés / ont reparti"},{"id":"c","text":"avons accompagné / sont repartis"},{"id":"d","text":"avons accompagnés / sont repartis"}]'::jsonb, 'd', 'Deux accords : « que » (= les touristes, masculin pluriel) est le COD placé avant l''auxiliaire avoir → avons accompagnés ; repartir se conjugue avec être et s''accorde avec le sujet « les touristes » → sont repartis.', 6)
