INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6ac3daca-98a7-597d-8879-0ee4d75d3dc6', '5352465b-77d7-534a-ba9f-d7f7178802cf', 'Comment forme-t-on l''imparfait de l''indicatif ?', '[{"id":"a","text":"Sur le radical du « nous » au présent + -ais, -ais, -ait, -ions, -iez, -aient"},{"id":"b","text":"Sur l''infinitif + -rai, -ras, -ra, -rons, -rez, -ront"},{"id":"c","text":"Avec l''auxiliaire être ou avoir + le participe passé"},{"id":"d","text":"Sur l''infinitif + -ai, -as, -a, -âmes, -âtes, -èrent"}]'::jsonb, 'a', 'L''imparfait se construit sur le radical de la 1re personne du pluriel du présent (nous chantons → chant-) auquel on ajoute -ais, -ais, -ait, -ions, -iez, -aient, les mêmes pour tous les verbes. La réponse b décrit le futur simple, la c le passé composé et la d le passé simple du 1er groupe.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1c4acb26-f671-51bb-a19b-7e50163b9c01', '5352465b-77d7-534a-ba9f-d7f7178802cf', 'Quelles sont les terminaisons du passé simple pour les verbes du 1er groupe (en -er) ?', '[{"id":"a","text":"-ais, -ais, -ait, -ions, -iez, -aient"},{"id":"b","text":"-ai, -as, -a, -âmes, -âtes, -èrent"},{"id":"c","text":"-is, -is, -it, -îmes, -îtes, -irent"},{"id":"d","text":"-us, -us, -ut, -ûmes, -ûtes, -urent"}]'::jsonb, 'b', 'Au passé simple, les verbes du 1er groupe (chanter, aller) prennent -ai, -as, -a, -âmes, -âtes, -èrent : « il chanta, ils chantèrent ». Les terminaisons en -is (c) valent pour finir et beaucoup de verbes du 3e groupe ; celles en -us (d) pour d''autres verbes du 3e groupe ; la série a est celle de l''imparfait.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0ccdbcc7-754b-5c54-9076-179f1fdb0098', '5352465b-77d7-534a-ba9f-d7f7178802cf', 'Dans un récit, quel temps sert à planter le décor et l''arrière-plan de l''histoire ?', '[{"id":"a","text":"Le passé simple"},{"id":"b","text":"Le futur simple"},{"id":"c","text":"L''imparfait"},{"id":"d","text":"L''impératif"}]'::jsonb, 'c', 'L''imparfait est le temps du décor et de l''arrière-plan : il fait durer la scène (« la médina dormait sous un ciel gris »). Le passé simple, lui, sert aux événements de premier plan qui font avancer l''histoire.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8c872563-b3b2-5457-a80b-024250bff246', '5352465b-77d7-534a-ba9f-d7f7178802cf', 'Quelle valeur de l''imparfait trouve-t-on dans : « Chaque matin, Nour prenait le bus pour aller au collège. » ?', '[{"id":"a","text":"Une action habituelle, répétée"},{"id":"b","text":"Une action soudaine et unique"},{"id":"c","text":"Un ordre donné à quelqu''un"},{"id":"d","text":"Une action située dans le futur"}]'::jsonb, 'a', '« Chaque matin » indique une habitude : l''imparfait exprime ici une action répétée dans le passé. Une action soudaine et unique se dirait au passé simple (« un matin, Nour prit le bus »).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ceb5cd9a-0b69-54c9-a379-1f7d772598fe', '5352465b-77d7-534a-ba9f-d7f7178802cf', 'Dans « Le soleil se couchait quand un cri déchira le silence. », pourquoi « déchira » est-il au passé simple ?', '[{"id":"a","text":"Parce que c''est une description qui dure"},{"id":"b","text":"Parce que c''est un événement soudain de premier plan"},{"id":"c","text":"Parce que c''est une action habituelle"},{"id":"d","text":"Parce que c''est un ordre"}]'::jsonb, 'b', '« Se couchait » décrit le décor qui dure (imparfait) ; « déchira » est l''événement soudain qui rompt cette durée et fait avancer l''histoire, d''où le passé simple. C''est le cœur de l''alternance : arrière-plan à l''imparfait, premier plan au passé simple.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

