INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('63fd4ead-c44c-5633-b4c4-a956d4b8f56d', 'e0d48ed0-2b69-50eb-9268-c83f42a40748', 'Complète à l''imparfait : « Autrefois, Aziz ___ (finir) toujours ses devoirs avant le dîner. »', '[{"id":"a","text":"finissait"},{"id":"b","text":"finit"},{"id":"c","text":"finisait"},{"id":"d","text":"finira"}]'::jsonb, 'a', 'L''imparfait se forme sur le radical du « nous » au présent : nous finissons → finiss-, puis -ait à la 3e personne du singulier : « finissait ». « finit » est le passé simple, « finisait » oublie un s, et « finira » est le futur.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ef6ecc81-36c1-56fa-a4fb-d42c616c4783', 'e0d48ed0-2b69-50eb-9268-c83f42a40748', 'Complète au passé simple : « Ce jour-là, Nour ___ (chanter) devant toute la classe. »', '[{"id":"a","text":"chantait"},{"id":"b","text":"chanta"},{"id":"c","text":"chantas"},{"id":"d","text":"chantera"}]'::jsonb, 'b', 'Au passé simple, un verbe du 1er groupe à la 3e personne du singulier prend -a : « il/elle chanta ». « chantait » est l''imparfait, « chantas » est la 2e personne (tu chantas) et « chantera » le futur.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5c01bdf5-db35-5c85-b044-3567ce3b050b', 'e0d48ed0-2b69-50eb-9268-c83f42a40748', 'Quelle est la valeur de l''imparfait dans : « La médina de Sfax dormait sous un ciel gris. » ?', '[{"id":"a","text":"Une description, un décor"},{"id":"b","text":"Une action soudaine et unique"},{"id":"c","text":"Un ordre"},{"id":"d","text":"Une action située dans le futur"}]'::jsonb, 'a', 'L''imparfait plante ici le décor de l''histoire : il décrit le cadre qui dure. Une action soudaine et unique se raconterait au passé simple.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
