  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9bbdb882-660f-5155-b90d-309878f42313', 'e0d48ed0-2b69-50eb-9268-c83f42a40748', 'Complète au passé simple : « À midi, les voyageurs ___ (arriver) enfin au port de La Goulette. »', '[{"id":"a","text":"arrivaient"},{"id":"b","text":"arrivés"},{"id":"c","text":"arrivèrent"},{"id":"d","text":"arriverent"}]'::jsonb, 'c', 'Au passé simple, un verbe du 1er groupe à la 3e personne du pluriel prend -èrent (avec accent) : « ils arrivèrent ». « arrivaient » est l''imparfait, « arrivés » est le participe passé et « arriverent » oublie l''accent obligatoire.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('83e49d90-70a1-5e54-a4e3-4af393029b51', 'e0d48ed0-2b69-50eb-9268-c83f42a40748', 'Laquelle de ces formes est au passé simple (et non à l''imparfait) ?', '[{"id":"a","text":"il marchait"},{"id":"b","text":"il marcha"},{"id":"c","text":"il marchera"},{"id":"d","text":"il marche"}]'::jsonb, 'b', '« il marcha » (-a) est le passé simple d''un verbe du 1er groupe. « il marchait » (-ait) est l''imparfait, « il marchera » le futur et « il marche » le présent. Ne confonds pas -a (passé simple) et -ait (imparfait) !', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6056b358-2fe7-58e9-bd5f-315fb08d938e', 'e0d48ed0-2b69-50eb-9268-c83f42a40748', 'Complète au passé simple : « Après une longue attente, le train ___ (partir). »', '[{"id":"a","text":"partait"},{"id":"b","text":"partis"},{"id":"c","text":"parta"},{"id":"d","text":"partit"}]'::jsonb, 'd', '« Partir » se conjugue au passé simple sur la série en -is : je partis, il partit, ils partirent. À la 3e personne du singulier : « partit ». « partait » est l''imparfait, « partis » la 1re/2e personne et « parta » applique à tort la terminaison des verbes en -er.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
