INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ab2a0167-7af0-56c9-b7bc-e5046300b016', '4e8379a9-9641-5e01-862c-3defd94ae49d', 'Complète à l''imparfait : « Il ___ (être) une fois un jeune pêcheur de Mahdia. »', '[{"id":"a","text":"étais"},{"id":"b","text":"fut"},{"id":"c","text":"était"},{"id":"d","text":"serait"}]'::jsonb, 'c', '« Être » est le seul verbe vraiment irrégulier à l''imparfait : j''étais, tu étais, il était… La formule d''ouverture des contes est « Il était une fois » ✓. « fut » est le passé simple, « étais » la 1re/2e personne et « serait » le conditionnel.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
