INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('52479f70-f5e1-5b7a-9ff9-3e77c93be93b', '4e8379a9-9641-5e01-862c-3defd94ae49d', 'Complète au passé simple : « En ouvrant la porte, Ghofrane ___ (voir) un étrange paquet. »', '[{"id":"a","text":"vit"},{"id":"b","text":"voyait"},{"id":"c","text":"vut"},{"id":"d","text":"voit"}]'::jsonb, 'a', '« Voir » fait au passé simple : je vis, il vit, ils virent. À la 3e personne du singulier : « vit » ✓. « voyait » est l''imparfait, « voit » le présent et « vut » n''existe pas (on ne construit pas le passé simple sur l''infinitif).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aff38300-00c4-5425-9bc2-ca300ee84de8', '4e8379a9-9641-5e01-862c-3defd94ae49d', 'Choisis la forme correcte : « Il faisait nuit lorsque la voiture ___ devant la maison. » (s''arrêter)', '[{"id":"a","text":"s''arrêtait"},{"id":"b","text":"s''arrêta"},{"id":"c","text":"s''arrête"},{"id":"d","text":"s''arrêtera"}]'::jsonb, 'b', '« Il faisait nuit » est le décor (imparfait) ; l''arrivée de la voiture est un événement soudain de premier plan : passé simple « s''arrêta » ✓. Mettre « s''arrêtait » ferait de cette action un simple décor, ce qui n''a pas de sens ici.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9dd4f6a2-bcba-5038-a86e-135a29f985f6', '4e8379a9-9641-5e01-862c-3defd94ae49d', 'Une phrase contient une erreur de temps. Laquelle ? « 1. Il faisait beau ce matin-là. 2. Les oiseaux chantaient dans les arbres. 3. Soudain, un orage éclatait. 4. La pluie tomba sur la médina. »', '[{"id":"a","text":"La phrase 1"},{"id":"b","text":"La phrase 2"},{"id":"c","text":"La phrase 3"},{"id":"d","text":"La phrase 4"}]'::jsonb, 'c', '« Soudain » annonce un événement brusque de premier plan : il faut le passé simple « un orage éclata », pas l''imparfait « éclatait ». Les phrases 1 et 2 sont des décors qui durent (imparfait, correct) et la phrase 4 est bien un événement au passé simple. (Chasse à l''erreur : on désigne la phrase fautive.)', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8c31899c-f33e-5e28-9926-598aeba7f879', '4e8379a9-9641-5e01-862c-3defd94ae49d', 'Complète au passé simple : « Les élèves ___ (entrer) puis ils ___ (finir) l''exercice. »', '[{"id":"a","text":"entrèrent … finirent"},{"id":"b","text":"entrirent … finirent"},{"id":"c","text":"entrèrent … finissèrent"},{"id":"d","text":"entraient … finirent"}]'::jsonb, 'a', '« Entrer » (1er groupe) → -èrent : « entrèrent » ; « finir » (2e groupe) → -irent : « finirent » ✓. Le piège : appliquer -èrent à finir (« finissèrent » n''existe pas) ou -irent à entrer (« entrirent »). « entraient » est l''imparfait.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('79ad80bb-9007-5642-851e-4c16d9df7fb1', '4e8379a9-9641-5e01-862c-3defd94ae49d', 'Complète au passé simple : « Mehdi ___ (vouloir) parler, mais il ne ___ (pouvoir) pas. »', '[{"id":"a","text":"voulait … pouvait"},{"id":"b","text":"voulut … pouva"},{"id":"c","text":"voula … put"},{"id":"d","text":"voulut … put"}]'::jsonb, 'd', '« Vouloir » et « pouvoir » suivent la série en -u : il voulut, il put ✓. Le piège : « pouva » et « voula » appliquent à tort les terminaisons des verbes en -er. « voulait … pouvait » serait l''imparfait, qui décrit au lieu de raconter l''événement.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

