INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('68d09973-60d6-5586-b511-3c0e32068644', 'c682d995-24c5-5287-ad9e-ad686dc590b7', 'Complète à l''imparfait : « Chaque dimanche, mon oncle ___ (manger) avec nous à Kairouan. »', '[{"id":"a","text":"mangeais"},{"id":"b","text":"mangeait"},{"id":"c","text":"mangait"},{"id":"d","text":"mangea"}]'::jsonb, 'b', 'À l''imparfait, « manger » garde le e devant le a pour conserver le son [j] : je mangeais, il mangeait. À la 3e personne du singulier : « mangeait » ✓. « mangait » oublie le e, « mangeais » est la 1re/2e personne et « mangea » est le passé simple. « Chaque dimanche » indique bien une habitude.', 1)
