  ('4636a1d4-7736-5d0b-bccf-078b729a7a85', 'c682d995-24c5-5287-ad9e-ad686dc590b7', 'Quelle valeur a l''imparfait dans : « Wassim lisait tranquillement pendant le voyage. » ?', '[{"id":"a","text":"Un ordre"},{"id":"b","text":"Une action achevée et unique"},{"id":"c","text":"Une action future"},{"id":"d","text":"Une action qui dure"}]'::jsonb, 'd', 'L''imparfait exprime ici une action en cours, sans début ni fin marqués : la lecture dure pendant le voyage. Une action achevée et unique s''exprimerait au passé simple (« Wassim lut une page »).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
