INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e50bb32-83c1-55cd-b94c-c1c3e6e38eeb', 'c682d995-24c5-5287-ad9e-ad686dc590b7', 'Complète en respectant l''alternance : « La nuit ___ (tomber : décor) quand la caravane ___ (s''arrêter : événement soudain). »', '[{"id":"a","text":"tomba … s''arrêtait"},{"id":"b","text":"tombait … s''arrêtait"},{"id":"c","text":"tomba … s''arrêta"},{"id":"d","text":"tombait … s''arrêta"}]'::jsonb, 'd', 'Le décor qui dure va à l''imparfait (« la nuit tombait ») et l''événement soudain de premier plan au passé simple (« la caravane s''arrêta ») ✓. Les autres combinaisons inversent les rôles des deux temps.', 5)
