INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b08207b7-3ad2-58a9-a9a1-a49645e73b3d', 'c682d995-24c5-5287-ad9e-ad686dc590b7', 'Quelle phrase raconte une action soudaine (passé simple) ?', '[{"id":"a","text":"Tous les étés, il allait à Tabarka."},{"id":"b","text":"La maison était calme et silencieuse."},{"id":"c","text":"Tout à coup, la lampe s''éteignit."},{"id":"d","text":"Les enfants jouaient dans la cour."}]'::jsonb, 'c', '« Tout à coup, la lampe s''éteignit » est un événement bref et soudain au passé simple ✓. Les trois autres phrases sont à l''imparfait : habitude (« il allait »), décor (« était calme ») et action qui dure (« jouaient »).', 6)
ON CONFLICT (id) DO UPDATE SET
