INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3a4518ac-703f-5aeb-83f8-61a796c671bc', 'ce966517-5480-5ca5-918b-0291dad89d69', 'Une phrase contient une erreur de temps. Laquelle ? « 1. Le vent soufflait sur les dunes de Douz. 2. Les chameliers avançaient lentement. 3. Tout à coup, une tempête se levait. 4. Le groupe s''abrita derrière un rocher. »', '[{"id":"a","text":"La phrase 1"},{"id":"b","text":"La phrase 2"},{"id":"c","text":"La phrase 3"},{"id":"d","text":"La phrase 4"}]'::jsonb, 'c', '« Tout à coup » signale un événement brusque : il faut le passé simple « une tempête se leva », pas l''imparfait « se levait ». Les phrases 1 et 2 décrivent le décor qui dure (imparfait, correct) et la phrase 4 est un événement au passé simple. (Chasse à l''erreur : on désigne la phrase fautive.)', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('edd1341e-fef9-5ec4-a02b-2592ad94ce18', 'ce966517-5480-5ca5-918b-0291dad89d69', 'Complète : « Il ___ (faire) très chaud ce jour-là ; les rues ___ (être) désertes lorsque, soudain, un enfant ___ (surgir) au coin de la ruelle. »', '[{"id":"a","text":"faisait … étaient … surgit"},{"id":"b","text":"fit … furent … surgit"},{"id":"c","text":"faisait … étaient … surgissait"},{"id":"d","text":"fit … étaient … surgit"}]'::jsonb, 'a', '« Il faisait chaud » et « les rues étaient désertes » sont le décor qui dure → imparfait ; « un enfant surgit » est l''événement soudain → passé simple ✓. Mettre le décor au passé simple (« fit », « furent ») ou l''événement à l''imparfait (« surgissait ») casse l''alternance.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fd33f25c-a9ef-5841-a002-51abf3ab7e69', 'ce966517-5480-5ca5-918b-0291dad89d69', 'Complète au passé simple : « Quand elle ___ (avoir) fini son travail, elle ___ (être) enfin tranquille. »', '[{"id":"a","text":"avait … était"},{"id":"b","text":"eut … fût"},{"id":"c","text":"eût … fut"},{"id":"d","text":"eut … fut"}]'::jsonb, 'd', 'Au passé simple, « avoir » → il eut et « être » → il fut : « quand elle eut fini, elle fut tranquille » ✓. « avait … était » est l''imparfait ; « fût » et « eût » (avec accent circonflexe) sont des formes du subjonctif, pas du passé simple de l''indicatif.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b9362072-8c48-5d8d-aca6-5dae4b7b6a0b', 'ce966517-5480-5ca5-918b-0291dad89d69', 'Quelle phrase respecte correctement l''alternance imparfait (décor) / passé simple (événement) ?', '[{"id":"a","text":"Il pleuvait quand la voiture tomba en panne."},{"id":"b","text":"Il plut quand la voiture tombait en panne."},{"id":"c","text":"Il pleuvait quand la voiture tombait en panne."},{"id":"d","text":"Il plut quand la voiture tomba en panne."}]'::jsonb, 'a', '« Il pleuvait » est le décor qui dure (imparfait) et « la voiture tomba en panne » l''événement soudain (passé simple) ✓. La phrase c laisse tout à l''imparfait (aucun événement ne surgit), et les phrases b et d mettent la pluie, qui est le décor, au passé simple.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

