INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('049fc39f-7812-5cb9-ac6f-fc0eed3711b6', '9cc0d5a3-ad11-52e1-a8b6-158990d5c814', 'Complète à l''imparfait : « Quand j''étais petit, je ___ (aller) souvent à la plage de Hammamet. »', '[{"id":"a","text":"allai"},{"id":"b","text":"allais"},{"id":"c","text":"allait"},{"id":"d","text":"alla"}]'::jsonb, 'b', '« Souvent » indique une habitude → imparfait. Sur le radical de « nous allons » (all-) + -ais à la 1re personne : « j''allais » ✓. « allai » est le passé simple (je), « allait » la 3e personne et « alla » le passé simple (il).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('71f14b8f-cf0a-5985-a478-31f694d522df', '9cc0d5a3-ad11-52e1-a8b6-158990d5c814', 'Complète au passé simple : « Rania ___ (prendre) son sac et sortit aussitôt. »', '[{"id":"a","text":"prenait"},{"id":"b","text":"prena"},{"id":"c","text":"prit"},{"id":"d","text":"prda"}]'::jsonb, 'c', '« Prendre » fait au passé simple : je pris, il prit, ils prirent. À la 3e personne du singulier : « prit » ✓, ce qui s''accorde avec « sortit » juste après. « prenait » est l''imparfait ; « prena » et « prda » sont des formes inventées.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c8e53956-a59a-5a4f-b08d-eea665c441cd', '9cc0d5a3-ad11-52e1-a8b6-158990d5c814', 'Quelle valeur a l''imparfait dans : « Le vieux marchand avait une longue barbe blanche. » ?', '[{"id":"a","text":"Un portrait, une description"},{"id":"b","text":"Une action soudaine"},{"id":"c","text":"Un ordre"},{"id":"d","text":"Une succession d''actions"}]'::jsonb, 'a', 'L''imparfait sert ici à dresser le portrait d''un personnage : il décrit un état, une caractéristique qui dure. Une succession d''actions rapides se raconterait au passé simple.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e62bb3e3-0643-5657-b6c4-8592c18550ab', '9cc0d5a3-ad11-52e1-a8b6-158990d5c814', 'Complète au passé simple : « Les pêcheurs ___ (partir) avant l''aube et ___ (revenir) au coucher du soleil. »', '[{"id":"a","text":"partaient … revenaient"},{"id":"b","text":"partirent … revenirent"},{"id":"c","text":"partirent … revenaient"},{"id":"d","text":"partirent … revinrent"}]'::jsonb, 'd', '« Partir » → partirent ; « revenir » (composé de venir) garde la nasale : ils revinrent ✓. Le piège : « revenirent » construit à tort le passé simple sur l''infinitif. « partaient … revenaient » serait l''imparfait, qui ne raconte pas ces deux actions successives.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0a30a4f1-baff-5e9b-a7c0-5d0247307afb', '9cc0d5a3-ad11-52e1-a8b6-158990d5c814', 'Une phrase contient une erreur de conjugaison au passé simple. Laquelle ? « 1. Il ferma la porte. 2. Nous chantâmes en chœur. 3. Ils finissèrent le repas. 4. Elle prit son manteau. »', '[{"id":"a","text":"La phrase 1"},{"id":"b","text":"La phrase 2"},{"id":"c","text":"La phrase 3"},{"id":"d","text":"La phrase 4"}]'::jsonb, 'c', '« Finir » suit la série en -irent au passé simple : « ils finirent », et non « finissèrent » (qui mélange le radical du présent finiss- avec la terminaison -èrent des verbes en -er). Les phrases 1 (ferma), 2 (chantâmes) et 4 (prit) sont correctes. (Chasse à l''erreur : on désigne la phrase fautive.)', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6f215881-34de-5268-804c-622610f2aaac', '9cc0d5a3-ad11-52e1-a8b6-158990d5c814', 'Complète : « La foule ___ (attendre) sur le quai ; le train ___ (entrer) en gare et tout le monde ___ (monter). »', '[{"id":"a","text":"attendait … entra … monta"},{"id":"b","text":"attendit … entra … monta"},{"id":"c","text":"attendait … entrait … montait"},{"id":"d","text":"attendait … entra … montait"}]'::jsonb, 'a', '« La foule attendait » est la situation qui dure → imparfait ; puis « le train entra » et « tout le monde monta » sont les événements successifs de premier plan → passé simple ✓. Mettre l''attente au passé simple (« attendit ») ou les événements à l''imparfait (« entrait », « montait ») casse l''alternance.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

