INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('58c8601f-d676-5427-b978-0189d914fd3b', '9b379ed0-7420-51cb-b357-b6e4c4d50f3f', 'Complète au passé simple : « — Bonjour, ___ (dire) le voyageur en entrant dans l''auberge. »', '[{"id":"a","text":"disait"},{"id":"b","text":"dit"},{"id":"c","text":"dis"},{"id":"d","text":"dut"}]'::jsonb, 'b', '« Dire » fait au passé simple : je dis, il dit, ils dirent. À la 3e personne du singulier : « dit » ✓. « disait » est l''imparfait, « dis » la 1re/2e personne et « dut » est le passé simple de devoir, un autre verbe.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
