INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9b86c18e-695e-55f0-a91d-4978509fd307', '9b379ed0-7420-51cb-b357-b6e4c4d50f3f', 'Complète au passé simple : « Le capitaine ___ (tenir) bon malgré la tempête. »', '[{"id":"a","text":"tenait"},{"id":"b","text":"tena"},{"id":"c","text":"tenit"},{"id":"d","text":"tint"}]'::jsonb, 'd', '« Tenir », comme « venir », a un passé simple à nasale -in- : je tins, il tint, ils tinrent. À la 3e personne du singulier : « tint » ✓. « tenait » est l''imparfait ; « tena » et « tenit » sont des formes inventées.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
