  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bf9f13a2-f84d-5128-adbc-15ec15a9d3c5', '9b379ed0-7420-51cb-b357-b6e4c4d50f3f', 'Complète : « Le soleil ___ (briller) ; les enfants ___ (jouer) dans la cour quand la cloche ___ (sonner). »', '[{"id":"a","text":"brillait … jouaient … sonna"},{"id":"b","text":"brilla … jouèrent … sonna"},{"id":"c","text":"brillait … jouaient … sonnait"},{"id":"d","text":"brilla … jouaient … sonna"}]'::jsonb, 'a', '« Le soleil brillait » et « les enfants jouaient » sont le décor et l''action qui dure → imparfait ; « la cloche sonna » est l''événement soudain qui rompt cette durée → passé simple ✓. Mettre le décor au passé simple (« brilla ») ou l''événement à l''imparfait (« sonnait ») casse l''alternance.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ec523249-32b0-53f8-8581-513deab63f37', '9b379ed0-7420-51cb-b357-b6e4c4d50f3f', 'Une phrase raconte mal l''alternance des temps. Laquelle ? « 1. Il faisait froid ce soir-là. 2. La neige recouvrait les toits. 3. Soudain, quelqu''un frappait à la porte. 4. Le grand-père se leva pour ouvrir. »', '[{"id":"a","text":"La phrase 1"},{"id":"b","text":"La phrase 2"},{"id":"c","text":"La phrase 3"},{"id":"d","text":"La phrase 4"}]'::jsonb, 'c', '« Soudain, quelqu''un frappait » est fautif : l''action brusque exige le passé simple « quelqu''un frappa ». Les phrases 1 et 2 posent le décor qui dure (imparfait, correct) et la phrase 4 est bien un événement au passé simple. (Chasse à l''erreur : on désigne la phrase fautive.)', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4ca77bac-c5b2-58b3-a532-bf8472dce03d', '9b379ed0-7420-51cb-b357-b6e4c4d50f3f', 'Complète au passé simple : « Il ___ (vouloir) crier, mais aucun son ne ___ (pouvoir) sortir ; ce ___ (être) terrifiant. »', '[{"id":"a","text":"voulait … pouvait … était"},{"id":"b","text":"voulut … put … fut"},{"id":"c","text":"voulut … pouva … fut"},{"id":"d","text":"voula … put … fût"}]'::jsonb, 'b', 'Trois verbes de la série en -u au passé simple : vouloir → il voulut, pouvoir → il put, être → il fut ✓. « voulait … pouvait … était » serait l''imparfait ; « pouva » et « voula » appliquent à tort les terminaisons des verbes en -er, et « fût » (accent) est un subjonctif.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cebaab6f-e420-5502-b45e-66f48d9c02b7', '9b379ed0-7420-51cb-b357-b6e4c4d50f3f', 'Quelle phrase respecte l''alternance imparfait (décor) / passé simple (événement) ?', '[{"id":"a","text":"La mer était calme lorsque le bateau leva l''ancre."},{"id":"b","text":"La mer fut calme lorsque le bateau levait l''ancre."},{"id":"c","text":"La mer était calme lorsque le bateau levait l''ancre."},{"id":"d","text":"La mer fut calme lorsque le bateau leva l''ancre."}]'::jsonb, 'a', '« La mer était calme » est le décor qui dure (imparfait) et « le bateau leva l''ancre » l''événement soudain (passé simple) ✓. La phrase c laisse tout à l''imparfait (aucun événement ne surgit), et les phrases b et d mettent le décor de la mer au passé simple.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

