INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('de7a5826-bbb6-57ec-8cfc-15f0d8599c55', '806bd145-2e8e-54c4-ae5c-eace812da428', 'Comment forme-t-on le plus-que-parfait ?', '[{"id":"a","text":"l''auxiliaire être ou avoir à l''imparfait + le participe passé"},{"id":"b","text":"l''auxiliaire être ou avoir au présent + le participe passé"},{"id":"c","text":"le verbe à l''imparfait, tout simplement"},{"id":"d","text":"l''auxiliaire au futur + le participe passé"}]'::jsonb, 'a', 'Le plus-que-parfait est un temps composé : auxiliaire être ou avoir à l''IMPARFAIT (avais, était…) + participe passé, par exemple « j''avais préparé », « elle était partie ». Avec l''auxiliaire au présent, on obtiendrait le passé composé.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a85cdf52-cae8-5015-b128-09253395ac37', '806bd145-2e8e-54c4-ae5c-eace812da428', 'Quelle phrase est au plus-que-parfait ?', '[{"id":"a","text":"Le guide a préparé les chameaux."},{"id":"b","text":"Le guide avait préparé les chameaux."},{"id":"c","text":"Le guide prépare les chameaux."},{"id":"d","text":"Le guide préparera les chameaux."}]'::jsonb, 'b', '« avait préparé » = auxiliaire avoir à l''imparfait + participe passé → plus-que-parfait. « a préparé » est un passé composé (auxiliaire au présent), « prépare » un présent et « préparera » un futur.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('998f1233-d234-5725-bb29-1c8dab88e171', '806bd145-2e8e-54c4-ae5c-eace812da428', 'Le plus-que-parfait sert surtout à exprimer :', '[{"id":"a","text":"une action qui se déroule maintenant"},{"id":"b","text":"un ordre ou un conseil"},{"id":"c","text":"une action accomplie avant une autre action passée"},{"id":"d","text":"une action qui se passera plus tard"}]'::jsonb, 'c', 'Le plus-que-parfait est le « passé du passé » : il marque l''antériorité, c''est-à-dire une action déjà accomplie avant une autre action passée, comme dans « le soleil s''était couché quand ils arrivèrent ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
