INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('341dc65f-491e-5a2b-a771-864e196ef91b', '806bd145-2e8e-54c4-ae5c-eace812da428', '« Lorsque Nour ouvrit le carnet, sa grand-mère avait déjà écrit les dernières pages. » Quelle action s''est passée EN PREMIER ?', '[{"id":"a","text":"Nour a ouvert le carnet."},{"id":"b","text":"Les deux actions se passent en même temps."},{"id":"c","text":"On ne peut pas le savoir."},{"id":"d","text":"La grand-mère a écrit les dernières pages."}]'::jsonb, 'd', '« avait écrit » est au plus-que-parfait : cette action est antérieure. La grand-mère a donc écrit les pages AVANT que Nour n''ouvre le carnet, même si cette action est citée en second dans la phrase (le mot « déjà » le confirme).', 4)
