INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db90d696-ab81-5230-85b4-290708be769c', '806bd145-2e8e-54c4-ae5c-eace812da428', 'Mets « partir » au plus-que-parfait : « Les caravaniers ___ à l''aube. »', '[{"id":"a","text":"avaient partis"},{"id":"b","text":"étaient parti"},{"id":"c","text":"étaient partis"},{"id":"d","text":"ont partis"}]'::jsonb, 'c', '« partir » est un verbe de mouvement : il se conjugue avec être. Au plus-que-parfait : être à l''imparfait (étaient) + participe accordé avec le sujet masculin pluriel → « étaient partis ». « avaient partis » se trompe d''auxiliaire, « étaient parti » oublie l''accord et « ont partis » est un passé composé fautif.', 5)
