INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8fc842cd-8d08-5586-91c9-da91ae225de9', 'e7ab9fbe-4439-5a4e-9898-350e717158a8', 'À quel temps est l''auxiliaire dans un verbe au plus-que-parfait ?', '[{"id":"a","text":"à l''imparfait"},{"id":"b","text":"au présent"},{"id":"c","text":"au futur simple"},{"id":"d","text":"au passé simple"}]'::jsonb, 'a', 'Le plus-que-parfait se forme avec l''auxiliaire être ou avoir à l''imparfait (avais, était…) suivi du participe passé. Au présent, l''auxiliaire donnerait un passé composé.', 1)
