INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('456aa047-0be8-5f3c-9b9c-44567e0cc2f1', 'e7ab9fbe-4439-5a4e-9898-350e717158a8', '« Le train était déjà parti quand ils arrivèrent. » Quelle action s''est passée EN PREMIER ?', '[{"id":"a","text":"Ils sont arrivés."},{"id":"b","text":"Le train est parti."},{"id":"c","text":"Les deux en même temps."},{"id":"d","text":"Aucune des deux n''est passée."}]'::jsonb, 'b', '« était parti » est au plus-que-parfait : l''action est antérieure. Le train est donc parti AVANT leur arrivée, ce que confirme le mot « déjà ».', 5)
