INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f4cb679a-b6db-53eb-81b1-8efcb28252f7', '11a6d3c9-e0c5-54a7-86e9-c1beb338f292', 'Quelle phrase est correctement au plus-que-parfait, avec le bon accord ?', '[{"id":"a","text":"Les voyageuses étaient descendues du car."},{"id":"b","text":"Les voyageuses avaient descendues du car."},{"id":"c","text":"Les voyageuses étaient descendu du car."},{"id":"d","text":"Les voyageuses ont descendues du car."}]'::jsonb, 'a', '« descendre » (mouvement) prend être : être à l''imparfait (étaient) + participe accordé avec le sujet féminin pluriel → « étaient descendues ». « avaient descendues » se trompe d''auxiliaire, « étaient descendu » oublie l''accord et « ont descendues » est un passé composé fautif.', 2)
