INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('88098b15-963c-5127-aa89-3970f846e4fb', '11a6d3c9-e0c5-54a7-86e9-c1beb338f292', 'Transforme au plus-que-parfait : « Le vent a effacé les traces. »', '[{"id":"a","text":"Le vent était effacé les traces."},{"id":"b","text":"Le vent avait effacées les traces."},{"id":"c","text":"Le vent avait effacé les traces."},{"id":"d","text":"Le vent aura effacé les traces."}]'::jsonb, 'c', 'On garde l''auxiliaire avoir mais on le met à l''imparfait : « avait effacé ». Le COD « les traces » est placé APRÈS le verbe → pas d''accord (donc pas « effacées »). « était » se trompe d''auxiliaire et « aura » est un futur antérieur.', 3)
