INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5713e6da-6cfb-5a20-a550-e61186bb8825', '11a6d3c9-e0c5-54a7-86e9-c1beb338f292', '« Nour relut la lettre que son père lui ___ avant le départ. » Complète au plus-que-parfait avec le bon accord.', '[{"id":"a","text":"avait écrit"},{"id":"b","text":"était écrite"},{"id":"c","text":"avait écrits"},{"id":"d","text":"avait écrite"}]'::jsonb, 'd', 'Avec avoir, le participe s''accorde avec le COD placé avant : « que » reprend « la lettre » (féminin singulier), placé avant le verbe → « avait écrite ». « avait écrit » oublie cet accord, « était écrite » se trompe d''auxiliaire et « avait écrits » accorde au masculin pluriel à tort.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9360e584-cdcf-5b36-87de-38c9109ad666', '11a6d3c9-e0c5-54a7-86e9-c1beb338f292', 'Dans « Ils campèrent là où les nomades s''étaient arrêtés la veille », que dit le plus-que-parfait ?', '[{"id":"a","text":"L''arrêt des nomades est antérieur : il a eu lieu avant que « ils » ne campent."},{"id":"b","text":"Les deux actions ont lieu exactement en même temps."},{"id":"c","text":"L''arrêt des nomades aura lieu après le campement."},{"id":"d","text":"Les nomades s''arrêtent au moment où « ils » campent."}]'::jsonb, 'a', '« s''étaient arrêtés » est au plus-que-parfait : il marque l''antériorité. L''arrêt des nomades s''est produit AVANT le campement de « ils », ce que renforce « la veille ». C''est le passé du passé.', 5)
ON CONFLICT (id) DO UPDATE SET
