  ('e4d6cf70-c5fb-5aa2-8efa-58c25f6d8716', '11a6d3c9-e0c5-54a7-86e9-c1beb338f292', 'Une seule phrase respecte à la fois le temps (plus-que-parfait) ET l''accord. Laquelle ?', '[{"id":"a","text":"La caravane avait reparti avant l''orage."},{"id":"b","text":"La caravane est repartie avant l''orage."},{"id":"c","text":"La caravane était repartie avant l''orage."},{"id":"d","text":"La caravane était reparti avant l''orage."}]'::jsonb, 'c', '« repartir » prend être : être à l''imparfait (était) + participe accordé avec le sujet féminin singulier « la caravane » → « était repartie ». « avait reparti » se trompe d''auxiliaire, « est repartie » est un passé composé (auxiliaire au présent) et « était reparti » oublie l''accord au féminin.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

