INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('070b0783-85c1-5f01-bbb8-e6f7f935c6e7', 'e4dcba47-e07a-5d79-a3b3-f2a0e270bab3', 'Conjugue « faire » au plus-que-parfait : « Vous ___ un long détour. »', '[{"id":"a","text":"aviez fait"},{"id":"b","text":"avez fait"},{"id":"c","text":"étiez faits"},{"id":"d","text":"faisiez"}]'::jsonb, 'a', 'Plus-que-parfait = avoir à l''imparfait (aviez) + participe passé « fait » → « aviez fait ». « avez fait » est un passé composé et « faisiez » un imparfait simple.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aa0dfe4c-8fa0-594a-9668-d2a2e5732d05', 'e4dcba47-e07a-5d79-a3b3-f2a0e270bab3', 'Transforme au plus-que-parfait : « La rivière a débordé sur la route. »', '[{"id":"a","text":"La rivière était débordée sur la route."},{"id":"b","text":"La rivière avait débordée sur la route."},{"id":"c","text":"La rivière avait débordé sur la route."},{"id":"d","text":"La rivière aurait débordé sur la route."}]'::jsonb, 'c', '« déborder » se conjugue ici avec avoir : avoir à l''imparfait (avait) + participe passé « débordé », qui ne s''accorde pas avec le sujet → « avait débordé ». « était débordée » change d''auxiliaire, « avait débordée » accorde à tort avec le sujet et « aurait débordé » est un conditionnel passé.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('72ab51f2-7749-50e2-b1f2-ed95f3282408', 'e4dcba47-e07a-5d79-a3b3-f2a0e270bab3', 'Complète au plus-que-parfait avec le bon accord : « Les portes que le gardien ___ restaient closes. »', '[{"id":"a","text":"avait fermé"},{"id":"b","text":"avait fermées"},{"id":"c","text":"avait fermés"},{"id":"d","text":"étaient fermées"}]'::jsonb, 'b', 'Avec avoir, accord avec le COD placé avant : « que » reprend « les portes » (féminin pluriel) → « avait fermées ». « avait fermé » oublie l''accord, « avait fermés » accorde au masculin à tort et « étaient fermées » se trompe d''auxiliaire (le sujet est « le gardien », pas « les portes »).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d50cb9d1-5b3f-5c4a-b11d-2d5ce9f565ef', 'e4dcba47-e07a-5d79-a3b3-f2a0e270bab3', 'Choisis la forme qui exprime l''antériorité : « Il repensait au conseil que son grand-père lui ___. »', '[{"id":"a","text":"a donné"},{"id":"b","text":"donnera"},{"id":"c","text":"donnait"},{"id":"d","text":"avait donné"}]'::jsonb, 'd', 'Le conseil a été donné AVANT le moment où il y repense (imparfait « repensait ») : c''est l''antériorité → plus-que-parfait « avait donné ». Le COD « que » = « le conseil » (masculin singulier) → pas de -s. Les autres temps ne marquent pas ce passé antérieur.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9bb43e48-3151-5f4d-bb84-42c14be12313', 'e4dcba47-e07a-5d79-a3b3-f2a0e270bab3', 'Quelle phrase est entièrement correcte ?', '[{"id":"a","text":"Dès qu''elles étaient descendues, le bus était reparti."},{"id":"b","text":"Dès qu''elles avaient descendues, le bus avait reparti."},{"id":"c","text":"Dès qu''elles étaient descendu, le bus était repartis."},{"id":"d","text":"Dès qu''elles sont descendues, le bus est reparti."}]'::jsonb, 'a', '« descendre » et « repartir » prennent être : être à l''imparfait + accord avec le sujet → « étaient descendues » (féminin pluriel) et « était reparti » (masculin singulier « le bus »). « avaient descendues… avait reparti » se trompe d''auxiliaire, « étaient descendu… était repartis » fait de mauvais accords et « sont descendues… est reparti » est au passé composé.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8822c30f-95a7-56b0-a858-13b39ec33b20', 'e4dcba47-e07a-5d79-a3b3-f2a0e270bab3', 'Réécris au plus-que-parfait : « Le porteur a chargé les sacs que nous avons préparés. »', '[{"id":"a","text":"Le porteur avait chargés les sacs que nous avions préparé."},{"id":"b","text":"Le porteur avait chargé les sacs que nous avions préparés."},{"id":"c","text":"Le porteur était chargé les sacs que nous étions préparés."},{"id":"d","text":"Le porteur avait chargé les sacs que nous avions préparé."}]'::jsonb, 'b', '« chargé » : COD « les sacs » placé après → invariable. « préparés » : COD « que » (= les sacs, masculin pluriel) placé avant → accord. On met les deux auxiliaires avoir à l''imparfait → « avait chargé », « avions préparés ». « avait chargés… avions préparé » inverse les accords, « était chargé… étions préparés » se trompe d''auxiliaire et « avait chargé… avions préparé » oublie l''accord de « préparés ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

