  ('c34e8099-6e8c-52dd-9ee8-a0a1279348b9', '5df22e8c-3ae7-5f51-acf2-2894984d24e0', 'french-8eme', '👑 Défi élite ⭐⭐⭐⭐ : le grand voyage du temps', 4, 300, 60, 'challenge', 'admin', 6)
