INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b5417585-d90d-56f4-a4da-040e35ea01e4', 'c34e8099-6e8c-52dd-9ee8-a0a1279348b9', 'Transforme au plus-que-parfait : « Elle s''est souvenue du chemin et elle a retrouvé la source. »', '[{"id":"a","text":"Elle s''avait souvenue du chemin et elle était retrouvé la source."},{"id":"b","text":"Elle s''était souvenue du chemin et elle avait retrouvé la source."},{"id":"c","text":"Elle s''était souvenu du chemin et elle avait retrouvée la source."},{"id":"d","text":"Elle s''est souvenue du chemin et elle avait retrouvé la source."}]'::jsonb, 'b', '« se souvenir » (pronominal) → être → « s''était souvenue » (accord au féminin). « retrouver » → avoir, COD « la source » après → invariable → « avait retrouvé ». « s''avait souvenue » emploie avoir pour le pronominal, « s''était souvenu… avait retrouvée » fait de mauvais accords et « s''est souvenue » laisse le premier verbe au passé composé.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6a2ed2f2-4d7e-576f-98a7-073dcb6cc94c', 'c34e8099-6e8c-52dd-9ee8-a0a1279348b9', '« Nous rebroussâmes chemin, car la neige ___ tous les cols. » Complète pour marquer l''antériorité.', '[{"id":"a","text":"a bloqué"},{"id":"b","text":"bloquait"},{"id":"c","text":"bloquera"},{"id":"d","text":"avait bloqué"}]'::jsonb, 'd', 'Le blocage des cols est la CAUSE antérieure à « rebroussâmes chemin » (passé simple) : on emploie le plus-que-parfait « avait bloqué ». « a bloqué » (passé composé) et « bloquait » (imparfait) ne marquent pas nettement ce passé antérieur, et « bloquera » est un futur.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('483cc858-118e-5a77-aae2-f8aaaa083199', 'c34e8099-6e8c-52dd-9ee8-a0a1279348b9', 'Dans « Le voyageur montra les photos qu''il avait prises dans les villes qu''il avait visitées », les deux plus-que-parfaits sont-ils bien accordés ?', '[{"id":"a","text":"Oui : « prises » s''accorde avec « les photos » et « visitées » avec « les villes », tous deux COD placés avant."},{"id":"b","text":"Non : avec avoir, le participe reste toujours invariable."},{"id":"c","text":"Non : les deux participes doivent s''accorder avec le sujet « il »."},{"id":"d","text":"Oui, mais seulement parce que ce sont des verbes de mouvement."}]'::jsonb, 'a', 'Avec avoir, le participe s''accorde avec le COD placé avant. « qu'' » reprend « les photos » puis « les villes » (féminin pluriel), tous deux avant le verbe → « prises », « visitées ». Avec avoir, jamais d''accord avec le sujet ; et ce ne sont pas des verbes de mouvement.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c8931f38-b38f-5208-97e2-f58eb8481b14', 'c34e8099-6e8c-52dd-9ee8-a0a1279348b9', 'Quelle phrase place correctement les faits dans le temps : le départ AVANT l''arrivée du télégramme ?', '[{"id":"a","text":"Le télégramme arriva, mais le capitaine est déjà parti."},{"id":"b","text":"Le télégramme était arrivé, mais le capitaine partait déjà."},{"id":"c","text":"Le télégramme arriva, mais le capitaine était déjà parti."},{"id":"d","text":"Le télégramme arrivait, mais le capitaine partira déjà."}]'::jsonb, 'c', 'Pour que le départ précède l''arrivée, on met le départ au plus-que-parfait (« était déjà parti ») et l''arrivée au passé simple (« arriva »). « le capitaine est déjà parti » mélange passé simple et passé composé, « était arrivé… partait déjà » inverse l''ordre des faits et « arrivait… partira déjà » emploie un futur incohérent.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b99f3104-f8e2-517c-a7c4-a2fe6d0cc27c', 'c34e8099-6e8c-52dd-9ee8-a0a1279348b9', 'Réécris au plus-que-parfait : « Les sentiers se sont effacés et les repères ont disparu. »', '[{"id":"a","text":"Les sentiers s''avaient effacés et les repères étaient disparu."},{"id":"b","text":"Les sentiers s''étaient effacés et les repères avaient disparu."},{"id":"c","text":"Les sentiers s''étaient effacé et les repères avaient disparus."},{"id":"d","text":"Les sentiers se sont effacés et les repères avaient disparu."}]'::jsonb, 'b', '« s''effacer » (pronominal) → être → « s''étaient effacés » (accord au masculin pluriel). « disparaître » → avoir, COD absent → invariable → « avaient disparu ». « s''avaient effacés » emploie avoir pour le pronominal, « s''étaient effacé… avaient disparus » fait de mauvais accords et « se sont effacés » laisse le premier verbe au passé composé.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eaf6888d-ea1c-55ed-ac99-03e81635fa2c', 'c34e8099-6e8c-52dd-9ee8-a0a1279348b9', 'Une seule phrase est irréprochable (temps, auxiliaires et accords). Laquelle ?', '[{"id":"a","text":"La lettre qu''elles avaient reçue annonçait le retour de ceux qui étaient partis en mer."},{"id":"b","text":"La lettre qu''elles avaient reçu annonçait le retour de ceux qui avaient partis en mer."},{"id":"c","text":"La lettre qu''elles avaient reçue annonçait le retour de ceux qui étaient parti en mer."},{"id":"d","text":"La lettre qu''elles avaient reçues annonçait le retour de ceux qui étaient partis en mer."}]'::jsonb, 'a', '« qu'' » reprend « la lettre » (féminin singulier), COD avant avoir → « reçue ». « partir » → être, accord avec « ceux » (masculin pluriel) → « étaient partis ». « avaient reçu… avaient partis » oublie l''accord de « reçu » et met « partir » avec avoir, « étaient parti » oublie l''accord de « parti » et « avaient reçues » accorde « reçue » au pluriel alors que « la lettre » est singulier.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
