INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a70155ed-a5ac-5709-9469-3910628a6dd5', '5b02a1d9-3510-5cb7-8500-8b72ccf3d116', 'Quelles sont les trois expansions du nom qui enrichissent un groupe nominal ?', '[{"id":"a","text":"L''adjectif épithète, le complément du nom et la proposition relative"},{"id":"b","text":"Le sujet, le verbe et le complément d''objet"},{"id":"c","text":"Le déterminant, le nom noyau et le pronom"},{"id":"d","text":"Le présent, le passé composé et le futur"}]'::jsonb, 'a', 'On étend un GN de trois façons : l''adjectif épithète (un décor somptueux), le complément du nom (le rideau de la scène) et la proposition relative (l''actrice qui salue). Le sujet, le verbe et le déterminant ne sont pas des expansions du nom.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('66394e1e-9b19-51e5-b820-219b017e30f9', '5b02a1d9-3510-5cb7-8500-8b72ccf3d116', 'Dans une proposition subordonnée relative, le pronom relatif « qui » occupe le plus souvent la fonction de :', '[{"id":"a","text":"COD du verbe"},{"id":"b","text":"sujet du verbe"},{"id":"c","text":"complément de lieu"},{"id":"d","text":"complément du nom"}]'::jsonb, 'b', '« qui » remplace l''antécédent dans la fonction de sujet : le comédien qui salue (= il salue). Le COD correspond à « que », le complément de lieu à « où », et le complément du nom n''est pas un pronom relatif.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a19da4c4-586e-5b5f-b550-9fad61726b3d', '5b02a1d9-3510-5cb7-8500-8b72ccf3d116', 'Comment est construit un complément du nom ?', '[{"id":"a","text":"Avec un pronom relatif suivi d''un verbe conjugué"},{"id":"b","text":"Avec un verbe d''état qui relie l''adjectif au sujet"},{"id":"c","text":"Avec une préposition (de, à, en…) suivie le plus souvent d''un nom"},{"id":"d","text":"Avec un déterminant placé seul devant le nom"}]'::jsonb, 'c', 'Le complément du nom se construit avec une préposition + un nom (ou un infinitif) : le costume de l''acteur, une machine à écrire. Le pronom relatif + verbe donne une relative, et le verbe d''état introduit un attribut, pas un complément du nom.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e17ec231-188e-5083-884d-4fc85d4518d6', '5b02a1d9-3510-5cb7-8500-8b72ccf3d116', 'L''adjectif relié au nom par un verbe d''état (être, sembler, devenir, rester…) s''appelle :', '[{"id":"a","text":"un adjectif épithète"},{"id":"b","text":"un complément du nom"},{"id":"c","text":"un attribut du sujet"},{"id":"d","text":"un pronom relatif"}]'::jsonb, 'c', 'Un verbe d''état entre le sujet et l''adjectif fait de cet adjectif un attribut du sujet : cette actrice est talentueuse. L''épithète, lui, est collé au nom dans le GN (une actrice talentueuse) et l''attribut n''est pas une expansion du nom.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('682a9b9f-fe9b-5b91-b56f-ea08033c52ca', '5b02a1d9-3510-5cb7-8500-8b72ccf3d116', 'On emploie le pronom relatif « dont » quand il remplace un complément introduit par :', '[{"id":"a","text":"la préposition « de »"},{"id":"b","text":"la préposition « à »"},{"id":"c","text":"aucune préposition"},{"id":"d","text":"un déterminant"}]'::jsonb, 'a', '« dont » remplace un complément en « de » : le livre dont je parle (= parler de ce livre), l''actrice dont le talent éblouit (= le talent de l''actrice). Si le verbe ne se construit pas avec « de », on choisit un autre pronom (qui, que, où).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

