INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3c3a817d-3433-59ce-9894-a8e893ba44e9', '168516bc-49e0-5391-928c-2ae1962e0d17', 'Lequel de ces groupes nominaux est étendu (enrichi d''une expansion) ?', '[{"id":"a","text":"le spectacle éblouissant"},{"id":"b","text":"le spectacle"},{"id":"c","text":"une actrice"},{"id":"d","text":"des lectures"}]'::jsonb, 'a', '« le spectacle éblouissant » = déterminant + nom + adjectif épithète : le GN est étendu par une expansion. « le spectacle », « une actrice » et « des lectures » sont des GN minimaux (déterminant + nom seul).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
