  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c471aecb-4150-5b39-bd10-e1ac576c0fba', '168516bc-49e0-5391-928c-2ae1962e0d17', 'Dans la phrase « Yassine range ses vieux cahiers dans le tiroir. », quel mot est un adjectif épithète ?', '[{"id":"a","text":"range"},{"id":"b","text":"vieux"},{"id":"c","text":"Yassine"},{"id":"d","text":"tiroir"}]'::jsonb, 'b', '« vieux » est un adjectif placé dans le GN, à côté du nom « cahiers » : c''est une épithète. « range » est le verbe, « Yassine » et « tiroir » sont des noms.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f2e69a96-ca60-5582-97d3-fcdcf44e93e8', '168516bc-49e0-5391-928c-2ae1962e0d17', 'Dans le groupe « le costume de la danseuse », quelle est l''expansion (complément) du nom « costume » ?', '[{"id":"a","text":"« le »"},{"id":"b","text":"« costume »"},{"id":"c","text":"« de la danseuse »"},{"id":"d","text":"il n''y a aucune expansion"}]'::jsonb, 'c', '« de la danseuse » = préposition « de » + nom : c''est un complément du nom qui précise « costume ». « le » est un déterminant et « costume » est le nom noyau.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('16427c7c-4488-56a0-b597-6a6d65e65147', '168516bc-49e0-5391-928c-2ae1962e0d17', 'Complète : « Le musicien ____ joue du oud est mon voisin. »', '[{"id":"a","text":"qui"},{"id":"b","text":"que"},{"id":"c","text":"dont"},{"id":"d","text":"où"}]'::jsonb, 'a', 'Reconstruis la relative : « le musicien joue du oud ». « le musicien » y est sujet du verbe « joue » → pronom relatif « qui ». « que » serait un COD, « dont » un complément en « de », « où » un lieu ou un temps.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c3372f56-f7f5-5067-a640-c4846f3d000a', '168516bc-49e0-5391-928c-2ae1962e0d17', 'Complète : « Le roman ____ Rym préfère raconte un voyage à Bizerte. »', '[{"id":"a","text":"qui"},{"id":"b","text":"que"},{"id":"c","text":"où"},{"id":"d","text":"dont"}]'::jsonb, 'b', 'Reconstruis la relative : « Rym préfère le roman ». « le roman » y est COD du verbe « préfère » (Rym est déjà le sujet) → pronom relatif « que ». On ne peut pas mettre « qui », car « qui » est toujours sujet.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bb13a134-a40e-5b67-833f-b30ced21bf27', '168516bc-49e0-5391-928c-2ae1962e0d17', 'Complète : « Voici la salle ____ nous répétons la pièce. »', '[{"id":"a","text":"qui"},{"id":"b","text":"que"},{"id":"c","text":"dont"},{"id":"d","text":"où"}]'::jsonb, 'd', 'Reconstruis la relative : « nous répétons la pièce dans la salle ». « la salle » y est complément de lieu → pronom relatif « où ». « nous » est déjà le sujet et « la pièce » le COD, donc ni « qui » ni « que ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
