INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('640600a3-a1c7-52b4-a809-db1bf7051037', 'ec70b8e6-e4dc-5ead-b605-74cac0c9d441', 'Complète : « L''écrivain ____ a signé ce roman vit à Sfax. »', '[{"id":"a","text":"qui"},{"id":"b","text":"que"},{"id":"c","text":"dont"},{"id":"d","text":"où"}]'::jsonb, 'a', 'Dans la relative « l''écrivain a signé ce roman », « l''écrivain » est sujet du verbe « a signé » → « qui ». Indice sûr : « qui » n''a jamais de sujet derrière lui, car il est lui-même le sujet.', 1)
