INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('08df363a-23fc-5118-b262-ecb498b8a186', 'ec70b8e6-e4dc-5ead-b605-74cac0c9d441', 'Complète : « La pièce ____ les élèves ont jouée a duré une heure. »', '[{"id":"a","text":"qui"},{"id":"b","text":"où"},{"id":"c","text":"que"},{"id":"d","text":"dont"}]'::jsonb, 'c', 'Dans la relative « les élèves ont joué la pièce », « la pièce » est COD (le sujet est « les élèves ») → « que ». Indice sûr : « que » a toujours un sujet derrière lui, ici « les élèves ».', 2)
ON CONFLICT (id) DO UPDATE SET
