INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d85aee5b-6d0a-5088-8480-5a2a9e55a6c6', 'ec70b8e6-e4dc-5ead-b605-74cac0c9d441', 'Dans « Skander admire le décor du spectacle. », quelle analyse est correcte ?', '[{"id":"a","text":"« le décor du spectacle » est complément du nom du verbe « admire »"},{"id":"b","text":"« du spectacle » est le COD de « admire »"},{"id":"c","text":"« du spectacle » est un adjectif épithète"},{"id":"d","text":"« le décor du spectacle » est COD de « admire », et « du spectacle » est complément du nom de « décor »"}]'::jsonb, 'd', '« admire quoi ? » → « le décor du spectacle » : c''est le COD du verbe. À l''intérieur de ce GN, « du spectacle » (préposition + nom) est complément du nom « décor ». Un COD complète le verbe sans préposition ; un complément du nom suit un nom avec préposition.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c8620980-6034-5468-acd3-a010499ed87e', 'ec70b8e6-e4dc-5ead-b605-74cac0c9d441', 'Complète : « Voici le tableau ____ l''artiste est très fière. »', '[{"id":"a","text":"dont"},{"id":"b","text":"que"},{"id":"c","text":"qui"},{"id":"d","text":"où"}]'::jsonb, 'a', 'On dit « être fière DE quelque chose » : le complément est introduit par « de » → pronom relatif « dont » (l''artiste est fière de ce tableau). « que » (COD) serait faux, car « être fière » ne se construit pas sans préposition.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
