  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fdad03aa-2fa1-5d17-ab13-21fd9e330950', 'ec70b8e6-e4dc-5ead-b605-74cac0c9d441', 'Dans « Les spectateurs enthousiastes deviennent silencieux quand la musique commence. », comment analyser « enthousiastes » et « silencieux » ?', '[{"id":"a","text":"les deux sont des adjectifs épithètes"},{"id":"b","text":"« enthousiastes » est épithète et « silencieux » est attribut du sujet"},{"id":"c","text":"« enthousiastes » est attribut et « silencieux » est épithète"},{"id":"d","text":"les deux sont des attributs du sujet"}]'::jsonb, 'b', '« enthousiastes » est collé au nom « spectateurs » dans le GN → épithète. « silencieux » est relié au sujet par le verbe d''état « deviennent » → attribut du sujet. Seul l''adjectif introduit par un verbe d''état est attribut.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
