  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f6ec186f-cd54-54ee-bfdc-1bddcb6a7aaa', 'ec70b8e6-e4dc-5ead-b605-74cac0c9d441', 'Parmi ces phrases, laquelle est correctement construite ?', '[{"id":"a","text":"Le film que je l''ai regardé était long."},{"id":"b","text":"Le film que j''ai regardé était long."},{"id":"c","text":"Le film qui j''ai regardé était long."},{"id":"d","text":"Le film dont j''ai regardé était long."}]'::jsonb, 'b', '« que » remplace déjà l''antécédent COD (le film) : on n''ajoute pas de pronom « l'' » (erreur en a). « qui » serait sujet (faux, le sujet est « je »), et « regarder » ne se construit pas avec « de » (donc pas « dont »).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
