INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6575ff6f-79fb-5304-9356-ae8bdb54038c', '26c99f06-a2fe-503c-bdfe-a9e6dfba7466', 'Dans « Cette représentation semble magnifique. », le mot « magnifique » est :', '[{"id":"a","text":"un adjectif épithète"},{"id":"b","text":"un complément du nom"},{"id":"c","text":"un attribut du sujet"},{"id":"d","text":"un pronom relatif"}]'::jsonb, 'c', '« semble » est un verbe d''état qui relie l''adjectif « magnifique » au sujet « représentation » → attribut du sujet. Il serait épithète s''il touchait le nom dans le GN : « une représentation magnifique ».', 3)
