INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c3a6d600-bfbb-5930-b946-1778125af814', '26c99f06-a2fe-503c-bdfe-a9e6dfba7466', 'Complète : « C''est un festival ____ tout le monde parle à Hammamet. »', '[{"id":"a","text":"que"},{"id":"b","text":"qui"},{"id":"c","text":"où"},{"id":"d","text":"dont"}]'::jsonb, 'd', 'On dit « parler DE quelque chose » : le complément est introduit par « de » → « dont » (tout le monde parle de ce festival). « que » (COD) serait faux, car « parler » se construit ici avec « de ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4e10e529-32a8-5a5e-ac41-3bf1fe5436aa', '26c99f06-a2fe-503c-bdfe-a9e6dfba7466', 'Complète : « Je me souviens du jour ____ le rideau s''est levé pour la première fois. »', '[{"id":"a","text":"où"},{"id":"b","text":"que"},{"id":"c","text":"qui"},{"id":"d","text":"dont"}]'::jsonb, 'a', '« où » ne marque pas seulement le lieu, mais aussi le temps : « le jour où le rideau s''est levé ». Le sujet de la relative est déjà « le rideau », donc ni « qui » ni « que ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9a70b15a-92ea-5ced-ab5e-2758156a0177', '26c99f06-a2fe-503c-bdfe-a9e6dfba7466', 'Dans « Les acteurs que Nour a rencontrés sont tunisiens. », quel est l''antécédent du pronom relatif « que » ?', '[{"id":"a","text":"Nour"},{"id":"b","text":"tunisiens"},{"id":"c","text":"Les acteurs"},{"id":"d","text":"rencontrés"}]'::jsonb, 'c', 'L''antécédent est le nom placé juste avant le pronom relatif, celui que la relative enrichit : « Les acteurs ». C''est aussi lui que « que » remplace comme COD dans « Nour a rencontré les acteurs ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

