INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('808bc191-b92f-51a1-a925-4849b52c7a6a', '412a0516-3a8c-5369-bad9-a302eb1d9f67', 'Dans « le jeune violoniste du conservatoire qui a ébloui la salle », classe les trois expansions du nom « violoniste » dans l''ordre où elles apparaissent.', '[{"id":"a","text":"adjectif épithète, complément du nom, proposition relative"},{"id":"b","text":"complément du nom, adjectif épithète, proposition relative"},{"id":"c","text":"proposition relative, adjectif épithète, complément du nom"},{"id":"d","text":"attribut du sujet, complément du nom, proposition relative"}]'::jsonb, 'a', '« jeune » (adjectif à côté du nom) = épithète, « du conservatoire » (préposition + nom) = complément du nom, « qui a ébloui la salle » (pronom relatif + verbe) = proposition relative. Il n''y a pas d''attribut, car aucun verbe d''état ne relie un adjectif au sujet.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d92c5f0c-91aa-55d2-ab1e-c6d04d5f10dc', '412a0516-3a8c-5369-bad9-a302eb1d9f67', 'Complète : « Kairouan est la ville ____ ce poète se souvient avec émotion. »', '[{"id":"a","text":"où"},{"id":"b","text":"dont"},{"id":"c","text":"que"},{"id":"d","text":"qui"}]'::jsonb, 'b', 'Piège : « ville » évoque un lieu, mais c''est le VERBE qui commande le pronom. On dit « se souvenir DE quelque chose » → complément en « de » → « dont » (ce poète se souvient de la ville). « où » ne conviendrait que pour « habiter, vivre, aller » dans un lieu.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c0a90b02-31cf-50c5-adf9-0b3a9e15c7ee', '412a0516-3a8c-5369-bad9-a302eb1d9f67', 'Complète : « Voici le village ____ mes grands-parents ont vécu quarante ans. »', '[{"id":"a","text":"dont"},{"id":"b","text":"que"},{"id":"c","text":"où"},{"id":"d","text":"qui"}]'::jsonb, 'c', 'Ici « vivre » indique le lieu : « mes grands-parents ont vécu DANS le village » → complément de lieu → « où ». À comparer avec « se souvenir DE » qui, lui, appelle « dont » : c''est la construction du verbe qui décide, pas le mot « village ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('215de355-70d1-516d-b220-dc0ffc421a70', '412a0516-3a8c-5369-bad9-a302eb1d9f67', 'Complète : « L''outil ____ le sculpteur a besoin est introuvable. »', '[{"id":"a","text":"que"},{"id":"b","text":"qui"},{"id":"c","text":"où"},{"id":"d","text":"dont"}]'::jsonb, 'd', 'On dit « avoir besoin DE quelque chose » : le complément est introduit par « de » → « dont » (le sculpteur a besoin de cet outil). L''erreur fréquente est de mettre « que », mais « que » remplace un COD sans préposition.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f4ded87a-9b18-5a2d-a7c2-f63c6c63a623', '412a0516-3a8c-5369-bad9-a302eb1d9f67', 'Dans « Le rideau rouge de la scène paraît lourd. », quelle analyse des trois éléments est correcte ?', '[{"id":"a","text":"« rouge » = attribut, « de la scène » = COD, « lourd » = épithète"},{"id":"b","text":"« rouge » = épithète, « de la scène » = complément du nom, « lourd » = attribut du sujet"},{"id":"c","text":"« rouge » = épithète, « de la scène » = complément du nom, « lourd » = épithète"},{"id":"d","text":"« rouge » = complément du nom, « de la scène » = épithète, « lourd » = attribut"}]'::jsonb, 'b', '« rouge » touche le nom « rideau » dans le GN → épithète. « de la scène » (préposition + nom) → complément du nom de « rideau ». « paraît » est un verbe d''état qui relie « lourd » au sujet → attribut du sujet.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d10d4d95-2e83-57fb-8e85-0c8254b0a165', '412a0516-3a8c-5369-bad9-a302eb1d9f67', 'Parmi ces phrases, laquelle est correcte ?', '[{"id":"a","text":"C''est un auteur dont j''admire le style."},{"id":"b","text":"C''est un auteur dont j''admire son style."},{"id":"c","text":"C''est un auteur que j''admire son style."},{"id":"d","text":"C''est un auteur dont son style est célèbre."}]'::jsonb, 'a', '« dont » contient déjà l''idée de « de l''auteur » : on ne répète donc pas « son » (erreurs en b et d). La construction correcte est « dont j''admire le style » (= j''admire le style de l''auteur). « que » (COD) ne conviendrait pas ici.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

