INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fe2e430d-c200-5589-843c-37dfefcbda1d', '208e953c-1fac-53f9-bee3-e21de5388258', 'Complète : « Le café ____ nous nous retrouvons se trouve près du théâtre. »', '[{"id":"a","text":"qui"},{"id":"b","text":"que"},{"id":"c","text":"dont"},{"id":"d","text":"où"}]'::jsonb, 'd', '« se retrouver DANS un lieu » : complément de lieu → « où » (nous nous retrouvons dans le café). Le sujet « nous » est déjà présent, donc ni « qui » ni « que » ; et le verbe ne se construit pas avec « de », donc pas « dont ».', 1)
