INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3e74120a-a237-5338-8812-b18640ad762d', '208e953c-1fac-53f9-bee3-e21de5388258', 'Complète : « C''est une chanteuse ____ la voix émeut tout le public. »', '[{"id":"a","text":"qui"},{"id":"b","text":"que"},{"id":"c","text":"dont"},{"id":"d","text":"où"}]'::jsonb, 'c', '« la voix DE la chanteuse » : le lien de possession se dit avec « de » → « dont » (la voix de la chanteuse émeut le public). « qui » serait faux : ce n''est pas la chanteuse qui émeut directement, c''est sa voix.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
