  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1ac23c78-f026-5357-8131-984fcd2260fa', '208e953c-1fac-53f9-bee3-e21de5388258', 'Quelle phrase respecte les règles d''élision du pronom relatif ?', '[{"id":"a","text":"L''ami qu''applaudit la scène est parti."},{"id":"b","text":"Le rôle qu''il joue est difficile."},{"id":"c","text":"L''ami qui''applaudit crie fort."},{"id":"d","text":"Le rôle que il joue est difficile."}]'::jsonb, 'b', '« que » s''élide en « qu'' » devant une voyelle : « le rôle qu''il joue » ✓. « qui » ne s''élide JAMAIS (donc « qu''applaudit » et « qui''applaudit » sont faux), et devant « il » on doit élider « que » (donc « que il » est faux).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4bc931d2-dbc2-5b49-9d03-4ef1b56aefca', '208e953c-1fac-53f9-bee3-e21de5388258', 'Quelle proposition relative équivaut au groupe nominal « une actrice du théâtre de Tunis » ?', '[{"id":"a","text":"une actrice qui joue au théâtre de Tunis"},{"id":"b","text":"une actrice que le théâtre de Tunis"},{"id":"c","text":"une actrice dont le théâtre de Tunis"},{"id":"d","text":"une actrice où le théâtre de Tunis"}]'::jsonb, 'a', 'Pour transformer le complément du nom « du théâtre de Tunis » en relative, il faut un verbe : « qui joue au théâtre de Tunis ». Les autres réponses n''ont pas de verbe conjugué, donc ne forment aucune proposition relative.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('03a507c5-76e8-5ff9-9797-1e6642e90d91', '208e953c-1fac-53f9-bee3-e21de5388258', 'Dans « Ines écoute la mélodie du violon. », quel groupe est complément du nom ?', '[{"id":"a","text":"la mélodie du violon"},{"id":"b","text":"du violon"},{"id":"c","text":"écoute"},{"id":"d","text":"Ines"}]'::jsonb, 'b', '« du violon » (préposition + nom) précise le nom « mélodie » : c''est un complément du nom. « la mélodie du violon » entier est le COD du verbe « écoute » (écoute quoi ?), pas un complément du nom.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

