INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a214076-ee98-5845-8ba1-11c8598ffa78', 'c6afe901-7396-5b5f-890f-9619f76909e7', 'Complète : « La comédienne ____ le metteur en scène a choisie répète chaque soir. »', '[{"id":"a","text":"qui"},{"id":"b","text":"dont"},{"id":"c","text":"que"},{"id":"d","text":"où"}]'::jsonb, 'c', 'Dans la relative « le metteur en scène a choisi la comédienne », le sujet est « le metteur en scène » et « la comédienne » est COD → « que ». L''accord « choisie » confirme le COD féminin placé avant le verbe. « qui » serait sujet, donc faux.', 1)
