INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('afbe28e6-8732-5d6b-9dc6-8453900bd099', 'c6afe901-7396-5b5f-890f-9619f76909e7', 'Complète : « La troupe compte douze artistes, ____ trois viennent de Sfax. »', '[{"id":"a","text":"que"},{"id":"b","text":"qui"},{"id":"c","text":"où"},{"id":"d","text":"dont"}]'::jsonb, 'd', '« dont » exprime ici un prélèvement dans un ensemble : « trois DES douze artistes » → « dont trois viennent de Sfax ». C''est la valeur partitive de « dont » (= parmi lesquels). « qui » désignerait tous les artistes, ce qui change le sens.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('30f52478-7dfd-55ba-8812-59ecf17103ff', 'c6afe901-7396-5b5f-890f-9619f76909e7', 'Quelle phrase transforme correctement « un poème dont j''ignore l''auteur » sans changer le sens ?', '[{"id":"a","text":"un poème dont l''auteur m''est inconnu"},{"id":"b","text":"un poème que j''ignore l''auteur"},{"id":"c","text":"un poème qui j''ignore l''auteur"},{"id":"d","text":"un poème où j''ignore l''auteur"}]'::jsonb, 'a', '« dont » remplace « de » : « j''ignore l''auteur DE ce poème » équivaut à « l''auteur de ce poème m''est inconnu », donc « dont l''auteur m''est inconnu ». « que » et « qui » ne conviennent pas à un complément en « de », et « où » marque le lieu ou le temps.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d8c9bb84-671d-5275-97f0-cfbef982e690', 'c6afe901-7396-5b5f-890f-9619f76909e7', 'Combien de compléments du nom la phrase « Le directeur du festival remercie les bénévoles du théâtre. » contient-elle ?', '[{"id":"a","text":"aucun"},{"id":"b","text":"un seul"},{"id":"c","text":"deux"},{"id":"d","text":"trois"}]'::jsonb, 'c', 'Deux compléments du nom : « du festival » (complément de « directeur ») et « du théâtre » (complément de « bénévoles »). « les bénévoles du théâtre » entier est le COD du verbe « remercie », ce n''est pas un complément du nom.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

