INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a6a3bc44-e022-5967-a335-580b929238c3', 'c6afe901-7396-5b5f-890f-9619f76909e7', 'Parmi ces phrases, laquelle emploie correctement tous ses pronoms relatifs ?', '[{"id":"a","text":"La pièce que raconte cette histoire, dont je t''ai parlé, se joue à Tunis."},{"id":"b","text":"La pièce qui raconte cette histoire, dont je t''ai parlé, se joue à Tunis."},{"id":"c","text":"La pièce qui raconte cette histoire, que je t''ai parlé, se joue à Tunis."},{"id":"d","text":"La pièce dont raconte cette histoire, qui je t''ai parlé, se joue à Tunis."}]'::jsonb, 'b', '« la pièce raconte cette histoire » : la pièce est sujet → « qui ». « je t''ai parlé DE la pièce » : complément en « de » → « dont ». Seule la phrase b combine correctement « qui » (sujet) et « dont » (parler de).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
