INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e9bdf6fd-bcf2-51c9-9de2-937d16859418', 'd172de6f-71f3-5948-97c9-5ad63613c051', 'Combien d''éléments un comparatif met-il face à face ?', '[{"id":"a","text":"Un seul élément, sans comparaison"},{"id":"b","text":"Deux éléments"},{"id":"c","text":"Tout un groupe d''éléments"},{"id":"d","text":"Trois éléments au minimum"}]'::jsonb, 'b', 'Le comparatif mesure une même qualité chez DEUX éléments : « Skander est plus grand que Rayan. » Désigner le champion de tout un groupe, c''est le rôle du superlatif ; intensifier sans comparer, c''est le superlatif absolu.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('82ac7486-38f4-57e2-ae86-ea22474f2a58', 'd172de6f-71f3-5948-97c9-5ad63613c051', 'Quel outil exprime le comparatif d''égalité sur un adjectif ?', '[{"id":"a","text":"autant de … que"},{"id":"b","text":"aussi … que"},{"id":"c","text":"le plus … de"},{"id":"d","text":"moins … que"}]'::jsonb, 'b', 'Sur un adjectif ou un adverbe, l''égalité se dit « aussi … que » : « Nour est aussi souple que sa partenaire. » « autant de … que » sert pour un nom, « moins … que » marque l''infériorité, et « le plus … de » est un superlatif.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('64e23e34-99fc-55f6-a8cf-11946228a079', 'd172de6f-71f3-5948-97c9-5ad63613c051', 'À quoi reconnaît-on un superlatif relatif ?', '[{"id":"a","text":"À la présence d''un article défini (le, la, les) devant plus ou moins"},{"id":"b","text":"À la présence du mot « que »"},{"id":"c","text":"À l''adverbe « très » placé devant l''adjectif"},{"id":"d","text":"À l''absence de tout adjectif"}]'::jsonb, 'a', 'Le superlatif relatif se reconnaît à son article défini : « la plus applaudie », « le moins risqué ». Le mot « que » appartient au comparatif, et « très » forme le superlatif ABSOLU, sans article.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('80dee425-0956-5250-9ca3-a6857273337a', 'd172de6f-71f3-5948-97c9-5ad63613c051', 'Quel mot introduit le complément d''un superlatif (le groupe de référence) ?', '[{"id":"a","text":"que"},{"id":"b","text":"de"},{"id":"c","text":"aussi"},{"id":"d","text":"plus"}]'::jsonb, 'b', 'Le superlatif se complète avec « de » : « le meilleur DE la classe ». C''est le comparatif qui se complète avec « que » : « meilleur QUE son voisin ». Ne pas confondre ces deux mots est l''enjeu du chapitre.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fb43f438-c66a-5e32-adfb-37cc0540d203', 'd172de6f-71f3-5948-97c9-5ad63613c051', 'Quel est le comparatif de supériorité correct de l''adjectif « bon » ?', '[{"id":"a","text":"plus bon"},{"id":"b","text":"mieux"},{"id":"c","text":"meilleur"},{"id":"d","text":"plus mieux"}]'::jsonb, 'c', '« bon » a un comparatif irrégulier : « meilleur » (jamais « plus bon »). « mieux » est le comparatif de l''adverbe « bien », pas de l''adjectif « bon » ; « plus mieux » n''existe pas.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

