INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1f1e3982-f00b-57c9-a430-66b9055b51d8', '02befd3f-bf80-5183-a68d-334da81dd468', 'Complète le comparatif de supériorité : « Skander est ____ agile ____ son partenaire. »', '[{"id":"a","text":"plus … que"},{"id":"b","text":"aussi … que"},{"id":"c","text":"moins … que"},{"id":"d","text":"plus … de"}]'::jsonb, 'a', 'La supériorité se construit avec « plus … que » : « plus agile que son partenaire ». « aussi » marque l''égalité, « moins » l''infériorité, et le comparatif se complète avec « que », jamais « de ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('beb0969e-9241-5f80-bf18-7529878c28b5', '02befd3f-bf80-5183-a68d-334da81dd468', 'Quel outil exprime l''égalité sur l''adjectif « rapide » ? « Hédia est ____ rapide que son frère. »', '[{"id":"a","text":"autant"},{"id":"b","text":"aussi"},{"id":"c","text":"plus de"},{"id":"d","text":"le plus"}]'::jsonb, 'b', 'Sur un adjectif, l''égalité se dit « aussi … que » : « aussi rapide que son frère ». « autant » et « plus de » servent pour un nom ou un verbe, et « le plus » est un superlatif.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('58e382a5-a506-5589-b9da-b1305da74dc5', '02befd3f-bf80-5183-a68d-334da81dd468', 'Complète avec l''outil qui compare une QUANTITÉ (un nom) : « La troupe compte ____ danseurs que de musiciens. »', '[{"id":"a","text":"plus"},{"id":"b","text":"aussi"},{"id":"c","text":"plus de"},{"id":"d","text":"le plus de"}]'::jsonb, 'c', 'Pour comparer une quantité sur un nom, on ajoute « de » : « plus de danseurs que ». « plus » seul irait avec un verbe, « aussi » avec un adjectif, et « le plus de » serait un superlatif.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e6316bbf-4b61-5a56-8ed5-3c35ffa92cc5', '02befd3f-bf80-5183-a68d-334da81dd468', 'Quelle phrase contient un superlatif relatif ?', '[{"id":"a","text":"Amine chante plus fort que Wassim."},{"id":"b","text":"Amine est la plus belle voix de la chorale."},{"id":"c","text":"Amine chante très juste."},{"id":"d","text":"Amine est aussi doué que sa sœur."}]'::jsonb, 'b', '« la plus belle voix de la chorale » : article défini + plus + complément en « de » = superlatif relatif. Les phrases a et d sont des comparatifs (que), et c est un superlatif absolu (très).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cbba6b0f-9997-51e0-b466-6aaeaa02b7d5', '02befd3f-bf80-5183-a68d-334da81dd468', 'Quel est le comparatif de supériorité de l''adjectif « bon » ? « Ce numéro est ____ que le précédent. »', '[{"id":"a","text":"plus bon"},{"id":"b","text":"plus meilleur"},{"id":"c","text":"mieux"},{"id":"d","text":"meilleur"}]'::jsonb, 'd', '« bon » devient « meilleur » (jamais « plus bon »). « mieux » est le comparatif de « bien » (un adverbe), et « plus meilleur » est un doublon incorrect.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9878fcea-5fec-5533-8ab8-cb500ba6527e', '02befd3f-bf80-5183-a68d-334da81dd468', 'Quel mot forme un superlatif absolu (très haut degré, sans comparaison) ? « Le spectacle était ____ émouvant. »', '[{"id":"a","text":"plus"},{"id":"b","text":"moins"},{"id":"c","text":"très"},{"id":"d","text":"aussi"}]'::jsonb, 'c', '« très » exprime un très haut degré sans comparer : superlatif absolu. « plus », « moins » et « aussi » introduisent une comparaison avec un autre élément (comparatif).', 6)
ON CONFLICT (id) DO UPDATE SET
