INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8d913f7d-3701-572a-8e55-f28f315fdabe', '6fd408c3-2bef-55ee-ae4b-fc72dac6fa9f', 'Complète correctement : « À l''entraînement, Yasmine répète ____ son partenaire. » (comparatif de supériorité sur le VERBE)', '[{"id":"a","text":"plus de que"},{"id":"b","text":"le plus que"},{"id":"c","text":"aussi que"},{"id":"d","text":"plus que"}]'::jsonb, 'd', 'Comparer une action (un verbe), c''est « plus que » sans « de » : « répète plus que son partenaire ». « plus de » s''emploie avec un nom, « aussi » marque l''égalité, et « le plus » serait un superlatif.', 1)
