INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('58178638-39ed-5108-9515-341dfe6bf9e5', '6fd408c3-2bef-55ee-ae4b-fc72dac6fa9f', 'Quelle phrase est correcte ?', '[{"id":"a","text":"Rayan saute plus haut de tous les acrobates."},{"id":"b","text":"Rayan est le plus haut sauteur que la troupe."},{"id":"c","text":"Rayan saute plus haut que tous les acrobates."},{"id":"d","text":"Rayan saute aussi haut de son rival."}]'::jsonb, 'c', 'C''est un comparatif : il se complète avec « que » → « plus haut que tous les acrobates ». Les phrases a et d emploient « de » là où il faut « que » ; la phrase b mélange un superlatif avec « que » au lieu de « de ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c22eabb3-36cb-57aa-8996-d0995db5f664', '6fd408c3-2bef-55ee-ae4b-fc72dac6fa9f', 'Choisis la forme juste : « L''an dernier je dansais mal ; cette année, je danse ____. »', '[{"id":"a","text":"plus bien"},{"id":"b","text":"meilleur"},{"id":"c","text":"mieux"},{"id":"d","text":"plus mieux"}]'::jsonb, 'c', '« danser » est un verbe : on le modifie avec l''adverbe « mieux » (comparatif de « bien »). « plus bien » n''existe pas, « meilleur » qualifie un nom (adjectif), et « plus mieux » est un doublon incorrect.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('41718098-13a8-57f5-ac04-f20663640f18', '6fd408c3-2bef-55ee-ae4b-fc72dac6fa9f', 'Complète le superlatif relatif : « Nour a réalisé ____ figure ____ tout le gala. »', '[{"id":"a","text":"la plus belle … que"},{"id":"b","text":"la plus belle … de"},{"id":"c","text":"plus belle … de"},{"id":"d","text":"la meilleure … que"}]'::jsonb, 'b', 'Superlatif relatif : article + plus + adjectif, puis complément en « de » → « la plus belle figure de tout le gala ». L''option a met « que » (comparatif), l''option c oublie l''article obligatoire, et l''option d met « que » là où il faut « de ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('45ad83ae-de64-5a2b-bfbe-49c6219a7bd8', '6fd408c3-2bef-55ee-ae4b-fc72dac6fa9f', 'Une seule phrase emploie correctement « meilleur ». Laquelle ?', '[{"id":"a","text":"Skander joue meilleur que l''an dernier."},{"id":"b","text":"Skander a obtenu un meilleur classement que Rayan."},{"id":"c","text":"Skander travaille meilleur quand il est concentré."},{"id":"d","text":"Skander réussit meilleur ses saltos."}]'::jsonb, 'b', '« meilleur » est un adjectif : il qualifie un nom → « un meilleur classement ». Dans a, c et d il porte sur un verbe (joue, travaille, réussit) : il faudrait l''adverbe « mieux ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f6849672-7861-5b78-a272-1ba0fe24bbe8', '6fd408c3-2bef-55ee-ae4b-fc72dac6fa9f', 'Corrige la faute : « C''est la plus mauvaise soirée de la saison » peut aussi s''écrire :', '[{"id":"a","text":"C''est la pire soirée de la saison."},{"id":"b","text":"C''est la plus pire soirée de la saison."},{"id":"c","text":"C''est la pire soirée que la saison."},{"id":"d","text":"C''est la plus mal soirée de la saison."}]'::jsonb, 'a', '« mauvais » a un superlatif irrégulier : « la pire » (= la plus mauvaise). « la plus pire » est un doublon fautif, « que » remplace à tort le « de » du superlatif, et « mal » est un adverbe, il ne qualifie pas un nom.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

