INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c6c6391f-0c00-5f59-9e10-a788989d67af', 'cba9fd46-6f51-59fc-9533-77b38b7dd4fc', 'Complète le comparatif d''infériorité : « Le second numéro est ____ long ____ le premier. »', '[{"id":"a","text":"moins … que"},{"id":"b","text":"moins … de"},{"id":"c","text":"aussi … que"},{"id":"d","text":"le moins … de"}]'::jsonb, 'a', 'L''infériorité sur un adjectif se dit « moins … que » : « moins long que le premier ». Le comparatif se complète avec « que », pas « de » ; « aussi » marque l''égalité et « le moins » est un superlatif.', 1)
