INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bb5449fc-8785-5d51-9830-ca3dcf931720', 'cba9fd46-6f51-59fc-9533-77b38b7dd4fc', 'Quel outil compare une quantité (nom) à égalité ? « Nous avons ____ places ____ vous. »', '[{"id":"a","text":"aussi … que"},{"id":"b","text":"plus de … que"},{"id":"c","text":"autant … que"},{"id":"d","text":"autant de … que"}]'::jsonb, 'd', 'Sur un nom, l''égalité de quantité se dit « autant de … que » : « autant de places que vous ». « aussi » va avec un adjectif, « autant » seul avec un verbe, et « plus de » marque la supériorité, pas l''égalité.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('058c0066-bf57-547d-9d8e-162faa5fd456', 'cba9fd46-6f51-59fc-9533-77b38b7dd4fc', 'Quelle phrase est un superlatif absolu ?', '[{"id":"a","text":"Le clown est le plus drôle de la troupe."},{"id":"b","text":"Le clown est plus drôle que l''acrobate."},{"id":"c","text":"Le clown est extrêmement drôle."},{"id":"d","text":"Le clown est moins drôle que prévu."}]'::jsonb, 'c', '« extrêmement drôle » exprime un très haut degré sans comparer : superlatif absolu. La phrase a est un superlatif relatif (le plus … de), et b et d sont des comparatifs (que).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
