INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('82b629e9-506b-564c-b04f-74802e201626', 'cba9fd46-6f51-59fc-9533-77b38b7dd4fc', 'Complète avec la forme irrégulière : « Ce spectacle est ____ que celui de l''an dernier. » (bon, comparatif de supériorité)', '[{"id":"a","text":"plus bon"},{"id":"b","text":"meilleur"},{"id":"c","text":"mieux"},{"id":"d","text":"le meilleur"}]'::jsonb, 'b', '« bon » devient « meilleur » au comparatif. « plus bon » n''existe pas, « mieux » vient de l''adverbe « bien », et « le meilleur » est un superlatif (avec article), pas un comparatif.', 4)
