INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dae63c0d-b8d9-5c54-ae58-3532647e0769', 'cba9fd46-6f51-59fc-9533-77b38b7dd4fc', 'Accorde correctement : « Ce sont les ____ artistes du festival. » (bon, superlatif)', '[{"id":"a","text":"plus bons"},{"id":"b","text":"mieux"},{"id":"c","text":"meilleurs"},{"id":"d","text":"meilleur"}]'::jsonb, 'c', '« meilleur » s''accorde comme un adjectif : masculin pluriel → « les meilleurs artistes ». « plus bons » est fautif, « mieux » est un adverbe invariable, et « meilleur » (singulier) ne s''accorde pas avec « artistes » (pluriel).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
