  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('96986be3-e26e-5bb0-ad0d-8ba778c27eff', 'cba9fd46-6f51-59fc-9533-77b38b7dd4fc', 'Choisis « que » ou « de » : « Farès est le plus souple ____ toute l''équipe. »', '[{"id":"a","text":"que"},{"id":"b","text":"de"},{"id":"c","text":"aussi"},{"id":"d","text":"autant"}]'::jsonb, 'b', '« le plus souple » est un superlatif : son complément (le groupe de référence) s''introduit avec « de » → « de toute l''équipe ». « que » servirait à un comparatif (souple QUE son voisin).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
