  ('a70c2cbf-4b78-5d2d-bb05-1b8a67778f8f', 'cca389bf-1d34-5ccf-94cd-14e4e4a725f8', 'french-8eme', '👑 Défi élite ⭐⭐⭐⭐ : maître de la comparaison', 4, 300, 60, 'challenge', 'admin', 4)
