INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f0b331ba-9bd7-5af8-89ef-74b22a395a71', 'a70c2cbf-4b78-5d2d-bb05-1b8a67778f8f', 'Une seule phrase est entièrement correcte. Laquelle ?', '[{"id":"a","text":"Nour danse mieux que sa rivale, mais Hédia est la meilleure de toutes."},{"id":"b","text":"Nour danse meilleur que sa rivale, mais Hédia est la mieux de toutes."},{"id":"c","text":"Nour danse mieux de sa rivale, mais Hédia est la meilleure que toutes."},{"id":"d","text":"Nour danse plus bien que sa rivale, mais Hédia est la plus bonne de toutes."}]'::jsonb, 'a', '« danse » (verbe) → adverbe « mieux … que » ; « la meilleure de toutes » = superlatif adjectif accordé + complément en « de ». b intervertit meilleur/mieux, c met « de » au comparatif et « que » au superlatif, d emploie « plus bien » et « plus bonne » qui n''existent pas.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('371c53b9-3aa9-5180-b63b-7b0382810126', 'a70c2cbf-4b78-5d2d-bb05-1b8a67778f8f', 'Transforme au superlatif relatif de supériorité : « Ce numéro est risqué (du programme). »', '[{"id":"a","text":"Ce numéro est plus risqué du programme."},{"id":"b","text":"Ce numéro est le plus risqué du programme."},{"id":"c","text":"Ce numéro est le plus risqué que le programme."},{"id":"d","text":"Ce numéro est très risqué du programme."}]'::jsonb, 'b', 'Superlatif relatif = article + plus + adjectif + « de » → « le plus risqué du programme » (du = de + le). a oublie l''article obligatoire, c met « que » au lieu de « de », et d est un superlatif absolu qui ne peut pas recevoir de complément en « de ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4de7cd34-7e88-535c-b254-7551ba4d5c3e', 'a70c2cbf-4b78-5d2d-bb05-1b8a67778f8f', '« Il reste moins de trois minutes avant le lever de rideau. » Quel comparatif complète le mieux : « Il reste ____ temps ____ prévu. » ?', '[{"id":"a","text":"moins de … que"},{"id":"b","text":"moins … que"},{"id":"c","text":"aussi … que"},{"id":"d","text":"le moins … de"}]'::jsonb, 'a', '« temps » est un nom (quantité) : l''infériorité se dit « moins de … que » → « moins de temps que prévu ». « moins … que » irait avec un adjectif, « aussi » marque l''égalité, et « le moins … de » est un superlatif.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('03c081ac-9547-5e1c-b2d8-b4a4e76a5f15', 'a70c2cbf-4b78-5d2d-bb05-1b8a67778f8f', 'Quelle phrase emploie CORRECTEMENT l''irrégulier « pire » ?', '[{"id":"a","text":"Cette chute est pire de toutes les erreurs du soir."},{"id":"b","text":"Cette chute est la plus pire du spectacle."},{"id":"c","text":"Cette chute est pire que la précédente."},{"id":"d","text":"Cette chute est plus pire que la précédente."}]'::jsonb, 'c', '« pire » (comparatif de « mauvais ») se complète avec « que » : « pire que la précédente ». a met « de » à un comparatif, tandis que b et d ajoutent « plus » devant « pire », ce qui fait un doublon fautif.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e567436f-1e7d-5baa-a21a-52176e17cb70', 'a70c2cbf-4b78-5d2d-bb05-1b8a67778f8f', 'Repère la phrase où « aussi » / « autant » est mal employé.', '[{"id":"a","text":"Cet acrobate a autant de courage que son maître."},{"id":"b","text":"Cet acrobate s''entraîne autant que son maître."},{"id":"c","text":"Cet acrobate est aussi courageux que son maître."},{"id":"d","text":"Cet acrobate a aussi de courage que son maître."}]'::jsonb, 'd', 'Devant un nom (« courage »), l''égalité de quantité se dit « autant de », pas « aussi de » → il fallait « autant de courage ». Les trois autres sont justes : « autant de » + nom (a), « autant » + verbe (b), « aussi » + adjectif (c).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ab37b8f0-f660-5f1e-bd8c-b020c52f9ae9', 'a70c2cbf-4b78-5d2d-bb05-1b8a67778f8f', '« Plus l''artiste s''exerce, ____ il progresse. » Quel mot complète ce comparatif de proportion ?', '[{"id":"a","text":"plus"},{"id":"b","text":"aussi"},{"id":"c","text":"autant de"},{"id":"d","text":"le plus"}]'::jsonb, 'a', 'La tournure « Plus …, plus … » exprime une progression parallèle : « Plus l''artiste s''exerce, plus il progresse. » « aussi » marque l''égalité, « autant de » se met devant un nom, et « le plus » forme un superlatif, pas cette corrélation.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

