INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c5dbcf19-1fc9-502b-81b7-2fa6a4773168', '5468bf51-50f4-545d-bb84-ac2087fca5de', 'Complète le comparatif d''égalité sur le VERBE : « Ce jongleur amuse le public ____ le magicien. »', '[{"id":"a","text":"aussi que"},{"id":"b","text":"autant de que"},{"id":"c","text":"autant que"},{"id":"d","text":"aussi de que"}]'::jsonb, 'c', 'Sur un verbe (« amuse »), l''égalité se dit « autant que » : « amuse le public autant que le magicien ». « aussi » va avec un adjectif, et « autant de » / « aussi de » se placent devant un nom.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('37df2568-e3b9-559f-86e9-b8f0bfd730b9', '5468bf51-50f4-545d-bb84-ac2087fca5de', 'Quelle phrase distingue correctement comparatif et superlatif ?', '[{"id":"a","text":"Wassim est plus rapide de son frère et le plus rapide que l''équipe."},{"id":"b","text":"Wassim est plus rapide que son frère et le plus rapide de l''équipe."},{"id":"c","text":"Wassim est plus rapide que son frère et le plus rapide que l''équipe."},{"id":"d","text":"Wassim est plus rapide de son frère et le plus rapide de l''équipe."}]'::jsonb, 'b', 'Comparatif → « que » (plus rapide QUE son frère) ; superlatif → « de » (le plus rapide DE l''équipe). Chaque autre option se trompe au moins une fois de mot de liaison.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('97e764e3-268e-54a1-b020-673443d695ea', '5468bf51-50f4-545d-bb84-ac2087fca5de', 'Choisis entre « meilleur » et « mieux » : « Avec de l''entraînement, elle obtiendra de ____ résultats et jouera ____. »', '[{"id":"a","text":"mieux … meilleur"},{"id":"b","text":"mieux … mieux"},{"id":"c","text":"meilleurs … meilleur"},{"id":"d","text":"meilleurs … mieux"}]'::jsonb, 'd', '« résultats » est un nom → adjectif accordé « meilleurs » ; « jouera » est un verbe → adverbe « mieux ». On dit donc « de meilleurs résultats » et « jouera mieux ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9db48003-83db-56e5-bdec-a59c4c8c5f98', '5468bf51-50f4-545d-bb84-ac2087fca5de', 'Complète le superlatif : « De tous les costumes, celui-ci est ____ coloré ____ la garde-robe. »', '[{"id":"a","text":"plus … de"},{"id":"b","text":"le plus … que"},{"id":"c","text":"le plus … de"},{"id":"d","text":"très … de"}]'::jsonb, 'c', 'Superlatif relatif = article + plus + adjectif + « de » → « le plus coloré de la garde-robe ». a oublie l''article, b met « que » au lieu de « de », et « très » (superlatif absolu) n''accepte pas de complément en « de ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1e9aabbb-7173-5a7f-89a1-6c7d854064ec', '5468bf51-50f4-545d-bb84-ac2087fca5de', 'Repère la phrase FAUSSE.', '[{"id":"a","text":"Sa performance est meilleure que la mienne."},{"id":"b","text":"Il a eu une plus bonne note que moi."},{"id":"c","text":"Ce résultat est pire que le précédent."},{"id":"d","text":"Elle chante mieux que l''an dernier."}]'::jsonb, 'b', '« plus bonne » n''existe pas : le comparatif de « bon(ne) » est « meilleure » → « une meilleure note ». Les trois autres phrases emploient correctement meilleure (a), pire (c) et mieux (d).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('06c9bd8e-4210-5ed2-b40d-e13ed99275f1', '5468bf51-50f4-545d-bb84-ac2087fca5de', '« Chedy est le danseur le moins expérimenté ____ la troupe, mais il progresse ____ vite ____ les autres. » Complète.', '[{"id":"a","text":"de … plus … que"},{"id":"b","text":"que … plus … de"},{"id":"c","text":"de … plus … de"},{"id":"d","text":"que … plus … que"}]'::jsonb, 'a', '« le moins expérimenté » est un superlatif → complément en « de » (de la troupe) ; « plus vite que les autres » est un comparatif → « que ». Seule l''option a combine correctement « de » (superlatif) puis « que » (comparatif).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
