INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7491ec8f-04e4-5184-b585-da4bdfac7e5e', '018e414d-7952-578e-832c-6a2de7bfd0bb', 'Quelle phrase est irréprochable ?', '[{"id":"a","text":"Ce final est le plus grandiose de la soirée et bien meilleur que l''ouverture."},{"id":"b","text":"Ce final est le plus grandiose que la soirée et bien mieux que l''ouverture."},{"id":"c","text":"Ce final est plus grandiose de la soirée et bien meilleur de l''ouverture."},{"id":"d","text":"Ce final est le plus grandiose de la soirée et bien plus bon que l''ouverture."}]'::jsonb, 'a', '« le plus grandiose de la soirée » (superlatif + de) et « meilleur que l''ouverture » (comparatif de l''adjectif « bon » + que). b met « que » au superlatif et « mieux » (adverbe) là où il faut l''adjectif ; c oublie l''article et met « de » au comparatif ; d emploie « plus bon » qui n''existe pas.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
