INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5d564e99-fb92-542f-9712-3c168ef6ba6c', '018e414d-7952-578e-832c-6a2de7bfd0bb', '« Il y avait ____ spectateurs ce soir ____ à la première. » Complète l''infériorité de quantité.', '[{"id":"a","text":"moins … que"},{"id":"b","text":"moins de … que"},{"id":"c","text":"le moins de … que"},{"id":"d","text":"moins de … de"}]'::jsonb, 'b', '« spectateurs » est un nom : l''infériorité de quantité se dit « moins de … que » → « moins de spectateurs que ». « moins … que » irait avec un adjectif, « le moins de » serait un superlatif, et le comparatif se complète par « que », pas « de ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8f24366b-ddcd-5b95-ab3e-e8c8f737c792', '018e414d-7952-578e-832c-6a2de7bfd0bb', 'Réécris sans faute : « C''est le plus mauvais éclairage et la plus mauvaise sono. » Quelle version irrégulière est correcte ?', '[{"id":"a","text":"C''est le pire éclairage et la pire sono."},{"id":"b","text":"C''est le plus pire éclairage et la plus pire sono."},{"id":"c","text":"C''est le pire éclairage et la pire des sonos que le gala."},{"id":"d","text":"C''est le pire éclairage et le pire sono."}]'::jsonb, 'a', '« le plus mauvais » = « le pire » ; « la plus mauvaise » = « la pire » (pire s''accorde en genre par l''article). b ajoute « plus » (doublon fautif), c colle un « que » superflu, et d met « le pire » devant « sono » qui est féminin (« la pire sono »).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a6ff0141-89d4-58ca-875e-713c2050018a', '018e414d-7952-578e-832c-6a2de7bfd0bb', 'Une seule phrase respecte l''accord de l''irrégulier. Laquelle ?', '[{"id":"a","text":"Ce sont les meilleur numéros et les pire moments à la fois."},{"id":"b","text":"Ce sont les meilleurs numéros et les pires moments à la fois."},{"id":"c","text":"Ce sont les mieux numéros et les pires moments à la fois."},{"id":"d","text":"Ce sont les meilleurs numéros et les pire moments à la fois."}]'::jsonb, 'b', '« meilleur » et « pire » sont des adjectifs : au pluriel → « meilleurs » et « pires ». a et d oublient un accord, et c emploie « mieux » (adverbe invariable) qui ne peut pas qualifier le nom « numéros ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cca879c1-10d4-599d-a92f-d45abcf70dbc', '018e414d-7952-578e-832c-6a2de7bfd0bb', '« Ce chanteur a ____ de talent, mais il travaille ____ que les autres : voilà pourquoi il reste ____ de la troupe. » Choisis la série cohérente (supériorité, infériorité, superlatif d''infériorité).', '[{"id":"a","text":"plus … moins … le moins connu"},{"id":"b","text":"plus … moins de … moins connu"},{"id":"c","text":"plus de … moins de … le moins connu"},{"id":"d","text":"plus de … moins … le moins connu"}]'::jsonb, 'd', '« talent » est un nom → « plus de talent » ; « travaille » est un verbe → « moins que les autres » ; puis superlatif relatif « le moins connu (de la troupe) ». a oublie le « de » devant le nom, c ajoute un « de » en trop sur le verbe, et d oublie l''article du superlatif.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f09521a2-9c67-5e15-90f1-fbf028712aa9', '018e414d-7952-578e-832c-6a2de7bfd0bb', 'Distingue les deux superlatifs : quelle phrase contient un superlatif ABSOLU (et non relatif) ?', '[{"id":"a","text":"C''est la scène la plus vaste du théâtre."},{"id":"b","text":"C''est la scène la moins éclairée de la ville."},{"id":"c","text":"C''est une scène extrêmement vaste."},{"id":"d","text":"C''est la plus belle salle de la région."}]'::jsonb, 'c', '« extrêmement vaste » exprime un très haut degré sans comparer ni classer : superlatif absolu. Les phrases a, b et d sont des superlatifs relatifs (article + plus/moins + complément en « de »).', 6)
ON CONFLICT (id) DO UPDATE SET
