INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('44b9b975-bfe6-5668-9dfd-d424ea5ce8d9', '6927d0d5-88c1-55c8-95ba-b993bad266d9', 'À quelles questions répond un complément circonstanciel ?', '[{"id":"a","text":"quand ? où ? comment ? pourquoi ?"},{"id":"b","text":"qui ? quoi ?"},{"id":"c","text":"quel ? quelle ?"},{"id":"d","text":"à qui ? à quoi ?"}]'::jsonb, 'a', 'Le CC précise les circonstances de l''action : le temps (quand ?), le lieu (où ?), la manière (comment ?) et la cause (pourquoi ?). « Qui ? quoi ? » sert à trouver le sujet ou le COD ; « à qui ? à quoi ? » le COI.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1eb07e4a-8728-5fe1-af13-b5fed2b0d810', '6927d0d5-88c1-55c8-95ba-b993bad266d9', 'Dans « Les élèves se reposent sous les palmiers. », le groupe « sous les palmiers » est un CC de :', '[{"id":"a","text":"temps"},{"id":"b","text":"lieu"},{"id":"c","text":"manière"},{"id":"d","text":"cause"}]'::jsonb, 'b', '« Sous les palmiers » répond à la question où ? : c''est un CC de lieu. On peut le supprimer (Les élèves se reposent) et le déplacer (Sous les palmiers, les élèves se reposent).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('02ab198f-d272-5d7d-af85-a60e257af348', '6927d0d5-88c1-55c8-95ba-b993bad266d9', 'Quels sont les deux tests qui permettent de reconnaître un CC ?', '[{"id":"a","text":"l''accord et la conjugaison"},{"id":"b","text":"le genre et le nombre"},{"id":"c","text":"la suppression et le déplacement"},{"id":"d","text":"la majuscule et le point"}]'::jsonb, 'c', 'Un CC a deux pouvoirs que le COD et le COI n''ont pas : il est supprimable (on peut l''enlever) et déplaçable (on peut le bouger dans la phrase).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a0841b50-0a31-59ff-8f20-0676d06536ce', '6927d0d5-88c1-55c8-95ba-b993bad266d9', 'Dans « Youssef photographie l''oasis. », le groupe « l''oasis » est :', '[{"id":"a","text":"un CC de lieu"},{"id":"b","text":"un CC de manière"},{"id":"c","text":"un CC de temps"},{"id":"d","text":"un COD"}]'::jsonb, 'd', 'On ne peut ni supprimer ni déplacer « l''oasis » : ce n''est pas un CC. Photographie quoi ? l''oasis → c''est le COD. Le nom « oasis » désigne ici l''objet de l''action, pas le lieu.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9b3c6db3-23ae-5bc7-a032-e2f30eb6f9ef', '6927d0d5-88c1-55c8-95ba-b993bad266d9', 'Quelle phrase exprime une cause favorable ?', '[{"id":"a","text":"Grâce à son courage, Malek a réussi l''épreuve."},{"id":"b","text":"À cause du retard, ils ont raté le train."},{"id":"c","text":"À cause de la chaleur, la visite fut écourtée."},{"id":"d","text":"À cause du bruit, il n''a pas dormi."}]'::jsonb, 'a', '« Grâce à » annonce une cause favorable (qui aide) : grâce à son courage → il réussit. « À cause de » annonce une cause fâcheuse (retard, chaleur, bruit).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

