INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f361e433-c094-5b0a-b61c-3352a811af81', 'bc087065-53c2-5703-bb4f-22f629055fcb', 'Dans « Demain, la classe visitera l''amphithéâtre d''El Jem. », quel est le complément circonstanciel de temps ?', '[{"id":"a","text":"la classe"},{"id":"b","text":"Demain"},{"id":"c","text":"l''amphithéâtre d''El Jem"},{"id":"d","text":"visitera"}]'::jsonb, 'b', '« Demain » répond à la question quand ? : c''est le CC de temps. « L''amphithéâtre d''El Jem » répond à quoi ? (COD) et « la classe » est le sujet.', 1)
