INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c6949328-5beb-5530-aad4-3f2c0b7d18b9', 'bc087065-53c2-5703-bb4f-22f629055fcb', 'Dans « Les touristes se promènent dans la médina de Sousse. », le groupe « dans la médina de Sousse » est un CC de :', '[{"id":"a","text":"temps"},{"id":"b","text":"manière"},{"id":"c","text":"lieu"},{"id":"d","text":"cause"}]'::jsonb, 'c', '« Dans la médina de Sousse » répond à la question où ? : c''est un CC de lieu. On peut le déplacer : Dans la médina de Sousse, les touristes se promènent.', 2)
