INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8cdbb35e-4f0d-5581-9ddc-7c42edd38007', 'bc087065-53c2-5703-bb4f-22f629055fcb', 'Dans « Ines a répondu au guide calmement. », « calmement » est un CC de :', '[{"id":"a","text":"manière"},{"id":"b","text":"lieu"},{"id":"c","text":"temps"},{"id":"d","text":"cause"}]'::jsonb, 'a', '« Calmement » dit de quelle façon Ines a répondu (comment ?) : c''est un CC de manière. Beaucoup d''adverbes de manière se terminent par -ment.', 3)
