INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f6a69fdf-9363-5c10-9df3-849ea71067aa', 'bc087065-53c2-5703-bb4f-22f629055fcb', 'Dans « La visite a été écourtée à cause de la chaleur. », le CC « à cause de la chaleur » indique :', '[{"id":"a","text":"le lieu"},{"id":"b","text":"la cause"},{"id":"c","text":"le temps"},{"id":"d","text":"la manière"}]'::jsonb, 'b', '« À cause de la chaleur » répond à pourquoi ? : c''est un CC de cause. La chaleur est une cause fâcheuse, d''où l''emploi de « à cause de ».', 4)
