INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cf911096-4af3-5620-9ae7-3f3cf1b96fdb', 'bc087065-53c2-5703-bb4f-22f629055fcb', 'Quel groupe peut-on supprimer sans rendre la phrase incorrecte : « Rayan attend le car sur la place. » ?', '[{"id":"a","text":"le car"},{"id":"b","text":"Rayan"},{"id":"c","text":"attend"},{"id":"d","text":"sur la place"}]'::jsonb, 'd', '« Sur la place » est un CC de lieu, donc supprimable : Rayan attend le car. On ne peut enlever ni le sujet (Rayan), ni le verbe (attend), ni le COD (le car).', 5)
