INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9d81a52a-9fae-59ed-a017-3edb7f3be5a6', '1a318a62-a3b6-5e21-9883-0b96865c2292', 'Complète avec le bon connecteur : « La sortie a été reportée ___ la météo était mauvaise. »', '[{"id":"a","text":"ensuite"},{"id":"b","text":"d''abord"},{"id":"c","text":"pourtant"},{"id":"d","text":"parce que"}]'::jsonb, 'd', 'On exprime la cause du report : « parce que » introduit la raison. « Ensuite » et « d''abord » marquent le temps, « pourtant » l''opposition.', 4)
