INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2e1c75e4-4ac9-5027-beda-65004353d78e', '19ae25f0-6e2e-5cd4-a728-57c7c84e546f', 'Pour indiquer la succession des étapes d''un récit de voyage, quels connecteurs utilises-tu ?', '[{"id":"a","text":"à cause de… grâce à"},{"id":"b","text":"d''abord, ensuite, enfin"},{"id":"c","text":"parce que, car"},{"id":"d","text":"ici, là-bas"}]'::jsonb, 'b', '« D''abord, ensuite, enfin » sont des connecteurs de temps : ils organisent la chronologie du récit. « Parce que / car » marquent la cause, « ici / là-bas » le lieu.', 6)
