INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5b6c1fb9-696d-5581-8091-d63f68aa3d71', '445cd8dc-4ca2-5fc8-8367-871b2c9bfc53', 'Dans quelle phrase le groupe entre guillemets n''est-il PAS un complément circonstanciel ?', '[{"id":"a","text":"La caravane avance « dans le désert »."},{"id":"b","text":"Skander écrit « à sa correspondante »."},{"id":"c","text":"Le groupe est parti « à l''aube »."},{"id":"d","text":"Farah répond « avec assurance »."}]'::jsonb, 'b', 'Écrit à qui ? à sa correspondante : c''est un COI, ni supprimable ni déplaçable. Les autres sont des CC : lieu (dans le désert), temps (à l''aube), manière (avec assurance).', 1)
