INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d099e9ca-20fa-5b71-931e-0b20cd8ccdea', '445cd8dc-4ca2-5fc8-8367-871b2c9bfc53', 'Combien de compléments circonstanciels contient : « Le lendemain, à Kairouan, les élèves ont visité la Grande Mosquée avec émerveillement. » ?', '[{"id":"a","text":"un"},{"id":"b","text":"deux"},{"id":"c","text":"trois"},{"id":"d","text":"quatre"}]'::jsonb, 'c', 'Trois CC : « le lendemain » (temps), « à Kairouan » (lieu), « avec émerveillement » (manière). « La Grande Mosquée » n''est pas un CC : c''est le COD (ont visité quoi ?).', 2)
