INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4742459e-0139-5335-8ed3-3899302bbe9c', '445cd8dc-4ca2-5fc8-8367-871b2c9bfc53', 'Complète : « ___ un orage soudain, l''excursion au Chott el-Jérid a tourné court, mais ___ leur guide expérimenté, tous sont rentrés sains et saufs. »', '[{"id":"a","text":"Grâce à … à cause de"},{"id":"b","text":"À cause d'' … à cause de"},{"id":"c","text":"Grâce à … grâce à"},{"id":"d","text":"À cause d'' … grâce à"}]'::jsonb, 'd', 'L''orage est une cause fâcheuse (l''excursion tourne court) → « à cause d'' » ; le guide est une cause favorable (tous rentrent saufs) → « grâce à ».', 3)
