INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f7e7aa5c-c8f0-5d8c-9ea9-29c2e9257dcb', '445cd8dc-4ca2-5fc8-8367-871b2c9bfc53', 'Quelle transformation déplace correctement le CC de temps en tête de phrase, sans faute : « Les nomades plient la tente au lever du jour. » ?', '[{"id":"a","text":"Au lever du jour, les nomades plient la tente."},{"id":"b","text":"Les nomades au lever du jour plient la tente."},{"id":"c","text":"Plient la tente les nomades au lever du jour."},{"id":"d","text":"Au lever du jour les nomades, plient la tente."}]'::jsonb, 'a', 'Le CC « au lever du jour » se déplace en tête, suivi d''une virgule : Au lever du jour, les nomades plient la tente. La phrase b coupe le sujet et le verbe sans virgules, la d place mal la virgule, la c bouleverse l''ordre sujet-verbe.', 4)
