INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('10f0419d-ae26-5541-b316-4dc21d3b896b', '445cd8dc-4ca2-5fc8-8367-871b2c9bfc53', 'Dans « Nour a réussi l''ascension grâce à sa persévérance. », le groupe « grâce à sa persévérance » exprime :', '[{"id":"a","text":"la manière"},{"id":"b","text":"le temps"},{"id":"c","text":"la cause"},{"id":"d","text":"le lieu"}]'::jsonb, 'c', '« Grâce à » introduit une cause favorable : Nour réussit pourquoi ? grâce à sa persévérance. C''est un CC de cause, à ne pas confondre avec la manière (comment ?).', 5)
