INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('40f868ca-4ebb-5e13-bb8b-786b8aa91a59', '4f7b8860-6ca2-5015-a81c-244bf22a877c', 'Parmi ces mots, lequel décrit le caractère (le moral) d''une personne ?', '[{"id":"a","text":"élancé"},{"id":"b","text":"bronzé"},{"id":"c","text":"trapu"},{"id":"d","text":"généreux"}]'::jsonb, 'd', '« généreux » désigne une qualité du caractère : cela relève du portrait moral. « élancé », « bronzé » et « trapu » décrivent le corps ou le teint : c''est du physique.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cc76bef3-17f8-54b6-a31b-8058bcb2ca7f', '4f7b8860-6ca2-5015-a81c-244bf22a877c', 'Pour composer un portrait clair, dans quel ordre progresse-t-on le plus souvent ?', '[{"id":"a","text":"en sautant d''un détail à l''autre, au hasard"},{"id":"b","text":"du général au particulier (l''allure, puis le visage, puis les détails)"},{"id":"c","text":"en commençant toujours par les chaussures"},{"id":"d","text":"en ne parlant que des vêtements"}]'::jsonb, 'b', 'Un portrait ordonné va du général (la taille, l''allure) au particulier (le visage, puis les petits détails). On choisit un fil et on le tient, sinon la description devient confuse.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e31aaf8b-96c4-5541-97db-14261bdb7607', '4f7b8860-6ca2-5015-a81c-244bf22a877c', 'Dans « Nabil est habile comme un singe », quel est l''outil de comparaison ?', '[{"id":"a","text":"est"},{"id":"b","text":"habile"},{"id":"c","text":"comme"},{"id":"d","text":"singe"}]'::jsonb, 'c', '« comme » est l''outil qui rapproche Nabil du singe pour dire son adresse. « est » est un verbe d''état, « habile » l''adjectif et « singe » l''image à laquelle on le compare.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e2558c61-10ae-5e94-b32b-7506f036272e', '4f7b8860-6ca2-5015-a81c-244bf22a877c', 'Dans le GN « un marchand qui souriait sans cesse », l''expansion « qui souriait sans cesse » est…', '[{"id":"a","text":"un adjectif épithète"},{"id":"b","text":"un complément du nom"},{"id":"c","text":"une subordonnée relative"},{"id":"d","text":"un verbe d''état"}]'::jsonb, 'c', '« qui » suivi d''un verbe conjugué (souriait) introduit une subordonnée relative qui caractérise le nom « marchand ». L''épithète serait un adjectif (un marchand souriant), le complément du nom une préposition + nom (un marchand de tissus).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('d6a548ca-8d73-5894-9f34-86ed05b9a61c', '4f43f04d-65cb-5d2b-8b5e-09965da3af19', 'french-8eme', '⭐ Exercice : Le pinceau du portraitiste — physique ou moral ?', 1, 50, 10, 'practice', 'admin', 1)
