INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b47e9e7a-6d85-5c58-aacb-1776a258d69f', 'd6a548ca-8d73-5894-9f34-86ed05b9a61c', 'Dans « Slim a une silhouette élancée », le mot « élancée » appartient au portrait…', '[{"id":"a","text":"physique"},{"id":"b","text":"moral"},{"id":"c","text":"de cause"},{"id":"d","text":"de lieu"}]'::jsonb, 'a', '« élancée » décrit la silhouette, le corps : on le voit avec les yeux, donc c''est du portrait physique. Le portrait moral concernerait le caractère (par exemple « patient »).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d7746afb-8dfa-58a4-8035-f3917d9a18eb', 'd6a548ca-8d73-5894-9f34-86ed05b9a61c', 'Quel mot décrit une qualité du caractère (portrait moral) ?', '[{"id":"a","text":"corpulent"},{"id":"b","text":"pâle"},{"id":"c","text":"courageux"},{"id":"d","text":"grand"}]'::jsonb, 'c', '« courageux » désigne une qualité morale : cela ne se voit pas, cela se devine par les actes. « corpulent », « pâle » et « grand » décrivent le corps ou le teint : c''est du physique.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0aad43d8-9cf9-5f19-89fe-362bffbdf62b', 'd6a548ca-8d73-5894-9f34-86ed05b9a61c', 'Pour décrire le teint du visage de Mariem, quel mot conviendrait ?', '[{"id":"a","text":"hâlé"},{"id":"b","text":"généreux"},{"id":"c","text":"honnête"},{"id":"d","text":"paresseux"}]'::jsonb, 'a', '« hâlé » (bruni par le soleil) décrit le teint, c''est-à-dire la couleur de la peau : un mot du physique. Les trois autres (généreux, honnête, paresseux) décrivent le caractère.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4b351abd-7c26-582e-9597-097abbd59321', 'd6a548ca-8d73-5894-9f34-86ed05b9a61c', 'Dans le GN « un vieux pêcheur souriant », le mot « souriant » est…', '[{"id":"a","text":"un adjectif épithète"},{"id":"b","text":"un complément du nom"},{"id":"c","text":"une subordonnée relative"},{"id":"d","text":"un outil de comparaison"}]'::jsonb, 'a', '« souriant » est un adjectif placé dans le groupe nominal, à côté du nom « pêcheur » : c''est un adjectif épithète. Il n''y a ni préposition + nom (complément du nom), ni « qui » + verbe (relative).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6118c787-d21e-5f86-a14a-ae987516c8f2', 'd6a548ca-8d73-5894-9f34-86ed05b9a61c', 'Quel mot, dans la liste, est un outil de comparaison ?', '[{"id":"a","text":"et"},{"id":"b","text":"mais"},{"id":"c","text":"donc"},{"id":"d","text":"comme"}]'::jsonb, 'd', '« comme » sert à comparer : « fort comme un lion ». « et » additionne, « mais » oppose, « donc » exprime une conséquence : aucun de ces trois ne compare.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a4f72265-d011-5eb5-998d-dd0bb281ab57', 'd6a548ca-8d73-5894-9f34-86ed05b9a61c', 'Dans un portrait ordonné « du général au particulier », par quoi commence-t-on ?', '[{"id":"a","text":"par un petit détail des chaussures"},{"id":"b","text":"par l''aspect général : la taille, l''allure"},{"id":"c","text":"par la couleur des yeux"},{"id":"d","text":"par la forme des ongles"}]'::jsonb, 'b', '« Du général au particulier » signifie qu''on part de la vue d''ensemble (taille, allure, corpulence) avant d''aller vers les détails précis (les yeux, un objet, une habitude). On finit par le détail, on ne commence pas par lui.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

