INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f312998f-4422-5ab7-a791-dedb8c977fa0', '7037cafd-9b97-531b-baac-6af0d1174bb7', 'Trie ces quatre mots. Lequel N''appartient PAS au même plan que les trois autres : « trapu, généreux, élancé, corpulent » ?', '[{"id":"a","text":"trapu"},{"id":"b","text":"corpulent"},{"id":"c","text":"élancé"},{"id":"d","text":"généreux"}]'::jsonb, 'd', '« trapu », « élancé » et « corpulent » décrivent la silhouette (physique). « généreux » décrit le caractère (moral) : c''est l''intrus.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('08da5590-a799-512c-a5fd-236e4e289c0e', '7037cafd-9b97-531b-baac-6af0d1174bb7', 'Dans « Le forgeron, tel un ours, soulevait l''enclume », l''expression « tel un ours »…', '[{"id":"a","text":"est une comparaison qui souligne sa force"},{"id":"b","text":"est un complément du nom qui indique son métier"},{"id":"c","text":"est une simple addition d''idées"},{"id":"d","text":"exprime la cause de son action"}]'::jsonb, 'a', '« tel » est un outil de comparaison (comme « comme », « pareil à ») : il rapproche le forgeron d''un ours pour dire sa force. Ce n''est ni une addition, ni une cause, ni un complément du nom.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b5edc023-c214-5450-853c-af8eaf241df6', '7037cafd-9b97-531b-baac-6af0d1174bb7', 'On veut caractériser « un veilleur » par une SUBORDONNÉE RELATIVE. Quelle expansion convient ?', '[{"id":"a","text":"un veilleur silencieux"},{"id":"b","text":"un veilleur de nuit"},{"id":"c","text":"un veilleur qui ne fermait jamais l''œil"},{"id":"d","text":"un veilleur, tel une statue"}]'::jsonb, 'c', 'La subordonnée relative commence par un pronom relatif (qui, que, où, dont) suivi d''un verbe conjugué : « qui ne fermait jamais l''œil ». « silencieux » est un adjectif épithète, « de nuit » un complément du nom, « tel une statue » une comparaison.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a63d23cd-aea8-5af7-9dfa-d46d1869275e', '7037cafd-9b97-531b-baac-6af0d1174bb7', 'Dans « Fatma paraissait timide, mais son sourire franc rassurait », quel élément est un adjectif ATTRIBUT ?', '[{"id":"a","text":"« franc », relié à « sourire »"},{"id":"b","text":"« rassurait », le verbe principal"},{"id":"c","text":"« son », devant « sourire »"},{"id":"d","text":"« timide », relié à « Fatma » par « paraissait »"}]'::jsonb, 'd', '« paraissait » est un verbe d''état qui relie l''adjectif « timide » au sujet « Fatma » : « timide » est donc attribut. « franc » est épithète (collé au nom « sourire » dans le GN), « son » est un déterminant, « rassurait » un verbe d''action.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c0e38ba8-acbe-5a69-b5d0-356bc8aa5dc1', '7037cafd-9b97-531b-baac-6af0d1174bb7', 'Un élève écrit : « Le vieux Ammar était généreux. » Comment TRANSFORMER cette affirmation pour MONTRER la générosité par une action ?', '[{"id":"a","text":"Le vieux Ammar était vraiment très généreux."},{"id":"b","text":"Le vieux Ammar avait une nature généreuse et bonne."},{"id":"c","text":"Chaque soir, le vieux Ammar partageait son pain avec les enfants du quartier."},{"id":"d","text":"On disait partout que le vieux Ammar était généreux."}]'::jsonb, 'c', 'Pour montrer le moral, on remplace le mot par un geste concret : « partageait son pain » prouve la générosité sans la nommer. Les autres phrases répètent ou renforcent l''adjectif « généreux » sans le montrer en acte.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c1fb55dc-1cf5-527e-901d-79165977430f', '7037cafd-9b97-531b-baac-6af0d1174bb7', 'Dans « un capitaine à la barbe grise qui parlait peu », combien d''expansions différentes caractérisent « capitaine », et lesquelles ?', '[{"id":"a","text":"deux : un complément du nom (à la barbe grise) et une relative (qui parlait peu)"},{"id":"b","text":"deux : deux adjectifs épithètes"},{"id":"c","text":"une seule : une longue subordonnée relative"},{"id":"d","text":"trois : un adjectif, un complément du nom et une comparaison"}]'::jsonb, 'a', '« à la barbe grise » = préposition (à) + nom : c''est un complément du nom. « qui parlait peu » = pronom relatif « qui » + verbe : c''est une subordonnée relative. Deux expansions de natures différentes enrichissent le même nom.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

