  ('8131fcf5-5e03-5fee-8e98-e586f0be9c9e', '4f43f04d-65cb-5d2b-8b5e-09965da3af19', 'french-8eme', '⭐⭐ Exercice de révision : composer et caractériser', 2, 70, 15, 'practice', 'admin', 3)
