INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3ab9bb3f-fc2f-5583-9637-f704f53bae1a', '8131fcf5-5e03-5fee-8e98-e586f0be9c9e', 'Dans « Le libraire semblait rêveur », comment le mot « rêveur » caractérise-t-il le libraire ?', '[{"id":"a","text":"c''est un adjectif épithète dans le groupe nominal"},{"id":"b","text":"c''est un outil de comparaison"},{"id":"c","text":"c''est un complément du nom"},{"id":"d","text":"c''est un adjectif attribut, relié au nom par le verbe d''état « semblait »"}]'::jsonb, 'd', '« semblait » est un verbe d''état (comme être, paraître, devenir) : il relie l''adjectif « rêveur » au nom « libraire ». L''adjectif est donc attribut, pas épithète (il n''est pas collé au nom dans un GN).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('996efb56-3136-557a-85e3-fe15b9c1c104', '8131fcf5-5e03-5fee-8e98-e586f0be9c9e', 'Quelle phrase MONTRE la générosité de Warda plutôt que de la nommer ?', '[{"id":"a","text":"Warda était une femme généreuse."},{"id":"b","text":"Warda avait un caractère généreux."},{"id":"c","text":"Warda offrait chaque jour une fleur à l''enfant qui passait."},{"id":"d","text":"Warda, c''est la générosité même."}]'::jsonb, 'c', 'Décrire le moral, c''est souvent le montrer par une action : « offrait une fleur » prouve la générosité par un geste concret. Les autres phrases se contentent de dire le mot « généreux » sans le prouver.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b29ed5dd-85b6-5bc0-a725-aa0a722db0da', '8131fcf5-5e03-5fee-8e98-e586f0be9c9e', 'Dans « un homme au regard perçant », l''expansion « au regard perçant » est…', '[{"id":"a","text":"un complément du nom"},{"id":"b","text":"un adjectif épithète"},{"id":"c","text":"une subordonnée relative"},{"id":"d","text":"un verbe d''état"}]'::jsonb, 'a', '« au regard perçant » = « à + le regard perçant » : une préposition (à) suivie d''un nom (regard) placée après le nom « homme ». C''est un complément du nom. Une relative aurait « qui » + verbe.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e9f8f9e9-2041-5078-89b2-e1d90ce2e4c2', '8131fcf5-5e03-5fee-8e98-e586f0be9c9e', 'Un élève range son portrait dans l''ordre « du général au particulier ». Quel classement respecte cet ordre ?', '[{"id":"a","text":"une petite cicatrice au menton → le visage → la taille"},{"id":"b","text":"une haute taille robuste → un visage large → une cicatrice au menton"},{"id":"c","text":"les yeux → la taille → le teint"},{"id":"d","text":"une cicatrice au menton → les chaussures → l''allure générale"}]'::jsonb, 'b', 'On part de la vue d''ensemble (la taille robuste), puis on resserre sur le visage, puis sur le petit détail (la cicatrice). Les autres listes commencent par un détail ou passent en désordre.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ceb818be-6176-5e78-8bfa-5a41021da583', '8131fcf5-5e03-5fee-8e98-e586f0be9c9e', 'Complète pour obtenir une comparaison : « Ses cheveux étaient noirs ___ le jais. »', '[{"id":"a","text":"et"},{"id":"b","text":"car"},{"id":"c","text":"mais"},{"id":"d","text":"comme"}]'::jsonb, 'd', 'Pour comparer les cheveux au jais (une pierre très noire), il faut un outil de comparaison : « comme ». « et » additionnerait, « car » donnerait une cause, « mais » opposerait : aucun ne compare.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bf4147be-b8c8-5ff5-a142-6e7473601689', '8131fcf5-5e03-5fee-8e98-e586f0be9c9e', 'Dans « une marchande avare, qui comptait ses pièces, au regard méfiant », combien de caractéristiques relèvent du portrait MORAL ?', '[{"id":"a","text":"une seule (« avare »)"},{"id":"b","text":"aucune, tout est physique"},{"id":"c","text":"deux (« avare » et « qui comptait ses pièces »)"},{"id":"d","text":"les trois expansions"}]'::jsonb, 'c', '« avare » nomme un défaut (moral) et « qui comptait ses pièces » le montre par un geste (moral aussi). « au regard méfiant » décrit ce qu''on voit, donc plutôt le physique — même si le regard trahit le caractère, l''élément décrit ici est le regard.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('008f1a56-130c-5230-ad8f-6fbcf13d6e2f', '4f43f04d-65cb-5d2b-8b5e-09965da3af19', 'french-8eme', '👑 Défi ⭐⭐⭐⭐ : le portrait révélateur', 4, 300, 60, 'boss', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('74d696c9-351a-5c1d-b52f-71869ac7afce', '008f1a56-130c-5230-ad8f-6fbcf13d6e2f', '« Le vieux Béchir, tel un roc, ne bronchait devant aucune tempête. » Que révèle cette comparaison sur son caractère ?', '[{"id":"a","text":"sa solidité, sa fermeté morale"},{"id":"b","text":"seulement sa grande taille physique"},{"id":"c","text":"sa couleur de peau"},{"id":"d","text":"l''endroit où il habite"}]'::jsonb, 'a', 'Comparer un homme à un roc (« tel un roc ») qui « ne bronchait devant aucune tempête » suggère une qualité morale : la solidité, la fermeté. La comparaison sert ici à peindre le caractère, pas seulement le corps.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('93968b0e-41bd-57a2-a8e2-3ca474ab5ddb', '008f1a56-130c-5230-ad8f-6fbcf13d6e2f', 'Dans « une gouvernante au visage fermé, que personne n''osait déranger », les deux expansions de « gouvernante » sont, dans l''ordre…', '[{"id":"a","text":"un adjectif épithète, puis un complément du nom"},{"id":"b","text":"une comparaison, puis un adjectif attribut"},{"id":"c","text":"deux subordonnées relatives"},{"id":"d","text":"un complément du nom, puis une subordonnée relative"}]'::jsonb, 'd', '« au visage fermé » = à + le visage fermé : préposition + nom = complément du nom. « que personne n''osait déranger » commence par le pronom relatif « que » + verbe : subordonnée relative. Dans cet ordre exactement.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('05035389-d6e9-5bf2-a836-d57d1927f6f1', '008f1a56-130c-5230-ad8f-6fbcf13d6e2f', '« Il avait des mains fines de pianiste, mais un regard qui glaçait le sang. » Comment ce portrait joue-t-il physique et moral ?', '[{"id":"a","text":"il est entièrement physique"},{"id":"b","text":"il ne contient aucune expansion du nom"},{"id":"c","text":"il est entièrement moral"},{"id":"d","text":"il oppose un détail physique délicat (mains fines) à une impression morale inquiétante suggérée par le regard"}]'::jsonb, 'd', '« des mains fines de pianiste » est un détail physique délicat ; « un regard qui glaçait le sang » part du physique (le regard) pour suggérer une menace morale. Le contraste (« mais ») rend le personnage troublant : c''est un portrait révélateur.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5103cef4-1808-5836-a9b2-e3a8a4dc2ef4', '008f1a56-130c-5230-ad8f-6fbcf13d6e2f', 'Un auteur veut caractériser « le juge » d''une seule expansion qui SUGGÈRE l''impartialité par une image. Laquelle choisir ?', '[{"id":"a","text":"le juge, aux cheveux blancs"},{"id":"b","text":"le juge sévère"},{"id":"c","text":"le juge, droit comme la balance qu''il tenait"},{"id":"d","text":"le juge qui portait une longue robe"}]'::jsonb, 'c', '« droit comme la balance qu''il tenait » est une comparaison qui, par l''image de la balance (symbole de justice), suggère l''impartialité : c''est de la caractérisation morale imagée. Les autres expansions décrivent le physique (cheveux, robe) ou nomment platement un trait (sévère).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b75c64fa-3e73-586a-811c-f119821dc465', '008f1a56-130c-5230-ad8f-6fbcf13d6e2f', 'Parmi ces quatre versions du même portrait, laquelle respecte le mieux l''ordre « du général au particulier, puis passage au moral » ?', '[{"id":"a","text":"Un grain de beauté sur la joue. Il était grand. Il était bon."},{"id":"b","text":"C''était un homme de haute taille ; son visage large s''ouvrait sur un sourire, et ce sourire disait toute sa bonté."},{"id":"c","text":"Il était bon. Il souriait. Il était grand. Sa joue avait un grain de beauté."},{"id":"d","text":"Sa bonté d''abord ; puis son sourire ; enfin, tout au bout, sa haute taille."}]'::jsonb, 'b', 'La version b part du général (haute taille), resserre sur le visage (large, le sourire), puis glisse vers le moral (« toute sa bonté ») que le sourire laisse deviner : ordre net et progressif. Les autres commencent par un détail ou par le moral, en désordre.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('80eeb4a0-801b-5c4d-bdb7-b2ab43477c99', '008f1a56-130c-5230-ad8f-6fbcf13d6e2f', '« Sa voix douce cachait une volonté de fer. » Quel outil de caractérisation porte l''idée morale de fermeté ?', '[{"id":"a","text":"l''adjectif « douce », attribut de « voix »"},{"id":"b","text":"le complément du nom « de fer », qui caractérise « volonté » par une image"},{"id":"c","text":"le verbe « cachait », qui est un verbe d''état"},{"id":"d","text":"une subordonnée relative introduite par « qui »"}]'::jsonb, 'b', '« de fer » est un complément du nom (de + fer) qui caractérise « volonté » : l''image du fer suggère la dureté, la fermeté morale. « douce » est bien un adjectif mais épithète (dans le GN « sa voix douce »), « cachait » est un verbe d''action, et il n''y a pas de relative ici.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('8a0de02e-2533-5926-8b25-5f28e6890fa8', '4f43f04d-65cb-5d2b-8b5e-09965da3af19', 'french-8eme', '⭐⭐⭐ Entraînement : l''atelier de la caractérisation', 3, 120, 30, 'practice', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
