INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('45e5530d-b888-5c5c-8d6f-7ffad0126af6', '8a0de02e-2533-5926-8b25-5f28e6890fa8', 'Quel groupe de mots mélange le physique et le moral (au lieu d''un seul plan) ?', '[{"id":"a","text":"mince, svelte, frêle"},{"id":"b","text":"avare, menteur, lâche"},{"id":"c","text":"pâle, blafard, hâlé"},{"id":"d","text":"trapu, honnête, bronzé"}]'::jsonb, 'd', 'Dans « trapu, honnête, bronzé », « trapu » et « bronzé » sont physiques mais « honnête » est moral : le plan est mélangé. Les trois autres listes restent sur un seul plan (silhouette, caractère, teint).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('19f9d126-adb5-5593-84de-c5cb70f0679d', '8a0de02e-2533-5926-8b25-5f28e6890fa8', 'Dans « Karim marchait d''une démarche pesante », le mot « pesante » caractérise…', '[{"id":"a","text":"un défaut moral de Karim"},{"id":"b","text":"l''humeur de Karim"},{"id":"c","text":"la cause de sa marche"},{"id":"d","text":"la manière de se déplacer (physique)"}]'::jsonb, 'd', '« pesante » décrit la démarche, c''est-à-dire la façon dont le corps se déplace : cela se voit, donc c''est du physique. Ce n''est pas un jugement sur le caractère.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('36de04f4-d881-5180-838b-5f97f1cfa3e7', '8a0de02e-2533-5926-8b25-5f28e6890fa8', 'On veut caractériser « une danseuse » par un COMPLÉMENT DU NOM. Quelle proposition convient ?', '[{"id":"a","text":"une danseuse gracieuse"},{"id":"b","text":"une danseuse aux gestes légers"},{"id":"c","text":"une danseuse qui tournoyait"},{"id":"d","text":"une danseuse, semblable à une flamme"}]'::jsonb, 'b', 'Le complément du nom est une préposition + un nom : « aux gestes légers » (à + les gestes). « gracieuse » est un adjectif épithète, « qui tournoyait » une relative, « semblable à une flamme » une comparaison.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9c696b30-be7a-5d2b-bb2f-6c73fe3d33ce', '8a0de02e-2533-5926-8b25-5f28e6890fa8', 'Dans « son visage devint sévère quand il vit le désordre », quel est le rôle de « devint » ?', '[{"id":"a","text":"c''est un verbe d''action ordinaire"},{"id":"b","text":"c''est un déterminant du nom « visage »"},{"id":"c","text":"c''est un outil de comparaison"},{"id":"d","text":"c''est un verbe d''état qui introduit l''attribut « sévère »"}]'::jsonb, 'd', '« devenir » fait partie des verbes d''état (être, sembler, paraître, devenir, rester) : il relie l''adjectif attribut « sévère » au nom « visage ». Il ne raconte pas une action comme « courir » ou « voir ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aef440f3-41dc-5a11-9a24-bb145ee03280', '8a0de02e-2533-5926-8b25-5f28e6890fa8', 'Quelle phrase contient une VRAIE comparaison (et pas seulement une addition de qualités) ?', '[{"id":"a","text":"Il était grand et fort."},{"id":"b","text":"Il était patient mais ferme."},{"id":"c","text":"Il était souple comme un roseau."},{"id":"d","text":"Il était honnête, donc respecté."}]'::jsonb, 'c', '« souple comme un roseau » compare l''homme à un roseau grâce à l''outil « comme ». « et », « mais », « donc » relient des idées (addition, opposition, conséquence) mais ne comparent rien.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0fb95f74-45f5-52a3-8a91-c67a74808369', '8a0de02e-2533-5926-8b25-5f28e6890fa8', 'Un élève rédige : « Ses yeux verts. Il était rusé. Un nez fin. Il trompait tout le monde. » Quel reproche d''organisation peut-on lui faire ?', '[{"id":"a","text":"il n''y a aucun détail physique"},{"id":"b","text":"il alterne sans ordre le physique (yeux, nez) et le moral (rusé, trompait), au lieu de regrouper chaque plan"},{"id":"c","text":"il n''y a aucun élément moral"},{"id":"d","text":"toutes les caractéristiques sont morales"}]'::jsonb, 'b', 'Le passage saute du physique (yeux, nez) au moral (rusé, trompait) puis revient : le portrait est décousu. Il faudrait regrouper le physique, puis passer au moral, pour un portrait clair et progressif.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b0abb37d-a98b-50cc-b7e3-02adfd7ca330', '4f43f04d-65cb-5d2b-8b5e-09965da3af19', 'french-8eme', '👑 Défi élite ⭐⭐⭐⭐ : le portraitiste virtuose', 4, 300, 60, 'boss', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
