INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b4c802cd-7226-5e65-bf78-e3494d5532ef', 'b0abb37d-a98b-50cc-b7e3-02adfd7ca330', 'Dans « le contrebandier, au sourire aimable mais aux yeux fuyants », qu''est-ce que le narrateur laisse deviner ?', '[{"id":"a","text":"une contradiction : l''amabilité affichée cache une nature peu franche"},{"id":"b","text":"qu''il est simplement malade"},{"id":"c","text":"uniquement la couleur de ses yeux"},{"id":"d","text":"qu''il est très grand"}]'::jsonb, 'a', '« un sourire aimable » (apparence avenante) opposé à « des yeux fuyants » (le regard fuyant trahit le malaise ou la malhonnêteté) crée une contradiction : sous l''amabilité perce une nature peu franche. Le physique décrit sert à suggérer le moral.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3767ce5b-9fb9-5b50-a712-b2b3fd75c219', 'b0abb37d-a98b-50cc-b7e3-02adfd7ca330', 'Classe ces trois expansions de « l''aïeule » selon leur nature : « courbée » / « aux mains ridées » / « qui racontait les vieilles histoires ».', '[{"id":"a","text":"adjectif épithète / complément du nom / subordonnée relative"},{"id":"b","text":"complément du nom / adjectif épithète / comparaison"},{"id":"c","text":"subordonnée relative / complément du nom / adjectif épithète"},{"id":"d","text":"comparaison / adjectif attribut / complément du nom"}]'::jsonb, 'a', '« courbée » = adjectif épithète ; « aux mains ridées » = à + les mains = complément du nom ; « qui racontait les vieilles histoires » = pronom relatif « qui » + verbe = subordonnée relative. Trois outils différents pour un même nom.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('730eb50e-c941-5616-9cd6-fb0bf1918fcd', 'b0abb37d-a98b-50cc-b7e3-02adfd7ca330', 'Pour peindre l''avarice d''un personnage SANS employer le mot « avare », quelle phrase est la plus efficace ?', '[{"id":"a","text":"Il était connu pour son avarice légendaire."},{"id":"b","text":"Il comptait ses sous trois fois avant de rendre la monnaie, et fermait la lumière dès qu''on quittait la pièce."},{"id":"c","text":"C''était un homme très, très économe et avare."},{"id":"d","text":"Tout le monde le trouvait avare et pingre."}]'::jsonb, 'b', 'Montrer le moral par des actions précises (« comptait ses sous trois fois », « fermait la lumière ») fait sentir l''avarice sans la nommer : c''est l''art du portrait révélateur. Les autres phrases répètent l''adjectif « avare » au lieu de le montrer.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2ed43995-cf9b-5952-8be3-d1ed2abbadca', 'b0abb37d-a98b-50cc-b7e3-02adfd7ca330', '« Rigide comme un piquet, l''inspecteur restait droit ; jamais un pli de son uniforme ne se froissait. » Que traduit surtout ce portrait ?', '[{"id":"a","text":"seulement des détails physiques sans signification"},{"id":"b","text":"par la comparaison et le détail de l''uniforme, une rigueur, une discipline morale"},{"id":"c","text":"la gentillesse et la douceur du personnage"},{"id":"d","text":"l''endroit exact où il travaillait"}]'::jsonb, 'b', '« Rigide comme un piquet » (comparaison), « restait droit » (verbe d''état + attribut) et « jamais un pli… ne se froissait » sont des détails physiques choisis pour suggérer une qualité morale : la rigueur, la discipline. Le physique est mis au service du moral.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a3806bf5-b3a5-5a02-939b-82dd86ddd8ef', 'b0abb37d-a98b-50cc-b7e3-02adfd7ca330', 'Dans « ses joues creuses, que la maladie avait pâlies, semblaient de cire », combien d''outils de caractérisation différents repère-t-on ?', '[{"id":"a","text":"un seul : un adjectif"},{"id":"b","text":"aucun, il n''y a qu''un nom"},{"id":"c","text":"trois : un adjectif épithète (creuses), une subordonnée relative (que la maladie avait pâlies) et une comparaison via un attribut (semblaient de cire)"},{"id":"d","text":"deux compléments du nom"}]'::jsonb, 'c', '« creuses » = adjectif épithète ; « que la maladie avait pâlies » = subordonnée relative (pronom « que » + verbe) ; « semblaient de cire » = verbe d''état « semblaient » introduisant une image comparative (attribut). Trois outils s''additionnent pour un portrait riche.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ad7ed986-ed95-53f3-be8d-921f9d7f5153', 'b0abb37d-a98b-50cc-b7e3-02adfd7ca330', 'Un jury de rédaction doit choisir le meilleur portrait « du général au particulier avec passage au moral ». Lequel récompenser ?', '[{"id":"a","text":"« Menteur. De grands pieds. Un front. Il trichait toujours. »"},{"id":"b","text":"« De taille moyenne, le marchand avait un visage rond aux petits yeux mobiles ; ces yeux, sans cesse en mouvement, disaient assez sa méfiance. »"},{"id":"c","text":"« Sa méfiance d''abord. Puis un œil. Puis, tout à la fin, sa taille moyenne. »"},{"id":"d","text":"« Il avait un œil. Il était moyen. Il se méfiait. Il avait un visage. »"}]'::jsonb, 'b', 'La version b va du général (taille moyenne) au particulier (visage rond, petits yeux mobiles), puis glisse vers le moral (« disaient assez sa méfiance ») que le détail des yeux laisse deviner : ordre clair, physique au service du moral. Les autres sont en désordre ou commencent par le moral.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

