INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('010a76ca-a24a-5ecc-9d02-2aa0dca11987', '9d172b83-4767-50dd-a6ed-a1fb50b781d5', 'À quoi servent les deux-points ( : ) placés juste avant une parole rapportée, comme dans « Il dit : … » ?', '[{"id":"a","text":"à poser une question"},{"id":"b","text":"à annoncer les paroles qu''un personnage va prononcer"},{"id":"c","text":"à fermer le dialogue"},{"id":"d","text":"à séparer deux adjectifs"}]'::jsonb, 'b', 'Les deux-points annoncent la parole : ils préviennent le lecteur qu''un personnage va parler. Ce sont ensuite les guillemets qui encadrent les paroles.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c9ba3c76-85b8-5332-9493-905005ff46c1', '9d172b83-4767-50dd-a6ed-a1fb50b781d5', 'Quel signe encadre (ouvre et ferme) les paroles rapportées au discours direct ?', '[{"id":"a","text":"les parenthèses ( )"},{"id":"b","text":"les crochets [ ]"},{"id":"c","text":"les guillemets « »"},{"id":"d","text":"les tirets seuls — —"}]'::jsonb, 'c', 'Les guillemets « » ouvrent et ferment le passage prononcé. Les parenthèses et les crochets ne s''emploient pas pour le dialogue ; le tiret, lui, marque seulement le changement d''interlocuteur.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a0f98e36-a04f-5e43-bcf6-c1947489417f', '9d172b83-4767-50dd-a6ed-a1fb50b781d5', 'Dans un dialogue, à quoi sert le tiret ( — ) placé au début d''une nouvelle ligne ?', '[{"id":"a","text":"à indiquer qu''un autre personnage prend la parole"},{"id":"b","text":"à souligner un mot important"},{"id":"c","text":"à marquer une soustraction"},{"id":"d","text":"à couper un mot en fin de ligne"}]'::jsonb, 'a', 'Le tiret signale le changement d''interlocuteur : chaque fois qu''un autre personnage parle, on va à la ligne et on commence par un tiret.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4b5597a3-b57c-5a41-94bd-e00ad2d965d0', '9d172b83-4767-50dd-a6ed-a1fb50b781d5', 'Complète avec le verbe introducteur qui convient au ton : « Où as-tu trouvé ce livre ? ___ Sofien. »', '[{"id":"a","text":"ordonna"},{"id":"b","text":"s''écria"},{"id":"c","text":"murmura"},{"id":"d","text":"demanda"}]'::jsonb, 'd', 'La réplique est une question (« Où… ? ») : le verbe introducteur juste est « demanda ». « ordonna » convient à un ordre, « s''écria » à un cri, et « murmura » à une voix basse.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('21001c43-ff00-5c71-bcf3-af5f1d131c90', '9d172b83-4767-50dd-a6ed-a1fb50b781d5', 'Dans la phrase « J''ai réussi ! s''exclama Rania. », quelle est la proposition incise ?', '[{"id":"a","text":"J''ai réussi"},{"id":"b","text":"Rania"},{"id":"c","text":"s''exclama Rania"},{"id":"d","text":"J''ai"}]'::jsonb, 'c', 'L''incise est le groupe « s''exclama Rania » : un verbe de parole (s''exclama) avec son sujet inversé (Rania), inséré dans la parole du personnage.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
