INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bf4a47fa-0f3c-51e9-96ef-e1de5906ad55', '327c0983-30fe-5763-a93e-d1b5821354f5', 'Le maître ouvrit la porte et dit ___ « Entrez, les enfants. » Quel signe faut-il dans le blanc, juste avant les paroles ?', '[{"id":"a","text":"une virgule ( , )"},{"id":"b","text":"deux-points ( : )"},{"id":"c","text":"un point-virgule ( ; )"},{"id":"d","text":"un tiret ( — )"}]'::jsonb, 'b', 'Les deux-points annoncent les paroles qui vont être prononcées. On écrit : « Le maître dit : « Entrez, les enfants. » »', 1)
