INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cd2887d8-4804-5448-ac23-a8770fd40271', '327c0983-30fe-5763-a93e-d1b5821354f5', 'Quel signe faut-il pour OUVRIR les paroles rapportées au discours direct ?', '[{"id":"a","text":"«"},{"id":"b","text":"("},{"id":"c","text":"["},{"id":"d","text":"/"}]'::jsonb, 'a', 'Le guillemet ouvrant « ouvre la parole ; le guillemet fermant » la referme. Les parenthèses, crochets et barres ne s''emploient pas pour le dialogue.', 2)
