INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ad969859-8c10-5354-b8b6-fcdc0a0cc70c', '327c0983-30fe-5763-a93e-d1b5821354f5', 'Dans « — Attends-moi ! cria Yassine. », quel mot est le verbe introducteur (verbe de parole) ?', '[{"id":"a","text":"Attends"},{"id":"b","text":"moi"},{"id":"c","text":"cria"},{"id":"d","text":"Yassine"}]'::jsonb, 'c', '« cria » est le verbe qui présente la parole (verbe introducteur). « Attends » est la parole du personnage, et « Yassine » est le sujet de « cria ».', 3)
