INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f7b41840-9ac1-5d4f-9762-2dc02f47b4d0', '327c0983-30fe-5763-a93e-d1b5821354f5', 'Dans un dialogue écrit, le tiret placé au début d''une ligne sert à :', '[{"id":"a","text":"montrer qu''un AUTRE personnage prend la parole"},{"id":"b","text":"additionner deux nombres"},{"id":"c","text":"terminer le récit"},{"id":"d","text":"séparer les syllabes d''un mot"}]'::jsonb, 'a', 'Le tiret marque le changement d''interlocuteur : on va à la ligne et on met un tiret dès qu''un autre personnage parle.', 4)
