INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('712de511-21d3-5bfb-a123-f78620064b96', '327c0983-30fe-5763-a93e-d1b5821354f5', 'Complète avec le verbe introducteur qui convient au ton : « Sortez immédiatement ! ___ le directeur. »', '[{"id":"a","text":"chuchota"},{"id":"b","text":"demanda"},{"id":"c","text":"ordonna"},{"id":"d","text":"bredouilla"}]'::jsonb, 'c', '« Sortez immédiatement ! » est un ordre lancé fort : le verbe juste est « ordonna ». « chuchota » et « bredouilla » sont des voix faibles, « demanda » annonce une question.', 5)
