INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3769b29d-250d-5748-ae2c-78cda7feea46', '327c0983-30fe-5763-a93e-d1b5821354f5', 'Complète correctement les paroles : « La vieille dame sourit et dit : ___ »', '[{"id":"a","text":"« bonjour, mon enfant. »"},{"id":"b","text":"« Bonjour, mon enfant. »"},{"id":"c","text":"bonjour, mon enfant."},{"id":"d","text":"(Bonjour, mon enfant.)"}]'::jsonb, 'b', 'Après les deux-points, on ouvre les guillemets et la parole commence par une MAJUSCULE, puis on referme les guillemets : « Bonjour, mon enfant. » La minuscule (a), l''absence de guillemets (c) et les parenthèses (d) sont fausses.', 6)
