INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5956e0ee-610e-5c36-89c2-e9d59a9dc9d4', '40c3a93d-4093-5abf-b747-cbebe1a34af3', 'Dans « Je crois, murmura Amina, que nous sommes perdus. », quelle est la proposition incise ?', '[{"id":"a","text":"Je crois"},{"id":"b","text":"que nous sommes perdus"},{"id":"c","text":"murmura Amina"},{"id":"d","text":"nous sommes perdus"}]'::jsonb, 'c', 'L''incise « murmura Amina » (verbe de parole + sujet inversé) est insérée au milieu de la parole d''Amina et encadrée de deux virgules.', 1)
