INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ce008d3c-1aad-57a1-ba10-e2d22f556075', '40c3a93d-4093-5abf-b747-cbebe1a34af3', 'Quelle incise est correctement écrite (avec l''inversion du sujet) ?', '[{"id":"a","text":"dit il"},{"id":"b","text":"il dit"},{"id":"c","text":"il-dit"},{"id":"d","text":"dit-il"}]'::jsonb, 'd', 'Dans l''incise, le sujet passe après le verbe et se relie par un tiret : « dit-il ». « il dit » n''a pas d''inversion ; « dit il » et « il-dit » sont mal orthographiés.', 2)
