INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4253ce77-e17c-5379-821b-1b136d161286', '40c3a93d-4093-5abf-b747-cbebe1a34af3', 'Complète l''incise avec la bonne liaison : « Où vas-tu ? demanda___elle. »', '[{"id":"a","text":"demanda-elle"},{"id":"b","text":"demanda-t-elle"},{"id":"c","text":"demandat-elle"},{"id":"d","text":"demanda t''elle"}]'::jsonb, 'b', 'Le verbe « demanda » se termine par une voyelle et le sujet est « elle » : on ajoute un « -t- » de liaison entre deux tirets → « demanda-t-elle ».', 3)
