INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3d62d58d-e46d-5dfd-93ba-daf4f072ee5f', '40c3a93d-4093-5abf-b747-cbebe1a34af3', 'Quelle phrase est correctement ponctuée ?', '[{"id":"a","text":"« Tu viens avec nous ? demanda Karim. »"},{"id":"b","text":"« Tu viens avec nous, demanda Karim ? »"},{"id":"c","text":"« Tu viens avec nous. demanda Karim ? »"},{"id":"d","text":"« Tu viens avec nous demanda Karim ? »"}]'::jsonb, 'a', 'La réplique est une question : le point d''interrogation reste collé à la parole (« Tu viens avec nous ? »), puis vient l''incise, puis le point final. Dans les autres, le « ? » est mal placé ou manque une ponctuation.', 4)
