INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ed639028-0de5-51c2-bea7-62ccd7398764', '40c3a93d-4093-5abf-b747-cbebe1a34af3', 'Un premier personnage vient de parler. Pour la réponse d''un DEUXIÈME personnage, quelle ligne est correctement présentée ? « Tu as fini tes devoirs ? demanda la mère. ___ »', '[{"id":"a","text":"Oui, maman, répondit Slim."},{"id":"b","text":": Oui, maman, répondit Slim."},{"id":"c","text":"(Oui, maman) répondit Slim."},{"id":"d","text":"— Oui, maman, répondit Slim."}]'::jsonb, 'd', 'Changement d''interlocuteur : on va à la ligne et on commence par un tiret. Il manque le tiret en (a) ; les deux-points (b) et les parenthèses (c) ne conviennent pas ici.', 5)
