INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a872039b-1b17-58df-be05-555bee0e9cae', '9260f432-da23-521d-b92d-0c296d653660', 'Complète avec le verbe qui convient au ton : « Nous avons gagné ! ___ toute l''équipe. »', '[{"id":"a","text":"chuchota"},{"id":"b","text":"s''écria"},{"id":"c","text":"soupira"},{"id":"d","text":"bredouilla"}]'::jsonb, 'b', '« Nous avons gagné ! » exprime la joie et se dit fort : « s''écria » convient. « chuchota » et « bredouilla » sont des voix faibles, « soupira » marque la fatigue ou la tristesse.', 4)
