INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b5292724-f197-5a0d-8ab7-26b152c35b94', '9260f432-da23-521d-b92d-0c296d653660', 'Dans « — C''est magnifique, souffla Maryam en regardant la mer. », quelle est l''incise ?', '[{"id":"a","text":"C''est magnifique"},{"id":"b","text":"en regardant la mer"},{"id":"c","text":"la mer"},{"id":"d","text":"souffla Maryam"}]'::jsonb, 'd', 'L''incise est « souffla Maryam » : verbe de parole + sujet inversé. « C''est magnifique » est la parole ; « en regardant la mer » est un complément qui précise l''action.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
