  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4443ccf0-0a6f-55b4-9fee-80ed5fd46952', '9260f432-da23-521d-b92d-0c296d653660', 'Quelle phrase respecte la ponctuation du discours direct ?', '[{"id":"a","text":"L''enfant demanda : « Où est mon chat ? »"},{"id":"b","text":"L''enfant demanda « où est mon chat ? »"},{"id":"c","text":"L''enfant demanda, où est mon chat ?"},{"id":"d","text":"L''enfant demanda : où est mon chat."}]'::jsonb, 'a', 'Il faut les deux-points, les guillemets, une majuscule au début de la parole et le point d''interrogation conservé : « Où est mon chat ? ». Les autres oublient les deux-points, les guillemets ou la majuscule.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
