INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6fe96928-0eb3-5937-aa96-5bd7a9251361', 'aca30542-6a99-5d95-8aee-4b041794b91e', 'Quelle phrase est correctement ponctuée au discours direct ?', '[{"id":"a","text":"La guide dit : « Suivez-moi ! »"},{"id":"b","text":"La guide dit « Suivez-moi ! »."},{"id":"c","text":"La guide dit : Suivez-moi !"},{"id":"d","text":"La guide dit ; « Suivez-moi ! »"}]'::jsonb, 'a', 'Deux-points pour annoncer, guillemets pour encadrer, majuscule et point d''exclamation à l''intérieur : « Suivez-moi ! ». En (b) le point final est en trop, (c) oublie les guillemets, (d) met un point-virgule à la place des deux-points.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8ac0c753-0ff4-5830-abb0-d166efa5e89e', 'aca30542-6a99-5d95-8aee-4b041794b91e', 'Repère l''erreur : « — Bonjour, dit le marchand. — Bonjour à toi. répondit l''enfant. »', '[{"id":"a","text":"il manque les deux-points"},{"id":"b","text":"après « toi », il faut une virgule (et non un point) avant l''incise « répondit »"},{"id":"c","text":"le tiret est en trop"},{"id":"d","text":"« Bonjour » ne prend pas de majuscule"}]'::jsonb, 'b', 'Quand une réplique déclarative est suivie d''une incise, on met une virgule (pas un point) : « Bonjour à toi, répondit l''enfant. » Le tiret et les majuscules sont corrects.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2d44bda9-a6c3-5da5-9abf-b7df18013c9f', 'aca30542-6a99-5d95-8aee-4b041794b91e', 'Quel dialogue est entièrement bien présenté ?', '[{"id":"a","text":"La mère demanda : As-tu faim ? - Un peu avoua Sami."},{"id":"b","text":"La mère demanda « as-tu faim ? — un peu, avoua Sami »"},{"id":"c","text":"La mère demanda : « As-tu faim ? / — Un peu, avoua Sami. »"},{"id":"d","text":"La mère demanda : « as-tu faim ? » — « un peu », avoua Sami."}]'::jsonb, 'c', 'En (c) tout est correct : deux-points, guillemets ouvrants, majuscule, « ? » conservé, tiret pour le changement d''interlocuteur, virgule avant l''incise, guillemets fermants à la fin. Les autres oublient les deux-points, les guillemets, les majuscules ou la virgule.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0f99fd08-73e3-5be7-9dc5-c02c3bd16cfc', 'aca30542-6a99-5d95-8aee-4b041794b91e', 'Choisis l''incise correcte : « Quel beau jardin ! ___ »', '[{"id":"a","text":"s''exclama-t-il le visiteur"},{"id":"b","text":"le visiteur s''exclama"},{"id":"c","text":"s''exclama-t-le visiteur"},{"id":"d","text":"s''exclama le visiteur"}]'::jsonb, 'd', 'L''incise demande l''inversion (verbe + sujet), et avec un NOM sujet on n''ajoute jamais de « -t- » ni de tiret : « s''exclama le visiteur ». « le visiteur s''exclama » n''est pas une incise (pas d''inversion) ; (a) et (c) ajoutent un « -t- » réservé au pronom il/elle/on.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0d80cf64-e081-57c1-830f-f30276cb4705', 'aca30542-6a99-5d95-8aee-4b041794b91e', 'Dans le récit « Le train ralentit. Amina se leva. », quelle insertion de la parole d''Amina est correcte ?', '[{"id":"a","text":"Amina se leva : « Nous arrivons », dit-elle avec joie."},{"id":"b","text":"Amina se leva « nous arrivons » dit elle avec joie"},{"id":"c","text":"Amina se leva, nous arrivons dit elle."},{"id":"d","text":"Amina se leva. — Nous arrivons dit elle avec joie"}]'::jsonb, 'a', 'La parole est annoncée (deux-points), encadrée (guillemets, majuscule) et suivie d''une incise correcte : « Nous arrivons », dit-elle. Les autres oublient les guillemets, les deux-points, l''inversion ou la ponctuation de l''incise.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e7d9c99b-7453-5381-8e9d-9ac014126b55', 'aca30542-6a99-5d95-8aee-4b041794b91e', 'Choisis le verbe introducteur qui colle au ton : « — Je… je n''ai pas fait mes devoirs, ___ Karim, les yeux baissés. »', '[{"id":"a","text":"claironna"},{"id":"b","text":"hurla"},{"id":"c","text":"balbutia"},{"id":"d","text":"proclama"}]'::jsonb, 'c', 'L''hésitation (« Je… je ») et la gêne (« les yeux baissés ») appellent « balbutia » (parler avec difficulté). « claironna », « hurla » et « proclama » sont des voix fortes et assurées, contraires au ton.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

