INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f9bf1fff-c9e2-50d0-a042-1ad2fa9e43e2', 'ba95fbaa-090a-5d38-9e80-1a10af6c1708', 'En typographie française, quel signe encadre une parole rapportée au discours direct ?', '[{"id":"a","text":"les guillemets « »"},{"id":"b","text":"les parenthèses ( )"},{"id":"c","text":"les crochets [ ]"},{"id":"d","text":"les barres / /"}]'::jsonb, 'a', 'Les guillemets français « » encadrent la parole. Les parenthèses, crochets et barres ne s''emploient pas pour le discours direct.', 1)
