INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bd534ce9-a696-5acd-a453-dc57fd4a032f', 'ba95fbaa-090a-5d38-9e80-1a10af6c1708', 'Lequel de ces verbes n''est PAS un verbe introducteur de parole ?', '[{"id":"a","text":"répliqua"},{"id":"b","text":"s''écria"},{"id":"c","text":"grimpa"},{"id":"d","text":"ajouta"}]'::jsonb, 'c', '« grimpa » est un verbe d''action (il ne présente pas des paroles). « répliqua », « s''écria » et « ajouta » sont bien des verbes introducteurs de parole.', 2)
