INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('740277af-34c3-5705-8edd-cd4d239f9778', 'ba95fbaa-090a-5d38-9e80-1a10af6c1708', 'Complète : « Le capitaine se retourna et lança ___ « En avant ! »', '[{"id":"a","text":", (virgule)"},{"id":"b","text":": (deux-points)"},{"id":"c","text":"; (point-virgule)"},{"id":"d","text":"— (tiret)"}]'::jsonb, 'b', 'Avant une parole rapportée, on met les deux-points pour l''annoncer : « lança : « En avant ! » ». La virgule, le point-virgule et le tiret ne conviennent pas ici.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
