INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b1da7f1f-c63b-52ba-8f63-d2c751a4b75a', 'ba95fbaa-090a-5d38-9e80-1a10af6c1708', 'Quelle phrase, avec une incise au milieu de la parole, est correctement ponctuée ?', '[{"id":"a","text":"« Ce soir dit-il nous partirons. »"},{"id":"b","text":"« Ce soir, dit-il nous partirons. »"},{"id":"c","text":"« Ce soir dit-il, nous partirons. »"},{"id":"d","text":"« Ce soir, dit-il, nous partirons. »"}]'::jsonb, 'd', 'Quand l''incise est insérée au milieu de la parole, elle est encadrée de DEUX virgules : « Ce soir, dit-il, nous partirons. » Les autres oublient une des deux virgules.', 4)
