INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('71680812-b73f-5048-99cf-2ce6111d4f5b', 'ba95fbaa-090a-5d38-9e80-1a10af6c1708', 'Un personnage a déjà parlé, puis il continue : « Et n''oublie pas ton manteau », ___ sa mère. Quel verbe montre qu''elle CONTINUE de parler ?', '[{"id":"a","text":"demanda"},{"id":"b","text":"ajouta"},{"id":"c","text":"interrogea"},{"id":"d","text":"se tut"}]'::jsonb, 'b', '« ajouta » indique que la mère continue, qu''elle dit quelque chose en plus. « demanda » et « interrogea » annoncent une question ; « se tut » signifie le contraire : elle arrête de parler.', 5)
