  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d8398011-856b-5bca-8f4c-84a8d97b082c', 'ba95fbaa-090a-5d38-9e80-1a10af6c1708', 'Dans le récit « La nuit tombait sur le port. », quelle insertion de dialogue est cohérente et bien ponctuée ?', '[{"id":"a","text":"Rentrons il se fait tard déclara le pêcheur."},{"id":"b","text":"« rentrons il se fait tard » : déclara le pêcheur"},{"id":"c","text":"« Rentrons, il se fait tard », déclara le pêcheur en rangeant ses filets."},{"id":"d","text":"— rentrons, il se fait tard déclara le pêcheur —"}]'::jsonb, 'c', 'La parole est encadrée de guillemets, commence par une majuscule, et l''incise « déclara le pêcheur » est séparée par une virgule. Les autres oublient les guillemets, la majuscule ou la ponctuation de l''incise.', 6)
ON CONFLICT (id) DO UPDATE SET
