INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f4c115ad-9fc3-534f-8244-baab62941d1b', '17efbcfb-ea60-5cfc-98b2-6c039176f55f', 'Laquelle de ces incises est correcte ?', '[{"id":"a","text":"« Viens », dit-elle-t."},{"id":"b","text":"« Viens », dit Yassine."},{"id":"c","text":"« Viens », Yassine dit."},{"id":"d","text":"« Viens », dit-Yassine."}]'::jsonb, 'b', 'Avec un NOM sujet, l''incise s''écrit verbe + nom, sans tiret ni « -t- » : « dit Yassine ». « Yassine dit » n''a pas d''inversion ; (a) et (d) ajoutent des tirets/‑t‑ réservés au pronom (dit-elle).', 1)
