INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('92addc51-ef78-5f44-ac21-734e77d47b8e', '17efbcfb-ea60-5cfc-98b2-6c039176f55f', 'Quelle phrase est parfaitement ponctuée ?', '[{"id":"a","text":"« Crois-tu demanda-t-il que nous réussirons ? »"},{"id":"b","text":"« Crois-tu, demanda-t-il que nous réussirons ? »"},{"id":"c","text":"« Crois-tu ? demanda-t-il, que nous réussirons. »"},{"id":"d","text":"« Crois-tu, demanda-t-il, que nous réussirons ? »"}]'::jsonb, 'd', 'La parole est « Crois-tu que nous réussirons ? » ; l''incise « demanda-t-il » y est insérée et encadrée de deux virgules, le « ? » restant à la fin de la question. Les autres oublient une virgule ou déplacent mal le point d''interrogation.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
