INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3db2962d-a032-5cf9-b7f5-82ab9cd6e479', '17efbcfb-ea60-5cfc-98b2-6c039176f55f', 'Dans ce dialogue à deux voix, quelle présentation est entièrement correcte ?', '[{"id":"a","text":"La marchande sourit combien en veux-tu trois s''il vous plaît répondit Ines les voici dit la marchande"},{"id":"b","text":"— Combien en veux-tu — Trois s''il vous plaît — Les voici"},{"id":"c","text":"La marchande sourit : « Combien en veux-tu ? / — Trois, s''il vous plaît, répondit Ines. / — Les voici, dit la marchande. »"},{"id":"d","text":"La marchande sourit : « Combien en veux-tu ? » « Trois » : « Les voici »"}]'::jsonb, 'c', 'En (c) : deux-points, guillemets ouvrants, majuscule et « ? » à la première réplique, puis un tiret à chaque changement d''interlocuteur, des incises correctes et les guillemets fermants à la fin. Les autres oublient guillemets, virgules d''incise ou empilent des guillemets à chaque réplique.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
