INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('00dd84df-0fce-5d75-b00a-afee51644a69', '17efbcfb-ea60-5cfc-98b2-6c039176f55f', 'Le narrateur a déjà écrit « dit » puis « répondit ». Pour une 3ᵉ réplique qui est un ordre sec — « — Silence ! ___ le surveillant. » — quel verbe est le plus juste ?', '[{"id":"a","text":"proposa"},{"id":"b","text":"suggéra"},{"id":"c","text":"ordonna"},{"id":"d","text":"demanda"}]'::jsonb, 'c', '« Silence ! » est un ordre : « ordonna » convient et varie du « dit » déjà employé. « proposa » et « suggéra » sont des propositions douces ; « demanda » annonce une question.', 4)
