INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3ec50e26-a577-5f41-a0a7-9f5fccf3c359', '17efbcfb-ea60-5cfc-98b2-6c039176f55f', 'Une seule de ces phrases est correcte. Laquelle ?', '[{"id":"a","text":"Il murmura : « je crois que oui. »"},{"id":"b","text":"Il murmura : « Je crois que oui. »"},{"id":"c","text":"Il murmura, « Je crois que oui. »"},{"id":"d","text":"Il murmura : Je crois que oui."}]'::jsonb, 'b', 'Il faut les deux-points, les guillemets et une MAJUSCULE au début de la parole : « Je crois que oui. » (a) met une minuscule, (c) une virgule au lieu des deux-points, (d) oublie les guillemets.', 5)
