INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b7596304-910c-56db-a537-9b7a48ba876c', '17efbcfb-ea60-5cfc-98b2-6c039176f55f', 'Dans un récit au passé, on veut rapporter les paroles EXACTES du personnage (discours direct). Quelle insertion est correcte ?', '[{"id":"a","text":"Le vieil homme s''assit et soupira : « Comme le temps a passé ! »"},{"id":"b","text":"Le vieil homme s''assit et soupira que le temps avait passé."},{"id":"c","text":"Le vieil homme s''assit et soupira : comme le temps a passé."},{"id":"d","text":"Le vieil homme s''assit et soupira — comme le temps a passé —"}]'::jsonb, 'a', 'Le discours direct annonce (deux-points), encadre (guillemets, majuscule) et garde les paroles exactes : « Comme le temps a passé ! » L''option (b) transforme les paroles (discours indirect, réservé à la 9ème) ; (c) et (d) oublient les guillemets.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
