INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1cd884bd-e3d5-5706-9e8d-68cc9539326c', '39e02166-7c43-5184-9e11-79fd1944f501', 'À quoi sert un substitut dans un texte ?', '[{"id":"a","text":"À ajouter une nouvelle idée sans rapport avec la précédente."},{"id":"b","text":"À reprendre un élément déjà cité pour éviter les répétitions."},{"id":"c","text":"À poser une question au lecteur."},{"id":"d","text":"À conjuguer le verbe de la phrase."}]'::jsonb, 'b', 'Le substitut reprend un mot déjà cité (le référent) sous un autre visage, ce qui rend le texte fluide et évite de répéter sans cesse le même mot.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e524a9fe-7869-5f26-8cf8-3bb5eddd6f7e', '39e02166-7c43-5184-9e11-79fd1944f501', 'Dans « Nour a terminé son article. Elle le relit à voix haute. », à quoi renvoie le pronom « Elle » ?', '[{"id":"a","text":"à l''article"},{"id":"b","text":"à la voix"},{"id":"c","text":"à Nour"},{"id":"d","text":"à la lecture"}]'::jsonb, 'c', '« Elle » est un pronom personnel féminin singulier : son référent est « Nour ». « L'' » dans « le relit » reprend « son article ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('228c95db-41b4-5497-8c98-0a6a6fd72191', '39e02166-7c43-5184-9e11-79fd1944f501', '« Le libraire ouvre la caisse. Il compte les pièces. » Le mot « Il » est un substitut…', '[{"id":"a","text":"lexical, car c''est un synonyme de libraire"},{"id":"b","text":"lexical, car c''est une périphrase"},{"id":"c","text":"lexical, car c''est un terme générique"},{"id":"d","text":"grammatical, car c''est un pronom"}]'::jsonb, 'd', '« Il » est un pronom personnel : un substitut grammatical. Un substitut lexical serait un nom ou un groupe nominal (un synonyme, un terme générique ou une périphrase), pas un pronom.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d30062f8-6825-5bdb-81b8-de6fc96e70e0', '39e02166-7c43-5184-9e11-79fd1944f501', 'Dans « Le lion se reposait. Le roi des animaux avait bien chassé. », le groupe « Le roi des animaux » est…', '[{"id":"a","text":"une périphrase"},{"id":"b","text":"un pronom démonstratif"},{"id":"c","text":"un pronom possessif"},{"id":"d","text":"un déterminant"}]'::jsonb, 'a', '« Le roi des animaux » est un groupe de mots qui décrit le référent au lieu de le nommer : c''est une périphrase, un substitut lexical. Ce n''est pas un pronom.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
