  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('797dada9-4dda-5005-bfb9-b4b2e3f07a55', '39e02166-7c43-5184-9e11-79fd1944f501', 'Complète pour respecter l''accord du substitut : « Les hirondelles sont revenues. ___ ont bâti leur nid sous le toit. »', '[{"id":"a","text":"Elles"},{"id":"b","text":"Elle"},{"id":"c","text":"Il"},{"id":"d","text":"Celui"}]'::jsonb, 'a', 'Le référent « les hirondelles » est féminin pluriel : le substitut doit s''accorder → Elles. « Il » et « Elle » sont au singulier, et « Celui » est masculin singulier.', 5)
