INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fd087971-b5ac-5353-9777-81979f6b4519', 'e0ef478a-7c3b-5b39-aaf7-44920d2cf28d', 'Dans « Skander a acheté un roman. Il le lit ce soir. », à quoi renvoie le pronom « le » ?', '[{"id":"a","text":"à Skander"},{"id":"b","text":"au soir"},{"id":"c","text":"au roman"},{"id":"d","text":"à la lecture"}]'::jsonb, 'c', 'Le pronom complément « le » reprend le référent « un roman » : il le lit = il lit le roman. « Il » reprend Skander, mais « le » reprend l''objet acheté.', 1)
