INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('67afaf0b-f2e9-5239-8d59-87fdb3a931cc', 'e0ef478a-7c3b-5b39-aaf7-44920d2cf28d', 'Dans « Nour a fini son article. Elle sourit. », le mot « Elle » qui reprend « Nour » est un substitut…', '[{"id":"a","text":"grammatical, car c''est un pronom"},{"id":"b","text":"lexical, car c''est un synonyme"},{"id":"c","text":"lexical, car c''est une périphrase"},{"id":"d","text":"lexical, car c''est un terme générique"}]'::jsonb, 'a', '« Elle » est un pronom personnel : c''est donc un substitut grammatical. Un substitut lexical serait un nom ou un groupe nominal (synonyme, périphrase, terme générique), jamais un pronom.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
