INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2ce057af-20e1-51eb-9ce2-365686985b29', 'e0ef478a-7c3b-5b39-aaf7-44920d2cf28d', 'Dans « Le médecin arriva vite. Le docteur ausculta l''enfant. », par quel procédé « le docteur » reprend-il « le médecin » ?', '[{"id":"a","text":"par une périphrase"},{"id":"b","text":"par un pronom personnel"},{"id":"c","text":"par un terme générique"},{"id":"d","text":"par un synonyme"}]'::jsonb, 'd', '« Docteur » a le même sens que « médecin » : c''est un synonyme, un substitut lexical. Ce n''est pas un pronom, ni une périphrase (qui serait un groupe descriptif), ni un terme générique (qui serait plus général).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
