  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c6e90e71-475d-59e4-b0c6-a901dfb23424', 'e0ef478a-7c3b-5b39-aaf7-44920d2cf28d', 'Complète en respectant l''accord : « La gazelle broutait tranquillement. ___ leva soudain la tête. »', '[{"id":"a","text":"Il"},{"id":"b","text":"Elle"},{"id":"c","text":"Ils"},{"id":"d","text":"Celui"}]'::jsonb, 'b', 'Le référent « la gazelle » est féminin singulier : le substitut doit s''accorder → Elle. « Il » serait masculin, « Ils » pluriel, et « Celui » est un pronom démonstratif masculin.', 4)
