INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3e518533-c209-5752-ae01-db72bb591197', 'e0ef478a-7c3b-5b39-aaf7-44920d2cf28d', 'Dans « Un aigle planait très haut. Cet oiseau surveillait la vallée. », le mot « oiseau » qui reprend « aigle » est…', '[{"id":"a","text":"une périphrase"},{"id":"b","text":"un pronom démonstratif"},{"id":"c","text":"un terme générique"},{"id":"d","text":"un synonyme exact"}]'::jsonb, 'c', '« Oiseau » est plus général que « aigle » et l''englobe : c''est un terme générique. Ce n''est pas un synonyme exact (tous les oiseaux ne sont pas des aigles) ni une périphrase (qui serait un groupe descriptif).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
