INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1dcc69fa-3467-53d7-83fe-d2e59a30561f', 'e0ef478a-7c3b-5b39-aaf7-44920d2cf28d', 'Quelle suite évite la répétition grâce à un substitut correct ?', '[{"id":"a","text":"Le libraire range les livres. Le libraire ferme la boutique."},{"id":"b","text":"Le libraire range les livres. Il ferme la boutique."},{"id":"c","text":"Le libraire range les livres. Elle ferme la boutique."},{"id":"d","text":"Le libraire range les livres. Ils ferme la boutique."}]'::jsonb, 'b', '« Il » reprend « le libraire » (masculin singulier) sans répéter le nom : c''est la bonne reprise. La phrase a répète le nom, la phrase c a un mauvais accord (Elle), et la phrase d cumule un mauvais accord et une faute de conjugaison.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
