INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('baad3eb8-2255-528b-bbf8-905ccd3404d6', '44f15dba-f947-5d03-a66b-d0953d12ae45', 'Dans « Les touristes photographiaient la médina. Ils admiraient ses ruelles étroites. », que reprend le déterminant possessif « ses » ?', '[{"id":"a","text":"les touristes"},{"id":"b","text":"la médina"},{"id":"c","text":"les ruelles"},{"id":"d","text":"les photos"}]'::jsonb, 'b', '« ses ruelles » = les ruelles de la médina : le possessif « ses » reprend le référent « la médina ». Le piège est de le rattacher à « les touristes », mais ce sont les ruelles de la médina, pas celles des touristes.', 1)
