INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('04a20eb4-3307-5fa6-900d-ec6337ba6b8e', '44f15dba-f947-5d03-a66b-d0953d12ae45', 'Complète : « Ton exposé est déjà prêt ; ___ est encore à écrire. » (il s''agit de mon exposé)', '[{"id":"a","text":"le mien"},{"id":"b","text":"mon"},{"id":"c","text":"mien"},{"id":"d","text":"le mon"}]'::jsonb, 'a', '« le mien » est un pronom possessif : il remplace tout le groupe « mon exposé ». « mon » seul est un déterminant, il exigerait un nom derrière (mon exposé) ; « mien » sans article et « le mon » n''existent pas ainsi.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d9596801-3e48-5a1e-b612-14e54248c35a', '44f15dba-f947-5d03-a66b-d0953d12ae45', 'Complète : « Deux romans sont posés sur la table : ___ de Skander est corné. »', '[{"id":"a","text":"celle"},{"id":"b","text":"celui"},{"id":"c","text":"ceux"},{"id":"d","text":"cela"}]'::jsonb, 'b', 'Le pronom démonstratif reprend « roman », masculin singulier → celui de Skander. « celle » serait féminin, « ceux » pluriel, et « cela » reprend une idée, pas un nom précis.', 3)
ON CONFLICT (id) DO UPDATE SET
