INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bc3bb7ba-2097-5344-ba8c-aa94882b62ad', '44f15dba-f947-5d03-a66b-d0953d12ae45', 'Dans quelle phrase la reprise par le pronom est-elle ambiguë ?', '[{"id":"a","text":"Skander salua le libraire, puis il rangea les livres."},{"id":"b","text":"Nour ferma son cahier et le rangea dans son sac."},{"id":"c","text":"Les élèves sortirent en récréation ; ils riaient."},{"id":"d","text":"La cloche sonna ; elle annonçait la fin du cours."}]'::jsonb, 'a', '« il » peut renvoyer à Skander ou au libraire : deux masculins singuliers, donc la reprise est ambiguë. On lèverait le doute en nommant celui qui range. Dans les autres phrases, un seul référent possible correspond au genre et au nombre du pronom.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e1f76a6d-2d48-5f31-9de6-f6fb92b424bb', '44f15dba-f947-5d03-a66b-d0953d12ae45', 'Pour reprendre « une truite » par un terme générique exact, quel substitut convient ?', '[{"id":"a","text":"ce fauve"},{"id":"b","text":"cet oiseau"},{"id":"c","text":"ce poisson"},{"id":"d","text":"ce reptile"}]'::jsonb, 'c', 'La truite est un poisson : « ce poisson » l''englobe correctement. Un terme générique doit vraiment contenir le référent ; « fauve », « oiseau » et « reptile » désignent d''autres catégories d''animaux et seraient des reprises fausses.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dcd8cfd0-383d-5680-9494-b3e634af0df9', '44f15dba-f947-5d03-a66b-d0953d12ae45', '« Le vieux figuier était énorme. L''arbre donnait de l''ombre. Il abritait les oiseaux. Ce géant vivait là depuis un siècle. » Combien de substituts reprennent « le vieux figuier » ?', '[{"id":"a","text":"un"},{"id":"b","text":"deux"},{"id":"c","text":"trois"},{"id":"d","text":"quatre"}]'::jsonb, 'c', 'Trois substituts forment la chaîne : « L''arbre » (terme générique), « Il » (pronom) et « Ce géant » (périphrase). « les oiseaux » n''est pas une reprise du figuier, c''est un autre référent.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
