INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4d82776d-059e-5530-9760-7ab7826c0ce5', 'b813a24a-5286-53ba-9c4a-b366fad39c20', 'Complète en respectant l''accord : « Le chameau et son chamelon avancent. ___ traversent le désert. »', '[{"id":"a","text":"Il"},{"id":"b","text":"Elle"},{"id":"c","text":"Ils"},{"id":"d","text":"Celui"}]'::jsonb, 'c', 'Le référent est un groupe pluriel (le chameau + son chamelon) : le substitut est « Ils ». « Il » et « Elle » sont au singulier, et « Celui » est un pronom démonstratif qui ne convient pas ici.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
