INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1c882264-2cbf-5395-b272-0c1e78fcc039', 'b813a24a-5286-53ba-9c4a-b366fad39c20', 'Dans « J''ai déjà mon billet ; as-tu le tien ? », le groupe « le tien » est…', '[{"id":"a","text":"un déterminant possessif"},{"id":"b","text":"un pronom possessif"},{"id":"c","text":"un pronom personnel"},{"id":"d","text":"une périphrase"}]'::jsonb, 'b', '« le tien » remplace tout le groupe « ton billet » et se place seul : c''est un pronom possessif. Un déterminant possessif (ton) précéderait un nom ; « le tien » n''a pas besoin de nom derrière lui.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8a5a6b02-5c79-56ae-97e8-8ec7e4d9b327', 'b813a24a-5286-53ba-9c4a-b366fad39c20', 'Complète par un terme générique adapté : « Un rouge-gorge chantait dans le jardin. ___ égayait la matinée. »', '[{"id":"a","text":"Cet oiseau"},{"id":"b","text":"Ce mammifère"},{"id":"c","text":"Cette fleur"},{"id":"d","text":"Ce poisson"}]'::jsonb, 'a', 'Le rouge-gorge est un oiseau : « Cet oiseau » est le terme générique exact. « mammifère », « fleur » et « poisson » ne contiennent pas le référent et seraient des reprises fausses.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
