  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('785c3f11-2e47-5112-9a74-3a104a66ff9e', 'b813a24a-5286-53ba-9c4a-b366fad39c20', 'Quelle suite reprend correctement « Nour et Sonia » sans répétition ni faute d''accord ?', '[{"id":"a","text":"Nour et Sonia lisent un conte. Nour et Sonia adorent les récits anciens."},{"id":"b","text":"Nour et Sonia lisent un conte. Elles adorent les récits anciens."},{"id":"c","text":"Nour et Sonia lisent un conte. Ils adorent les récits anciens."},{"id":"d","text":"Nour et Sonia lisent un conte. Elle adore les récits anciens."}]'::jsonb, 'b', '« Nour et Sonia » est un groupe féminin pluriel → le substitut est « Elles ». La phrase a répète les noms, la phrase c met un masculin pluriel (Ils) à tort, et la phrase d met un singulier (Elle) pour deux personnes.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

