  ('54861ac0-04c6-50b3-ad50-8baffff30dae', '9f22d186-da4d-5041-9b70-c086a49eec6f', 'french-8eme', '👑 Défi élite ⭐⭐⭐⭐ : L''arène des chroniqueurs', 4, 300, 60, 'challenge', 'admin', 4)
