INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('24cc78da-85ce-5870-980a-b0562dbab2e9', '54861ac0-04c6-50b3-ad50-8baffff30dae', 'Une seule de ces affirmations sur les substituts est exacte. Laquelle ?', '[{"id":"a","text":"Un pronom personnel est un substitut lexical."},{"id":"b","text":"Une périphrase est un substitut lexical."},{"id":"c","text":"Le mot « mon » dans « mon cahier » est un pronom possessif."},{"id":"d","text":"Un substitut ne s''accorde jamais avec son référent."}]'::jsonb, 'b', 'La périphrase est bien un substitut lexical (un groupe nominal descriptif). Un pronom est un substitut grammatical, pas lexical ; « mon » devant un nom est un déterminant, pas un pronom ; et un substitut s''accorde toujours en genre et en nombre avec son référent.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bf003a6c-9912-5e5a-a92d-70e73c3266b1', '54861ac0-04c6-50b3-ad50-8baffff30dae', 'Chasse à l''erreur : dans quelle phrase le substitut est-il mal accordé avec son référent ?', '[{"id":"a","text":"La rivière débordait ; ils inondaient les champs."},{"id":"b","text":"Les cigognes migrent en automne ; elles reviennent au printemps."},{"id":"c","text":"Le platane perd ses feuilles ; il reverdira au printemps."},{"id":"d","text":"Les pêcheurs rentraient au port ; ils chantaient."}]'::jsonb, 'a', 'Ici la bonne réponse est la phrase fautive : « la rivière » est féminin singulier, le substitut devrait être « elle inondait », pas « ils inondaient ». Les trois autres reprises respectent le genre et le nombre de leur référent.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f67f0467-6ccf-583b-bb8e-3f622956c353', '54861ac0-04c6-50b3-ad50-8baffff30dae', 'Dans quelle phrase la reprise reste-t-elle ambiguë ?', '[{"id":"a","text":"Nour rangea ses crayons puis les compta un à un."},{"id":"b","text":"Le train entra en gare ; il était bondé de voyageurs."},{"id":"c","text":"Les enfants coururent vers la plage ; ils riaient aux éclats."},{"id":"d","text":"Karim rendit le livre au bibliothécaire quand il ferma la salle."}]'::jsonb, 'd', '« il » peut renvoyer à Karim ou au bibliothécaire, deux masculins singuliers : la reprise est ambiguë. Dans les autres phrases, un seul référent correspond au pronom, la reprise est claire.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('99b81794-fb77-579c-9319-5ac781beb9c0', '54861ac0-04c6-50b3-ad50-8baffff30dae', 'Le référent est « un dauphin ». Quel substitut serait FAUX ?', '[{"id":"a","text":"ce mammifère"},{"id":"b","text":"ce poisson"},{"id":"c","text":"cet animal"},{"id":"d","text":"ce cétacé"}]'::jsonb, 'b', 'Le dauphin est un mammifère marin (un cétacé), pas un poisson : « ce poisson » serait une reprise fausse. « mammifère », « animal » et « cétacé » contiennent tous correctement le référent.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('96642cbf-cc13-5059-8777-a9e249ed63d7', '54861ac0-04c6-50b3-ad50-8baffff30dae', 'Complète : « Mes résultats sont excellents ; ___ aussi. » (il s''agit de tes résultats)', '[{"id":"a","text":"le tien"},{"id":"b","text":"tes"},{"id":"c","text":"les tients"},{"id":"d","text":"les tiens"}]'::jsonb, 'd', '« résultats » est masculin pluriel : le pronom possessif est « les tiens ». « le tien » serait un singulier, « tes » est un déterminant qui appellerait un nom, et « les tients » est une orthographe fautive.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('80840a94-9d6a-51a9-8a5f-5b09debd31a2', '54861ac0-04c6-50b3-ad50-8baffff30dae', '« Le vieux gardien ouvrit la grille. Le vieil homme sourit aux élèves. Il connaissait chacun d''eux. Ce fidèle serviteur veillait sur l''école depuis trente ans. » Combien de substituts reprennent « le vieux gardien » ?', '[{"id":"a","text":"un"},{"id":"b","text":"deux"},{"id":"c","text":"trois"},{"id":"d","text":"quatre"}]'::jsonb, 'c', 'Trois substituts forment la chaîne : « Le vieil homme » (périphrase), « Il » (pronom) et « Ce fidèle serviteur » (périphrase). « les élèves » n''est pas une reprise du gardien.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

