INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4c6ec745-5137-59cd-9f01-a443f74f4b99', '00e86395-3188-52d7-93ed-a379c660b622', 'Dans « Sonia offrit un bracelet à sa cousine. Celle-ci le porta aussitôt. », à qui renvoie « Celle-ci » ?', '[{"id":"a","text":"à Sonia"},{"id":"b","text":"au bracelet"},{"id":"c","text":"à la cousine"},{"id":"d","text":"à la main"}]'::jsonb, 'c', 'Le pronom démonstratif « celle-ci » reprend le nom féminin le plus proche : la cousine. Le pronom « le » de « le porta », lui, reprend le bracelet.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
