INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4bcf9d41-1efb-5026-ae9d-bd2507921d36', '00e86395-3188-52d7-93ed-a379c660b622', 'Dans « Averroès enseigna la médecine. Le savant de Cordoue rédigea de nombreux traités. », le groupe « Le savant de Cordoue » est…', '[{"id":"a","text":"un pronom"},{"id":"b","text":"une périphrase"},{"id":"c","text":"un synonyme"},{"id":"d","text":"un déterminant"}]'::jsonb, 'b', 'C''est un groupe de mots qui décrit et identifie Averroès au lieu de répéter son nom : une périphrase, substitut lexical. Ce n''est ni un pronom ni un simple synonyme.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4618cd7e-77ae-550f-93ee-6a80046897de', '00e86395-3188-52d7-93ed-a379c660b622', 'Complète en respectant l''accord : « La lionne et ses petits se reposaient. ___ avaient bien mangé. »', '[{"id":"a","text":"Elle"},{"id":"b","text":"Elles"},{"id":"c","text":"Ils"},{"id":"d","text":"Il"}]'::jsonb, 'c', 'Le référent est un groupe mixte (la lionne, féminin + ses petits, masculin) : l''accord se fait au masculin pluriel → Ils. « Elle » et « Il » sont au singulier, et « Elles » ne conviendrait que pour un groupe entièrement féminin.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4af9a555-29e1-563d-b569-5dcc5367c10c', '00e86395-3188-52d7-93ed-a379c660b622', 'Complète par un terme générique adapté : « Un cactus poussait au milieu de la cour. ___ résistait à la sécheresse. »', '[{"id":"a","text":"Cet animal"},{"id":"b","text":"Cette plante"},{"id":"c","text":"Ce minéral"},{"id":"d","text":"Cet insecte"}]'::jsonb, 'b', 'Le cactus est une plante : « Cette plante » est le terme générique exact. « animal », « minéral » et « insecte » ne contiennent pas le référent et seraient des reprises fausses.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
