INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6a290a40-901f-5947-a65c-8253785e5729', '00e86395-3188-52d7-93ed-a379c660b622', 'Dans « Range tes affaires, je range les miennes. », le groupe « les miennes » remplace…', '[{"id":"a","text":"tes affaires"},{"id":"b","text":"les affaires"},{"id":"c","text":"mes mains"},{"id":"d","text":"mes affaires"}]'::jsonb, 'd', '« les miennes » est un pronom possessif féminin pluriel : il remplace « mes affaires ». Il ne reprend pas « tes affaires » (ce serait « les tiennes ») et ne se rapporte pas à un autre nom.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
