INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4415bbb1-33af-5b77-afc9-afdcdbe08fda', '00e86395-3188-52d7-93ed-a379c660b622', 'Un brouillon répète trois fois « le trésor ». Quelle réécriture évite la répétition sans faute d''accord ?', '[{"id":"a","text":"Les pirates cherchaient le trésor. Ils le convoitaient. Ce butin les rendait fous."},{"id":"b","text":"Les pirates cherchaient le trésor. Les pirates convoitaient le trésor."},{"id":"c","text":"Les pirates cherchaient le trésor. Elle le convoitait. Ce butin les rendait fous."},{"id":"d","text":"Les pirates cherchaient le trésor. Ils le convoitaient. Cette butin les rendait fous."}]'::jsonb, 'a', 'La reprise alterne « le » (pronom qui reprend le trésor) et « Ce butin » (périphrase) sans jamais répéter ni se tromper d''accord. La phrase b répète tout, la phrase c met « Elle » à la place de « Ils », et la phrase d écrit « Cette butin » (butin est masculin).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

