  ('307d9fa3-f72b-5fc5-b3e8-260098bcf0a7', '9f22d186-da4d-5041-9b70-c086a49eec6f', 'french-8eme', '👑 Défi élite ⭐⭐⭐⭐ : Le grand maître de la cohérence', 4, 300, 60, 'challenge', 'admin', 6)
