INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('64f7ab09-c40e-5755-9eab-0aa7dc5ef2b9', '307d9fa3-f72b-5fc5-b3e8-260098bcf0a7', 'Une seule de ces affirmations est exacte. Laquelle ?', '[{"id":"a","text":"Le pronom démonstratif « celui » est un substitut lexical."},{"id":"b","text":"Un terme générique est toujours plus précis que son référent."},{"id":"c","text":"Une périphrase remplace un nom par un groupe de mots qui le décrit."},{"id":"d","text":"Le déterminant « ses » et le pronom « les siens » sont identiques."}]'::jsonb, 'c', 'La périphrase remplace bien le nom par un groupe descriptif (le roi des animaux = le lion). « celui » est un pronom, donc un substitut grammatical ; un terme générique est plus général, pas plus précis ; et « ses » (déterminant + nom) diffère de « les siens » (pronom seul).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7afe9d1c-4bbd-5e93-b194-646c148ef741', '307d9fa3-f72b-5fc5-b3e8-260098bcf0a7', 'Dans quelle phrase la reprise par le pronom est-elle correctement accordée ?', '[{"id":"a","text":"Les documentaires que Nour préfère parlent des océans. Il la passionnent."},{"id":"b","text":"Le phare guidait les marins. Ils veillait sur la baie toute la nuit."},{"id":"c","text":"Les nomades dressèrent la tente. Il se reposèrent enfin."},{"id":"d","text":"La caravane traversa les dunes. Elle atteignit l''oasis au crépuscule."}]'::jsonb, 'd', '« la caravane » est féminin singulier → « Elle atteignit » : accord correct. Ailleurs : « les documentaires » appelle « ils » (et non « il »), « le phare » appelle « il » (et non « ils »), et « les nomades » appelle « ils » (et non « il »).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('787fc12e-4d8f-57a4-8b7e-fb0b555da03c', '307d9fa3-f72b-5fc5-b3e8-260098bcf0a7', '« Le professeur félicita l''élève, car il avait bien travaillé. » Pour montrer clairement que c''est l''ÉLÈVE qui a travaillé, comment reformuler ?', '[{"id":"a","text":"…, car cet élève avait bien travaillé."},{"id":"b","text":"…, car il avait bien travaillé."},{"id":"c","text":"…, car ils avaient bien travaillé."},{"id":"d","text":"…, car elle avait bien travaillé."}]'::jsonb, 'a', 'Remplacer le pronom ambigu « il » par « cet élève » désigne sans doute possible celui qui a travaillé. Garder « il » laisse l''ambiguïté (professeur ou élève ?), « ils » change le sens (deux personnes) et « elle » ne correspond à aucun référent féminin.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('630c8a89-0d27-5a6e-bbd4-93390521f090', '307d9fa3-f72b-5fc5-b3e8-260098bcf0a7', 'Le référent est « une chauve-souris ». Quel substitut est exact ?', '[{"id":"a","text":"cet oiseau"},{"id":"b","text":"ce reptile"},{"id":"c","text":"ce mammifère"},{"id":"d","text":"cet insecte"}]'::jsonb, 'c', 'La chauve-souris est un mammifère, même si elle vole : « ce mammifère » est la reprise exacte. Le piège classique est « cet oiseau » : voler ne fait pas d''un animal un oiseau. « reptile » et « insecte » sont également faux.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('01552569-cd9d-5f50-91d6-6c6664e8ee14', '307d9fa3-f72b-5fc5-b3e8-260098bcf0a7', 'Complète : « Nos places sont réservées ; ___ ne le sont pas encore. » (il s''agit de vos places)', '[{"id":"a","text":"le vôtre"},{"id":"b","text":"vos"},{"id":"c","text":"les votres"},{"id":"d","text":"les vôtres"}]'::jsonb, 'd', '« places » est féminin pluriel : le pronom possessif est « les vôtres », avec l''accent circonflexe. « le vôtre » serait un singulier, « vos » est un déterminant qui appellerait un nom, et « les votres » sans accent est une faute d''orthographe.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('995ad690-ab40-59d2-91db-6d2c27248855', '307d9fa3-f72b-5fc5-b3e8-260098bcf0a7', '« Le jeune apprenti forgeait une lame. Le garçon frappait le fer rougeoyant. Celui-ci crépitait sous les coups. L''artisan en herbe souriait. » À quoi renvoie le pronom « Celui-ci » ?', '[{"id":"a","text":"au jeune apprenti"},{"id":"b","text":"au fer"},{"id":"c","text":"à la lame"},{"id":"d","text":"aux coups"}]'::jsonb, 'b', '« Celui-ci » est masculin singulier et reprend le nom le plus proche qui correspond : « le fer » (c''est lui qui crépite). « la lame » est féminin (ce serait « celle-ci »), et « le jeune apprenti » est repris par « Le garçon » et « L''artisan en herbe », pas par « Celui-ci ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

