INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1f5658db-56dd-5917-9d6f-535222821b40', '3529680c-fe5d-5c70-9ba6-954136b66597', 'Dans la famille de mots « dent, dentiste, dentaire, dentier », quel est le radical (la partie commune) ?', '[{"id":"a","text":"dent"},{"id":"b","text":"tiste"},{"id":"c","text":"aire"},{"id":"d","text":"dentier"}]'::jsonb, 'a', 'Le radical est la partie commune à tous les mots de la famille et porteuse du sens : ici « dent », que l''on retrouve dans chaque mot. « tiste » et « aire » sont des fins de mots (suffixes), pas le radical.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8aa8f82d-c598-5cf0-acae-bf7900fe4069', '3529680c-fe5d-5c70-9ba6-954136b66597', 'Que signifie le préfixe « re- » dans le mot « relire » ?', '[{"id":"a","text":"lire avant"},{"id":"b","text":"lire de nouveau"},{"id":"c","text":"mal lire"},{"id":"d","text":"ne pas lire"}]'::jsonb, 'b', 'Le préfixe « re- » exprime la répétition : relire, c''est lire une nouvelle fois. Il ne marque ni l''antériorité, ni le contraire, ni la négation.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4667c504-e931-5982-b881-3970b152fc44', '3529680c-fe5d-5c70-9ba6-954136b66597', 'Dans le mot « chanteur », l''élément « -eur » ajouté au radical « chant- » est :', '[{"id":"a","text":"un préfixe"},{"id":"b","text":"un autre radical"},{"id":"c","text":"un suffixe"},{"id":"d","text":"un mot simple"}]'::jsonb, 'c', 'Un suffixe se place APRÈS le radical : « -eur » suit « chant- » et désigne celui qui fait l''action (le chanteur). Un préfixe, lui, se placerait avant le radical.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a308f26c-e7d8-5b85-9a91-1736ac5c0d5f', '3529680c-fe5d-5c70-9ba6-954136b66597', 'Dans quelle phrase le mot « glacé » est-il employé au sens FIGURÉ ?', '[{"id":"a","text":"J''ai bu un thé glacé après le sport."},{"id":"b","text":"L''eau du torrent était glacée."},{"id":"c","text":"Le vent glacé piquait les joues."},{"id":"d","text":"Il m''a lancé un regard glacé."}]'::jsonb, 'd', 'Un regard n''a pas de température : « glacé » y peint la froideur, l''hostilité — c''est le sens figuré. Dans les autres phrases, « glacé » garde son sens propre (vraiment froid).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('02519013-cf0d-536b-9beb-648cc8400cbd', '3529680c-fe5d-5c70-9ba6-954136b66597', 'Quel mot appartient au champ lexical de la FORÊT ?', '[{"id":"a","text":"clavier"},{"id":"b","text":"feuillage"},{"id":"c","text":"autoroute"},{"id":"d","text":"cartable"}]'::jsonb, 'b', 'Un champ lexical réunit les mots liés à un même thème. « feuillage » évoque la forêt et la nature ; « clavier », « autoroute » et « cartable » appartiennent à d''autres thèmes.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
