INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a932856d-1562-5734-862e-7f8813c3efc4', '87b96a79-1178-547b-ae96-f41aaeee17ab', 'Quel mot appartient à la famille de « fleur » ?', '[{"id":"a","text":"fleuriste"},{"id":"b","text":"flèche"},{"id":"c","text":"fleuve"},{"id":"d","text":"flamme"}]'::jsonb, 'a', 'Un mot de la famille partage le radical ET le sens : « fleuriste » (celui qui vend des fleurs) contient « fleur- ». « flèche », « fleuve » et « flamme » se ressemblent par le son mais n''ont rien à voir avec la fleur.', 1)
