INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dca214cc-3ad3-5cef-95ed-eecf5071af7a', '87b96a79-1178-547b-ae96-f41aaeee17ab', 'Quel est le radical commun à « chanter, chanteur, chanson, chantonner » ?', '[{"id":"a","text":"chanson"},{"id":"b","text":"chant"},{"id":"c","text":"chanteur"},{"id":"d","text":"eur"}]'::jsonb, 'b', 'Le radical est la plus petite partie commune à tous ces mots : « chant ». On lui ajoute ensuite des suffixes (-er, -eur, -son, -onner). « chanson » et « chanteur » sont des mots entiers, pas le radical.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ad69ce55-4877-5213-87f7-5ee7386f4947', '87b96a79-1178-547b-ae96-f41aaeee17ab', 'Dans le mot « impoli », quel est le préfixe ?', '[{"id":"a","text":"po-"},{"id":"b","text":"-oli"},{"id":"c","text":"im-"},{"id":"d","text":"-poli"}]'::jsonb, 'c', 'Le préfixe se place au début, devant le radical « poli » : c''est « im- », qui marque ici la négation (impoli = pas poli). « -poli » est le radical, pas le préfixe.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('84a3491b-7381-5134-8b7c-81c77bc61839', '87b96a79-1178-547b-ae96-f41aaeee17ab', 'Le suffixe « -able » dans « lavable » indique :', '[{"id":"a","text":"l''action de laver"},{"id":"b","text":"celui qui lave"},{"id":"c","text":"qu''on ne peut pas laver"},{"id":"d","text":"qu''on peut laver"}]'::jsonb, 'd', 'Le suffixe « -able » exprime ce qu''on peut faire : lavable = qu''on peut laver. Il ne marque ni l''action (ce serait « lavage ») ni la négation.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6bfdc9fd-12a2-5a04-b0ea-e5930acf8606', '87b96a79-1178-547b-ae96-f41aaeee17ab', 'Dans quelle phrase le verbe « brûler » est-il employé au sens PROPRE ?', '[{"id":"a","text":"La bougie brûle sur la table."},{"id":"b","text":"Il brûle d''impatience de partir."},{"id":"c","text":"Elle brûle les étapes pour finir vite."},{"id":"d","text":"Ce discours brûlant l''a bouleversé."}]'::jsonb, 'a', 'Au sens propre, « brûler » désigne un vrai feu : la bougie brûle réellement. Dans les autres phrases, le mot est imagé (impatience, précipitation, émotion) : c''est le sens figuré.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6118a842-e2d6-5792-b349-c18b990e3aba', '87b96a79-1178-547b-ae96-f41aaeee17ab', 'Quel mot n''appartient PAS au champ lexical de la mer ?', '[{"id":"a","text":"vague"},{"id":"b","text":"clavier"},{"id":"c","text":"marée"},{"id":"d","text":"rivage"}]'::jsonb, 'b', 'Un champ lexical réunit les mots d''un même thème : « vague », « marée » et « rivage » évoquent tous la mer. « clavier » appartient au thème de l''informatique : c''est l''intrus.', 6)
