INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e8f2101-0641-526b-8417-1fd1ce25bac0', '2435cf87-dcf9-5170-b883-caa1975c1fa3', 'Lequel de ces mots est formé d''un préfixe + un radical + un suffixe ?', '[{"id":"a","text":"chanteur"},{"id":"b","text":"invisible"},{"id":"c","text":"refaire"},{"id":"d","text":"maison"}]'::jsonb, 'b', '« invisible » = préfixe « in- » + radical « vis- » + suffixe « -ible ». « chanteur » n''a que radical + suffixe ; « refaire » que préfixe + radical ; « maison » est un mot simple, sans affixe.', 1)
