INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('649a6e2d-a295-50cb-a05f-ac5740211300', '2435cf87-dcf9-5170-b883-caa1975c1fa3', 'Dans le mot « prévoir », que signifie le préfixe « pré- » ?', '[{"id":"a","text":"contre"},{"id":"b","text":"beaucoup"},{"id":"c","text":"mal"},{"id":"d","text":"avant"}]'::jsonb, 'd', 'Le préfixe « pré- » signifie « avant » : prévoir, c''est voir à l''avance. On le retrouve dans prédire, préparer, prévenir.', 2)
