INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d3c77995-551b-5911-bf00-c71f4fee0508', '2435cf87-dcf9-5170-b883-caa1975c1fa3', 'Quel mot n''appartient PAS à la famille de « terre » ?', '[{"id":"a","text":"terreur"},{"id":"b","text":"terrain"},{"id":"c","text":"atterrir"},{"id":"d","text":"souterrain"}]'::jsonb, 'a', '« terrain », « atterrir » et « souterrain » partagent le radical « terr- » et l''idée du sol. « terreur » vient de la peur (terror), pas de la terre : c''est une fausse famille, même forme mais sens différent.', 3)
