INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a75d0ebe-a9fe-5ce9-a3c9-aba57f4985d5', '2435cf87-dcf9-5170-b883-caa1975c1fa3', 'En ajoutant le suffixe « -tion » au verbe « décorer », on obtient « décoration », qui est :', '[{"id":"a","text":"un verbe"},{"id":"b","text":"un adjectif"},{"id":"c","text":"un nom"},{"id":"d","text":"un adverbe"}]'::jsonb, 'c', 'Le suffixe « -tion » transforme le verbe « décorer » en un nom, « décoration » (l''action ou le résultat). Le suffixe change ici la classe grammaticale du mot.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
