  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b4f5db95-ba81-5b9a-8c4e-0126b8598b8d', '2435cf87-dcf9-5170-b883-caa1975c1fa3', 'Dans quelle phrase le verbe « dévorer » est-il employé au sens FIGURÉ ?', '[{"id":"a","text":"Le lion dévore sa proie dans la savane."},{"id":"b","text":"Il dévore un roman entier en une seule nuit."},{"id":"c","text":"Le chien affamé a dévoré toute sa gamelle."},{"id":"d","text":"Les fauves dévorent la viande crue."}]'::jsonb, 'b', 'Lire n''est pas manger : « dévorer un roman » signifie le lire avidement, c''est le sens figuré. Dans les autres phrases, on mange vraiment : c''est le sens propre.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
