  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ad76b3ca-9118-5eed-a012-cc33d50a3844', '2435cf87-dcf9-5170-b883-caa1975c1fa3', 'Quel préfixe faut-il ajouter à « responsable » pour former son contraire ?', '[{"id":"a","text":"im- (imresponsable)"},{"id":"b","text":"in- (inresponsable)"},{"id":"c","text":"ir- (irresponsable)"},{"id":"d","text":"dé- (déresponsable)"}]'::jsonb, 'c', 'Le préfixe de négation « in- » s''adapte à la lettre suivante : devant « r », il devient « ir- ». Le contraire de responsable est donc « irresponsable ». « im- » s''emploierait devant m/b/p, pas devant r.', 6)
