INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('258f85cf-521b-52a8-81f3-f2b72884a731', '3e1e19a2-74f4-568a-b98e-c2144772e598', 'Le suffixe « -ette » dans « maisonnette » indique :', '[{"id":"a","text":"une très grande maison"},{"id":"b","text":"une petite maison"},{"id":"c","text":"l''action de bâtir"},{"id":"d","text":"le contraire de maison"}]'::jsonb, 'b', 'Le suffixe « -ette » est un diminutif : il indique le petit. Une maisonnette est une petite maison, comme une fillette est une petite fille.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
