INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bb5801b9-846b-507d-a21f-cbb5ad2e21a0', '3e1e19a2-74f4-568a-b98e-c2144772e598', 'Dans l''expression « la clé du problème », le mot « clé » est employé au sens :', '[{"id":"a","text":"propre"},{"id":"b","text":"concret"},{"id":"c","text":"figuré"},{"id":"d","text":"premier"}]'::jsonb, 'c', 'Il ne s''agit pas d''un objet en métal : « la clé du problème » désigne la solution qui l''ouvre, par image. C''est donc le sens figuré (les mots « concret », « propre » et « premier » désignent au contraire le sens propre).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
