  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('81d7bea2-dd4d-5fb7-9a1c-0070ffa39602', '3e1e19a2-74f4-568a-b98e-c2144772e598', 'Quel mot n''est PAS de la famille de « chant » ?', '[{"id":"a","text":"chantier"},{"id":"b","text":"chanteur"},{"id":"c","text":"chanson"},{"id":"d","text":"chantonner"}]'::jsonb, 'a', '« chanteur », « chanson » et « chantonner » évoquent tous l''idée de chanter. « chantier » (un lieu de travaux) a la même forme de début mais aucun rapport de sens : c''est une fausse famille.', 6)
