INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9b0596a7-fd99-5861-a9fe-cab48b857404', 'd7b3bdc4-7fd7-5f05-b46c-9e5240f92f2e', 'Quelle est la décomposition correcte du mot « impensable » ?', '[{"id":"a","text":"radical « impens » + suffixe « -able »"},{"id":"b","text":"préfixe « im- » + radical « pens- » + suffixe « -able »"},{"id":"c","text":"préfixe « imp- » + radical « ens- » + suffixe « -able »"},{"id":"d","text":"préfixe « im- » + radical « pensable »"}]'::jsonb, 'b', 'Le radical est « pens- » (de penser). Devant lui, le préfixe de négation « im- » ; après lui, le suffixe « -able » (qu''on peut faire). Impensable = qu''on ne peut pas penser. Les autres découpages coupent le mot au mauvais endroit.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c351bf58-4e8f-5e70-bb88-eadecff6d65b', 'd7b3bdc4-7fd7-5f05-b46c-9e5240f92f2e', 'Dans lequel de ces mots le préfixe « in- » ne signifie PAS « ne… pas » (la négation) ?', '[{"id":"a","text":"inutile"},{"id":"b","text":"incapable"},{"id":"c","text":"inhabituel"},{"id":"d","text":"inspirer"}]'::jsonb, 'd', 'Dans « inspirer », « in- » signifie « dans » (faire entrer l''air) : ce n''est pas une négation. Dans les trois autres, « in- » nie : inutile = pas utile, incapable = pas capable, inhabituel = pas habituel. Un même préfixe peut avoir plusieurs sens.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('320cc7a4-5561-523a-8806-ee60cd90dcc4', 'd7b3bdc4-7fd7-5f05-b46c-9e5240f92f2e', 'Dans quelle phrase le verbe « éclater » est-il employé au sens PROPRE ?', '[{"id":"a","text":"La joie éclate sur son visage."},{"id":"b","text":"Elle a éclaté de rire en le voyant."},{"id":"c","text":"Le ballon a éclaté dans un grand bruit."},{"id":"d","text":"Un scandale a éclaté dans la ville."}]'::jsonb, 'c', 'Au sens propre, « éclater », c''est se briser d''un coup : le ballon éclate réellement. Dans les autres phrases, le mot est imagé (la joie, le rire, un scandale qui surgit) : c''est le sens figuré.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b68faef-1142-5a15-9b6b-8da3bf41ef9b', 'd7b3bdc4-7fd7-5f05-b46c-9e5240f92f2e', 'L''ensemble « forêt, arbre, feuillage, verdure, oiseau » forme :', '[{"id":"a","text":"un champ lexical (le thème de la nature)"},{"id":"b","text":"une famille de mots (le même radical)"},{"id":"c","text":"une liste de synonymes"},{"id":"d","text":"une série de mots contraires"}]'::jsonb, 'a', 'Ces mots n''ont pas le même radical, donc ce n''est pas une famille ; ils n''ont pas le même sens, donc ce ne sont pas des synonymes. Ils se rattachent tous au thème de la nature : c''est un champ lexical.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2fe12f12-1e52-51ac-a327-e784476d1173', 'd7b3bdc4-7fd7-5f05-b46c-9e5240f92f2e', 'Quel mot appartient vraiment à la famille de « mer » (l''étendue d''eau salée) ?', '[{"id":"a","text":"amertume"},{"id":"b","text":"mère"},{"id":"c","text":"commère"},{"id":"d","text":"marin"}]'::jsonb, 'd', '« marin » (comme maritime, marée) partage le radical « mar- » et l''idée de la mer. « amertume » vient de « amer », « mère » est un homophone (le parent) et « commère » n''a aucun rapport : ce sont des pièges de forme, pas de sens.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('45953864-515a-50ee-8aae-3b20387ab1e3', 'd7b3bdc4-7fd7-5f05-b46c-9e5240f92f2e', 'Le suffixe « -âtre » dans « verdâtre » apporte une nuance :', '[{"id":"a","text":"de petitesse"},{"id":"b","text":"péjorative (un vert déplaisant)"},{"id":"c","text":"de grandeur"},{"id":"d","text":"de répétition"}]'::jsonb, 'b', 'Le suffixe « -âtre » ajoute une nuance péjorative, dépréciative : verdâtre = d''un vert sale ou déplaisant (comme blanchâtre, douceâtre). Il n''indique ni la petitesse, ni la grandeur, ni la répétition.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

