INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2fbc5a9c-207f-59d4-a170-4f703f6870b2', '9946ceac-c905-5025-a44d-aa7f1e155a1a', 'Quel mot est un DÉRIVÉ (formé avec un affixe) et non un mot simple ?', '[{"id":"a","text":"reboucher"},{"id":"b","text":"table"},{"id":"c","text":"arbre"},{"id":"d","text":"main"}]'::jsonb, 'a', '« reboucher » est un mot dérivé : préfixe « re- » + radical « bouch- » + suffixe « -er ». « table », « arbre » et « main » sont des mots simples, formés d''un seul radical sans affixe.', 1)
