INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('189b80d5-1335-5f25-959f-4f8b6a0aaf49', '9946ceac-c905-5025-a44d-aa7f1e155a1a', 'Dans le mot « redémarrer », le préfixe « re- » exprime :', '[{"id":"a","text":"le contraire"},{"id":"b","text":"l''éloignement"},{"id":"c","text":"la répétition"},{"id":"d","text":"la négation"}]'::jsonb, 'c', 'Le préfixe « re- » marque la répétition : redémarrer, c''est démarrer de nouveau. Il n''exprime ni le contraire (ce serait « dé- »), ni la négation.', 2)
