INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('39d18092-cc63-5719-b39b-10ccc4f8fbbd', '9946ceac-c905-5025-a44d-aa7f1e155a1a', 'Le suffixe « -ien » dans « musicien » sert à désigner :', '[{"id":"a","text":"un lieu"},{"id":"b","text":"celui qui exerce une activité"},{"id":"c","text":"une petite chose"},{"id":"d","text":"une action"}]'::jsonb, 'b', 'Le suffixe « -ien » désigne celui qui exerce une activité ou un métier : un musicien fait de la musique, comme un mécanicien, un historien. Il n''indique ni un lieu ni un diminutif.', 3)
