INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b81cb793-fe0e-5446-8c97-79dd329f1a0e', '9946ceac-c905-5025-a44d-aa7f1e155a1a', 'Dans « dévoiler un secret », le verbe « dévoiler » est employé au sens :', '[{"id":"a","text":"propre, enlever un voile de tissu"},{"id":"b","text":"concret"},{"id":"c","text":"littéral"},{"id":"d","text":"figuré"}]'::jsonb, 'd', 'Un secret n''a pas de voile en tissu : « dévoiler un secret » signifie le révéler, par image. C''est donc le sens figuré (les mots « concret », « littéral » et « propre » désignent au contraire le sens premier).', 4)
