INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('130920ed-f192-5f48-9721-a8b338933e01', '9946ceac-c905-5025-a44d-aa7f1e155a1a', 'Quel mot appartient à la famille de « nombre » ?', '[{"id":"a","text":"dénombrer"},{"id":"b","text":"ombre"},{"id":"c","text":"sombre"},{"id":"d","text":"encombrer"}]'::jsonb, 'a', '« dénombrer » (compter) partage le radical « nombr- » et l''idée de quantité, comme nombreux ou innombrable. « ombre », « sombre » et « encombrer » contiennent « ombre », pas « nombre » : ce sont des pièges de forme.', 5)
