INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c0dc0407-d950-5fe2-b0f3-eb7e3c796324', '86c7c4fd-fedc-506b-8e2d-95c9d5d36878', 'Quel est le contraire de « légal », formé à l''aide d''un préfixe de négation ?', '[{"id":"a","text":"délégal"},{"id":"b","text":"inlégal"},{"id":"c","text":"illégal"},{"id":"d","text":"irlégal"}]'::jsonb, 'c', 'Le préfixe de négation « in- » s''adapte à la lettre suivante : devant « l », il devient « il- ». Le contraire de légal est donc « illégal », comme illisible ou illimité. « inlégal » et « délégal » n''existent pas.', 1)
