INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7f2b5538-3392-5933-897a-36775f2895da', '86c7c4fd-fedc-506b-8e2d-95c9d5d36878', 'De combien d''éléments (préfixe, radical, suffixe) le mot « rechargeable » est-il composé ?', '[{"id":"a","text":"trois : re- + charg- + -able"},{"id":"b","text":"deux : recharge + -able"},{"id":"c","text":"deux : re- + chargeable"},{"id":"d","text":"quatre éléments"}]'::jsonb, 'a', 'On trouve trois éléments : le préfixe « re- » (de nouveau), le radical « charg- » (de charger) et le suffixe « -able » (qu''on peut faire). Rechargeable = qu''on peut charger de nouveau.', 2)
