INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f6455244-1cd3-50f3-8860-f4a6eca01074', '86c7c4fd-fedc-506b-8e2d-95c9d5d36878', 'Dans quelle phrase le mot « lumière » est-il employé au sens PROPRE ?', '[{"id":"a","text":"Le juge a fait la lumière sur l''affaire."},{"id":"b","text":"Cet élève est une lumière en mathématiques."},{"id":"c","text":"Elle a eu une idée lumineuse."},{"id":"d","text":"La lumière du soleil entre par la fenêtre."}]'::jsonb, 'd', 'Au sens propre, « lumière » désigne la clarté réelle : celle du soleil. Dans les autres phrases, le mot est imagé — comprendre (faire la lumière), une personne très intelligente, une idée brillante : c''est le sens figuré.', 3)
