INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7c95b92f-a9c5-592b-be18-4fb1e38ee228', '86c7c4fd-fedc-506b-8e2d-95c9d5d36878', 'Quelle analyse du mot « insupportable » est correcte ?', '[{"id":"a","text":"in- (« dans ») + supportable = qu''on peut supporter"},{"id":"b","text":"préfixe in- (négation) + radical support- + suffixe -able = qu''on ne peut pas supporter"},{"id":"c","text":"radical « insupport » + suffixe « -able »"},{"id":"d","text":"préfixe « insup- » + radical « -portable »"}]'::jsonb, 'b', 'Le mot se découpe en préfixe « in- » (négation), radical « support- » et suffixe « -able » : insupportable = qu''on ne peut pas supporter. Ici « in- » nie bien (contrairement à « inspirer »), et les découpages c et d coupent le mot au mauvais endroit.', 4)
