INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c0522ecd-dce9-53ac-8a40-2c81940cd4ce', '86c7c4fd-fedc-506b-8e2d-95c9d5d36878', 'Lequel de ces ensembles est une FAMILLE de mots (même radical), et non un champ lexical ?', '[{"id":"a","text":"hiver, froid, neige, gel"},{"id":"b","text":"école, cour, cartable, élève"},{"id":"c","text":"chant, chanteur, chanson, chantonner"},{"id":"d","text":"route, voiture, moto, essence"}]'::jsonb, 'c', 'Seul l''ensemble « chant, chanteur, chanson, chantonner » repose sur un radical commun (« chant- ») : c''est une famille de mots. Les autres regroupent des mots par thème, sans radical commun : ce sont des champs lexicaux.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
