  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eb166a98-b6d9-59ca-8d6f-06638782c529', '86c7c4fd-fedc-506b-8e2d-95c9d5d36878', 'Dans le mot « parasol », que signifie le préfixe « para- » ?', '[{"id":"a","text":"qui protège contre (le soleil)"},{"id":"b","text":"à côté de"},{"id":"c","text":"après"},{"id":"d","text":"avant"}]'::jsonb, 'a', 'Dans « parasol » (comme parapluie, paravent), le préfixe « para- » signifie « qui protège contre » : le parasol protège du soleil. Il ne marque ici ni l''antériorité ni la postériorité.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
